-- Poems batch 430
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-10444','幺・炼六尺身躯修自己，变七朵金莲到处随。配八卦跨鸾归，至九霄云外，','无名氏','元','元曲','yuanqu','','[]','十分的显雄威。',7,'元曲/yuanqu.json','["十分的显雄威。"]'),
('yuanqu-10445','南吕・一枝花','无名氏','元','元曲','yuanqu','','[]','自从俺学出家，偶然把明师遇。',67,'元曲/yuanqu.json','["自从俺学出家，偶然把明师遇。", "受辛勤十数载，无明夜办功夫。", "传的是道妙虚无，教我紧把丹田固，为残生作道术。", "行火候煅炼增加，入静定方为沐浴。"]'),
('yuanqu-10446','梁州・寂然不动分毫志，炼金丹除了厄苦，离尘俗换了凡躯。忘言减语，','无名氏','元','元曲','yuanqu','','[]','片时间收敛铅汞聚。',116,'元曲/yuanqu.json','["片时间收敛铅汞聚。", "有根蒂伏朴归真，有志气腾云蹑雾，有缘分飞上天衢。", "初学笃志真言语，见世俗人贪财好欲，不顾残生一个个要亻赞金珠。", "大限到百事都无，费精神使得干枯。", "从今，至古，神仙本是凡人做。", "定浮沉认宾主，收汞收铅莫迟阻，自问他有有无无。"]'),
('yuanqu-10447','哭皇天・化清香吹入中霄路，一时间造化须臾。舞翩翩海底寻鸥鹭，喜的','无名氏','元','元曲','yuanqu','','[]','是冷淡萧疏。',118,'元曲/yuanqu.json','["是冷淡萧疏。", "弟子师徒，笑吟吟同步赴仙都。", "蓬莱三岛归家去，昼夜功夫无思虑。", "冥冥杳杳，恍恍惚惚。", "天门开放道清虚，地户牢关抽添无数。", "澄澄湛湛功程做，独坐忘言默语，驾河车上下宽舒。", "功成纯粹守，似有却如无。", "明明地不昧元来路，包含万象，体不挂丝铢。"]'),
('yuanqu-10448','乌夜啼・运坤火乾天雾，要殷勤守玉炉。炼真汞成至宝，烹白雪似收支金','无名氏','元','元曲','yuanqu','','[]','煅黄芽做地母，饮刀圭习真土。',26,'元曲/yuanqu.json','["煅黄芽做地母，饮刀圭习真土。", "将龙虎来擒伏，呼风唤雨。"]'),
('yuanqu-10449','煞尾・化金仙脱体乘风去，一道寒光满太虚。有婴儿有姹女，有黄婆配亲','无名氏','元','元曲','yuanqu','','[]','霎时间会云雨，众仙欢个个舞。',114,'元曲/yuanqu.json','["霎时间会云雨，众仙欢个个舞。", "出了世尘离爱欲，早则不回头，一心觅钟吕，直至蓬莱伴师祖。", "同共群仙一处宿，升降三宫到紫府。", "调息绵绵炼真土，收敛黄芽治龙虎，骑坐白鹤跨鸾辂，离却凡间登仙路。", "再共清风做伴侣，又共明月做道主，飞入天宫玩仙府。"]'),
('yuanqu-10450','双调・新水令','无名氏','元','元曲','yuanqu','','[]','我在这门中整穷究了数十年，才参透了圣人机变。',51,'元曲/yuanqu.json','["我在这门中整穷究了数十年，才参透了圣人机变。", "定浮沉归妙理，进坤火炼丹田。", "先锁住意马心猿，更不把世俗缠。"]'),
('yuanqu-10451','驻马听・行的是调息绵绵，呼吸风云有后先。比及得三宫升变，九还七返','无名氏','元','元曲','yuanqu','','[]','妙中玄。',36,'元曲/yuanqu.json','["妙中玄。", "驾河车搬运走如烟，化清风直至金公院。", "若要道心坚，黄河浪滚泥丸转。"]'),
('yuanqu-10452','步步娇・大道从来人难羡，有影无形现。壶中别有天，炼就金丹养胎仙。','无名氏','元','元曲','yuanqu','','[]','双关路上气连连，酝甘露频吞烟。',15,'元曲/yuanqu.json','["双关路上气连连，酝甘露频吞烟。"]'),
('yuanqu-10453','沉醉东风・大限到来不选，也不论福富贵高官。直推到几时休几时休，每','无名氏','元','元曲','yuanqu','','[]','日价频发愿频发愿，今年推到来年。',33,'元曲/yuanqu.json','["日价频发愿频发愿，今年推到来年。", "担阁修行行路儿远，生死轮回怎免！。"]'),
('yuanqu-10454','雁儿落过得胜令・俺也曾遇明师将真道传，指与无边传。教我少贪心少爱','无名氏','元','元曲','yuanqu','','[]','欲，教俺多办工夫多修善。',70,'元曲/yuanqu.json','["欲，教俺多办工夫多修善。", "教俺休把利名牵，教俺多看些古书篇。", "尽都是通玄处，教俺共真师子细研。", "若是俺功全，得造化无人见。", "正是心也坚，心坚得自然。"]'),
('yuanqu-10455','沽美酒・将铅汞鼎内煎，炼至宝用乾乾，妙在前弦与后弦。分明有路显，','无名氏','元','元曲','yuanqu','','[]','引元神赴宫殿。',54,'元曲/yuanqu.json','["引元神赴宫殿。", "妙用三关机变，一气来透彻三田。", "九转炉中烟焰，龙虎龟蛇蟠旋。", "出于自然，自然，有一个无为真人出现。"]'),
('yuanqu-10456','川拨掉・好教我笑喧喧，共诸仙一处眠。也不索访道参禅，常要默坐忘言。','无名氏','元','元曲','yuanqu','','[]','调真息若不气喘，有先天有后天。',15,'元曲/yuanqu.json','["调真息若不气喘，有先天有后天。"]'),
('yuanqu-10457','殿前欢・劝英贤，请君常看指玄篇。无为大道人都恋，要行满功圆。跨鹤','无名氏','元','元曲','yuanqu','','[]','儿飞上天，方才入无为传，早则趁了修行愿。',37,'元曲/yuanqu.json','["儿飞上天，方才入无为传，早则趁了修行愿。", "修一个不来不去，谁肯恋在世长年！。"]'),
('yuanqu-10458','鸳鸯煞・这回再谁把世俗缠？超凡入圣随机变。道法双忘，紧固抽添。唱','无名氏','元','元曲','yuanqu','','[]','道真至蓬莱阆苑，做下部自然集，早则是虚无篇，愿心满。',26,'元曲/yuanqu.json','["道真至蓬莱阆苑，做下部自然集，早则是虚无篇，愿心满。"]'),
('yuanqu-10459','正宫・端正好','无名氏','元','元曲','yuanqu','','[]','谁知道我静中行，功劳大，这回早不染尘埃。',37,'元曲/yuanqu.json','["谁知道我静中行，功劳大，这回早不染尘埃。", "幼年间曾把明师拜，教俺跳出迷魂寨。"]'),
('yuanqu-10460','滚绣球・办功夫定慧开，炼三皇结圣胎。婴儿猛然惊怪，须臾间飞过灵台。','无名氏','元','元曲','yuanqu','','[]','到黄庭内院欢，动阳关将龙虎排。',53,'元曲/yuanqu.json','["到黄庭内院欢，动阳关将龙虎排。", "霎时间打成一块，定浮沉煅炼三灾。", "三华聚顶泥丸路，五气朝元绕玉街，下十二楼台。"]'),
('yuanqu-10461','倘秀才・调和就铅汞冶，蓦见坎女离男打乖，自有金公一处埋。成造化，','无名氏','元','元曲','yuanqu','','[]','笑诒诒，快哉！。',8,'元曲/yuanqu.json','["笑诒诒，快哉！。"]'),
('yuanqu-10462','迎仙客・长将他玉炉关，须要这八门开，用坎离颠倒栽。驾河车，牛旋买，','无名氏','元','元曲','yuanqu','','[]','搬载入宫来，收敛在三田外。',13,'元曲/yuanqu.json','["搬载入宫来，收敛在三田外。"]'),
('yuanqu-10463','红绣鞋・坐卧处阳升阴降，一窍开百窍齐开。九还七返定三灾。呼吸开归','无名氏','元','元曲','yuanqu','','[]','妙道，调真息透盈腮，治精华归气海。',17,'元曲/yuanqu.json','["妙道，调真息透盈腮，治精华归气海。"]'),
('yuanqu-10464','鲍老儿・炼元神观自在，养胎仙笑颜开。三田气滚透胸怀。煅至宝功劳大，','无名氏','元','元曲','yuanqu','','[]','万语千言句句该，都出在道德阴符界。',48,'元曲/yuanqu.json','["万语千言句句该，都出在道德阴符界。", "发动天关润九垓，采药物在乾坤外。", "自云堆里飞升快，变化累劫修来。"]'),
('yuanqu-10465','耍孩儿・初学笃志真心爱，广看些经书注解。忽然间心地悟豁然开，自想','无名氏','元','元曲','yuanqu','','[]','往日沉埋。',40,'元曲/yuanqu.json','["往日沉埋。", "果然实有登仙路，任意纵横到处该，还了这冤家债。", "这回万缘齐断，不染千灾。"]'),
('yuanqu-10466','一煞・静中功默默的行，点刀圭分皂白，灵台无物当宁耐。脱离生死修真','无名氏','元','元曲','yuanqu','','[]','路，倒把枯松日夜栽。',33,'元曲/yuanqu.json','["路，倒把枯松日夜栽。", "权且将时光来待，咫尺的是功圆行满，独步上天台。"]'),
('yuanqu-10467','二煞・也不索看三教书，也不索学七步才，只要昏昏默默将功程捱。炼成','无名氏','元','元曲','yuanqu','','[]','玉体乘风去，一道寒光入圣阶。',38,'元曲/yuanqu.json','["玉体乘风去，一道寒光入圣阶。", "做一个蓬莱客，全凭三千功行满，便要离俗骨得仙胎。"]'),
('yuanqu-10468','三煞・任时节跨青鸾飞上天，驾白鹤复地来，飞升变化登仙界。黄芽渐长','无名氏','元','元曲','yuanqu','','[]','人难识，玉兔窝中好避乖。',33,'元曲/yuanqu.json','["人难识，玉兔窝中好避乖。", "权且将时光待，咫尺的功圆行满，独步上天台。"]'),
('yuanqu-10469','正宫・端正好','无名氏','元','元曲','yuanqu','','[]','撇了是和非。',41,'元曲/yuanqu.json','["撇了是和非。", "掉了争和斗。", "把俺这心猿意马牢收。", "我则待舞西风两叶宽袍袖。", "看日月搬昏昼。"]'),
('yuanqu-10470','滚绣球・千家饭足可求，百衲衣不害羞。问是么破设设遮着皮肉，傲人间','无名氏','元','元曲','yuanqu','','[]','伯子公侯。',70,'元曲/yuanqu.json','["伯子公侯。", "我则待闲遥遥唱个道情，醉醺醺的打个稽首。", "抄化圣汤仙酒，藜杖瓢钵便是俺的行头。", "我则待今朝有酒今朝醉，明日无钱明日求，到大来散诞无忧。"]'),
('yuanqu-10471','倘秀才・有一等积书与子孙未必尽收，有一等积金与子孙未必尽守，我劝','无名氏','元','元曲','yuanqu','','[]','你莫与儿孙作马牛。',37,'元曲/yuanqu.json','["你莫与儿孙作马牛。", "今日个云生山势巧，来日个霜降水痕收，怎敖得他乌飞兔走！。"]'),
('yuanqu-10472','滚绣球・恰才见元宵灯挑在手，又见清明门前插杨柳。正修禊传觞曲水，','无名氏','元','元曲','yuanqu','','[]','不觉的击黾鼓竞渡龙舟。',77,'元曲/yuanqu.json','["不觉的击黾鼓竞渡龙舟。", "恰才是七月七，又早是九月九。", "咱能够几番儿欢喜厮守？都在烦恼中过了春秋。", "你见这纷纷的世事恁待要随缘过，都不顾急急光阴似水流，白了人头。"]'),
('yuanqu-10473','呆骨朵・休言道尧舜和桀纣，则不如郝王孙谭马丘刘。他每是文中子门徒，','无名氏','元','元曲','yuanqu','','[]','亢仓子志友。',42,'元曲/yuanqu.json','["亢仓子志友。", "休言为吏道张平叔，烟月的刘行首。", "则不如阐全真王祖师，道不如打回头马半州。"]'),
('yuanqu-10474','醉太平・汉钟离本是个帅首，蓝采和是个俳优。悬壶子本不曾去沽酒，铁','无名氏','元','元曲','yuanqu','','[]','拐李火焚了尸首。',43,'元曲/yuanqu.json','["拐李火焚了尸首。", "贺兰仙引定个曹国舅，韩湘子会造逡巡酒。", "吕洞宾三醉岳阳楼，度了一株绿柳。"]'),
('yuanqu-10475','尾・休言功行何时就，得到玄关便可投。人我场中枉驰骤，苦海波中早回','无名氏','元','元曲','yuanqu','','[]','四大神游。',24,'元曲/yuanqu.json','["四大神游。", "三岛十洲，神仙隐迹埋名，他则待目前走。"]'),
('yuanqu-10476','正宫・端正好','无名氏','元','元曲','yuanqu','','[]','我做的利己脱身术，恁做的害众成家活，恁道我风魔你更风魔。',49,'元曲/yuanqu.json','["我做的利己脱身术，恁做的害众成家活，恁道我风魔你更风魔。", "俺这里无名无利都参破，你利害有他这天来大。"]'),
('yuanqu-10477','滚绣球・俺这里，笑一合，利名场朗然识破。没来由为儿女劫动波波，便','无名氏','元','元曲','yuanqu','','[]','亻赞下不义财，积下些无用货。',56,'元曲/yuanqu.json','["亻赞下不义财，积下些无用货。", "死临头怎生逃躲，少不的打轮回作马骡。", "明放着天堂有路人行少，地狱无门去的多，落落魄魄。"]'),
('yuanqu-10478','南吕・金字经','无名氏','元','元曲','yuanqu','','[]','学仙须学做天仙，修炼金丹性命全。',272,'元曲/yuanqu.json','["学仙须学做天仙，修炼金丹性命全。", "全，羲皇画卦先。", "先天К，明师的诀传。", "金丹大药不难求，家家有种可自修。", "修，休离丹灶头。", "无中有，坎离颠倒收。", "金丹妙道大神功，降收白虎摄赤龙。", "龙，烹煎玉鼎中。", "须臾用，阴阳造化工。", "黍珠饵罢罢雍雍，精调火候十月功。", "功，胎仙灵变通。", "婴儿踊，万真朝绛宫。", "慧光明彻本来宗，无边法界一性通。", "通，禅心空不空。", "如来共，老君儒化同。", "修真祖性复全真，自在逍遥物外人。", "人，无贪无恚嗔。", "长生事，杏花枝上春。", "善功八百行三千，四海遨游度有缘。", "缘，九重丹诏宣。", "乘鸾鹤，班行列御前。", "见闻知觉总休题，悟得真空及第归。", "归，勘破造化机。", "非难易，永劫天地齐。"]'),
('yuanqu-10479','商调・梧叶儿','无名氏','元','元曲','yuanqu','','[]','观白鹭，看乌鸦，水底摸鱼虾。',370,'元曲/yuanqu.json','["观白鹭，看乌鸦，水底摸鱼虾。", "莺穿柳，蝶恋花，景幽雅，若非云门莫夸。", "想林济，大慈悲，究竟作根基。", "打一捧，去片皮，好呆痴，痛痒犹然不知。", "龟毛拂，兔角锥。", "虾蟆扑天飞。", "泥牛吼，木马嘶，少人知，俯仰泄漏天机。", "麦有面，粟有米，布裤里更有腿。", "山有石，海有月，语真实，洞霞无极立基。", "擒意马，锁心猿，神气养交全。", "非扭捏，合自然，体幽玄，法眼超过大千。", "玄妙塞，化城关，一脚□蹬翻。", "花红处，柳绿间，没遮栏，处处仙佛面颜。", "天边月，月正圆，掘地去寻天。", "有无有，颠倒颠，妙玄玄，正道须当要口传。", "天边月，月上弦，卯酉不虚传。", "八两汞，八两铅，一斤全，照破了三千及大千。", "天边月，月应弓，真道妙无穷。", "龙擒龙，虎擒龙，两相逢，结一朵金花弄风。", "天边月，月正南，前后各三三。", "离是女，坎是男，妙玄谈，不说破教人家怎参？天边月，月应炉，铅汞鼎中居。", "金凭火，炼就珠，一葫芦，三百八十四铢。"]'),
('yuanqu-10480','双调・雁儿落过得胜令','无名氏','元','元曲','yuanqu','','[]','想赴蟠桃玳瑁筵，休享御酒琼林宴。',303,'元曲/yuanqu.json','["想赴蟠桃玳瑁筵，休享御酒琼林宴。", "息争名夺利心，发养性修真愿。", "争如纸被裹云眠，茶药倚炉煎。", "看峻岭衔花鹿，使巅峰献果猿。", "朝元，在金阙寥阳殿。", "安然，蓬莱洞里仙。", "为浮生两鬓白，观镜里朱颜迈。", "忙辞了白象简，紧纳了金鱼带。", "绿柳倚门栽，金菊映篱开。", "爱的是流水清如玉，那里想侯门深似海。", "幽哉，袖拂白云外。", "彭泽，清闲归去来。", "光阴似流水，日月搬昏昼。", "尘俗一笔勾，世事都参透。", "睡来时高枕一无忧，闷来时拄杖半过头。", "饥来时一钵千家饭，闲来时孤身万里游。", "盈眸，阆苑风光秀。", "抬头，蓬莱景物幽。", "荣华似风内灯，富贵如槐安梦。", "恰六朝贺太平，十二国干戈动。", "人海混鱼龙，浮世隐英雄。", "收楚韩元帅，兴周的姜太公。", "功名，到底成何用？悉是：南柯一梦中！。"]'),
('yuanqu-10481','中吕・满庭芳','无名氏','元','元曲','yuanqu','','[]','风尘艳娃，堪题堪咏，堪羡堪夸。',59,'元曲/yuanqu.json','["风尘艳娃，堪题堪咏，堪羡堪夸。", "朱唇檀口些娘大，脸衬桃花。", "理冰弦纤纤银甲，步香尘窄窄刀麻。", "天生下，温柔典雅，端的玉无瑕。"]'),
('yuanqu-10482','中吕・红绣鞋','无名氏','元','元曲','yuanqu','','[]','手腕儿白似鹅翅，指头儿嫩似葱枝，玉抬盘捧定水晶卮。',49,'元曲/yuanqu.json','["手腕儿白似鹅翅，指头儿嫩似葱枝，玉抬盘捧定水晶卮。", "话儿甜来尽让，意儿勤不推辞，把一个贾长沙险醉死。"]'),
('yuanqu-10483','双调・拨不断','无名氏','元','元曲','yuanqu','','[]','老书生、小书生，二书生坏了中枢省。',43,'元曲/yuanqu.json','["老书生、小书生，二书生坏了中枢省。", "不言不语张左丞，铺眉拓眼董参政，也待学魏征一般俸请。"]'),
('yuanqu-10484','不知宫调・甜水令','无名氏','元','元曲','yuanqu','','[]','麻绦草履风袍袖，名利不刚求。',111,'元曲/yuanqu.json','["麻绦草履风袍袖，名利不刚求。", "蓑笠纶竿钓鱼钩，绿水东流。", "炉中炼出灵丹药，雷震采茶苗。", "明月清风杖头挑，不挂椰瓢。", "看看又早中年过，白发鬓边多。", "积玉堆金大如何？梦里存活。", "把心猿意马方拴定，为甚不争名。", "便得象简金鱼做公卿，白马红缨。"]'),
('yuanqu-10485','黄钟・红锦袍','无名氏','元','元曲','yuanqu','','[]','那老子彭泽县懒坐衙，倦将文卷押，数十日不上马，柴门掩上咱，篱下看黄花。',61,'元曲/yuanqu.json','["那老子彭泽县懒坐衙，倦将文卷押，数十日不上马，柴门掩上咱，篱下看黄花。", "爱的是绿水青山，见一个白衣人来报，来报五柳庄幽静煞。"]'),
('yuanqu-10486','浦印亢厥令・','无名氏','元','元曲','yuanqu','','[]','春夏间，遍郊原桃杏繁，用尽丹青图画难。',46,'元曲/yuanqu.json','["春夏间，遍郊原桃杏繁，用尽丹青图画难。", "道童将驴鞴上鞍，忍不住只恁般顽，将一个酒葫芦杨柳上拴。"]'),
('yuanqu-10487','正宫・塞鸿秋','无名氏','元','元曲','yuanqu','','[]','爱他时似爱初生月，喜他时似喜看梅梢月，想他时道几首西江月，盼他时似盼辰钩月。',628,'元曲/yuanqu.json','["爱他时似爱初生月，喜他时似喜看梅梢月，想他时道几首西江月，盼他时似盼辰钩月。", "当初意儿别，今日相抛撇，要相逢似水底捞明月。", "一对紫燕儿雕梁上肩相并，一对粉蝶儿花丛上偏相趁，一对鸳鸯儿水面上相交颈，一对儿虎猫儿绣凳上相偎定。", "觑了动人情，不由人心儿硬，冷清清偏俺合孤另。", "分分付付约定偷期话，冥冥悄悄款把门儿呀，潜潜等等立在花阴下，战战兢兢把不住心儿怕。", "转过海棠轩，映着荼縻架，果然道色胆天来大。", "腕肌消松了黄金钏，粉脂残淡了芙蓉面。", "紫霜毫点遍端溪砚，断肠诗懒写春罗扇。", "柳絮香衮绵，花落闲庭院，恨鸳鸯不锁黄金殿。", "影儿孤房儿静灯儿照，枕儿欹床儿卧帏屏儿上靠，心儿里思意儿里想人儿俏，不能够床儿上被儿里怀儿抱。", "怎生睚今宵，梦儿里添烦恼，几时睚得更儿尽月儿落鸡儿叫。", "山行警东边路西边路南边路，五里铺七里铺十里铺，行一步盼一步懒一步，霎时间天也暮日也暮云也暮。", "斜阳满地铺，回首生烟雾，兀的不山无数水无数情无数。", "宴毕警灯也照星也照月也照，东边笑西边笑南边笑。", "忽听的钧天乐箫韶乐云和乐，合着这大石调、小石调、黄钟调。", "银花遍地飘，火树连天照，喜的是君有道臣有道国有道。", "村夫饮宾也醉主也醉仆也醉，唱一会舞一会笑一会。", "管甚么三十岁五十岁或七十岁，你也跪他也跪恁也跪。", "无其繁弦急管催，吃到红轮日西坠，打的那盘也碎碟也碎碗也碎。", "丹客行朝烧炼暮烧炼朝暮学烧炼，这里串那里串到处都串遍。", "东家骗西家骗南北都诓遍，惹的妻埋怨子埋怨父母都埋怨。", "我问你金丹何日成？铅汞何日见？只落的披一片挂一片拖一片。"]'),
('yuanqu-10488','幺・凌波仙子生尘梦，向瑶台月下相逢。酒晕浓，凡心动，夜凉人静，飞','无名氏','元','元曲','yuanqu','','[]','下水晶宫。',5,'元曲/yuanqu.json','["下水晶宫。"]'),
('yuanqu-10489','正宫・叨叨令过折桂令驮背妓名陈观音奴','无名氏','元','元曲','yuanqu','','[]','虾儿腰龟儿背玉连环系不起香罗带，脊儿高绞儿细绿茸毛生就的王八盖，眼儿眍鼻儿凸驱外走了猢狲怪，嘴儿尖舌儿快洛伽山怎受的菩萨戒！兀的不丑杀人也么哥，兀的不丑杀人也么',187,'元曲/yuanqu.json','["虾儿腰龟儿背玉连环系不起香罗带，脊儿高绞儿细绿茸毛生就的王八盖，眼儿眍鼻儿凸驱外走了猢狲怪，嘴儿尖舌儿快洛伽山怎受的菩萨戒！兀的不丑杀人也么哥，兀的不丑杀人也么哥，钩儿形条儿样烂茄瓜辱没杀莺花寨。", "莺花寨命里合该，一背儿残疾，一世儿裁划。", "便道是倒凤颠鸾，莺俦燕侣，弯不剌怎么安排！风月债休将人定害，俺则怕雨云浓厥杀乔才。", "你这形骸，其实歪揣。", "调稍弓着不的扯拽，窍头船趁早儿撑开。"]'),
('yuanqu-10490','仙吕・醉扶归','无名氏','元','元曲','yuanqu','','[]','一点芳心碎，两叶翠眉低。',167,'元曲/yuanqu.json','["一点芳心碎，两叶翠眉低。", "薄幸檀郎尚未归，应是平康醉。", "不来也奴更候些，直等烛灭香消睡。", "锦瑟香尘昧，朱户绣帘垂。", "宝鉴从他落燕泥，陡恁慵梳洗。", "欲觅个团圆好梦，欹枕也难成寐。", "玉笋弹珠泪，银叶冷金猊。", "良夜迢迢玉漏迟，闷把帏屏倚。", "我又索先暖下纯绵被儿，来后教他睡。", "花影侵阶砌，月转小楼西。", "独倚屏山谩叹息，再把灯儿剔。", "自觑了孤栖影儿，咒罢也和衣睡。"]'),
('yuanqu-10491','仙吕・一半儿','无名氏','元','元曲','yuanqu','','[]','佳人才子共双双，纨扇轻摇玉体凉，荷钱贴水满池塘。',111,'元曲/yuanqu.json','["佳人才子共双双，纨扇轻摇玉体凉，荷钱贴水满池塘。", "拭罗裳，一半儿斜披一半儿敞。", "南楼昨夜雁声悲，良夜迢迢玉漏迟，花梧树底叶成堆。", "被风吹，一半儿沾泥一半儿飞。", "见佳人缟素一身穿，阁着泪汪汪在坟墓前，哭着痛人天。", "一只手匙撩一半儿蹇。"]'),
('yuanqu-10492','仙吕・四季花','无名氏','元','元曲','yuanqu','','[]','一年三百六十日，花酒不曾离。',41,'元曲/yuanqu.json','["一年三百六十日，花酒不曾离。", "醉醺醺酒淹衫袖湿，花压帽檐低。", "帽檐低，吃了穿了是便宜。"]'),
('yuanqu-10493','仙吕・锦橙梅','无名氏','元','元曲','yuanqu','','[]','厮收拾厮定当，越拘束着越荒唐。',68,'元曲/yuanqu.json','["厮收拾厮定当，越拘束着越荒唐。", "入门来不带酒厮禁持，觑不得娘香胡相。", "恁娘又不是女娘，绣房中不是茶坊，甘不过这不良。", "唤梅香，快扶入那销金帐。"]'),
('yuanqu-10494','仙吕・三番玉楼人','无名氏','元','元曲','yuanqu','','[]','风摆檐间马，雨打响碧窗纱。',77,'元曲/yuanqu.json','["风摆檐间马，雨打响碧窗纱。", "枕剩衾寒没乱煞，不着我题名儿骂，暗想他，暗想他，忒情杂。", "等来家，好生的歹斗咱。", "我将那厮脸儿上不抓，耳轮儿揪罢，我问你昨夜宿谁家。"]'),
('yuanqu-10495','南吕・西番经','无名氏','元','元曲','yuanqu','','[]','四海英雄汉，六合天地间，旧识荆州不信韩。',114,'元曲/yuanqu.json','["四海英雄汉，六合天地间，旧识荆州不信韩。", "乾，破冠朝暮弹。", "空长叹，牧童牛背山。", "醉鞭平康巷，少年长乐坊，乐府金钗十二行。", "狂，老来空断肠。", "花溪上，梦中黄四娘。", "座上三台印，帐前十万军，半纸功名百战身。", "君，便合拂袖尘。", "学韩信，不如林下人。"]'),
('yuanqu-10496','南吕・玉娇枝过四块玉','无名氏','元','元曲','yuanqu','','[]','休争闲气，都只是南柯梦里。',120,'元曲/yuanqu.json','["休争闲气，都只是南柯梦里。", "想功名到底成何济？总虚华几人知！百般乖不如一就痴，十分醒争似三分醉。", "则这的是人生落得，不受用图个甚的！赤紧的乌紧飞，兔紧追，看看的老来催。", "人无百岁人，枉作千年计。", "将眉间闷锁开，休把心上愁绳系，则这的是延年益寿的理。"]'),
('yuanqu-10497','中吕・迎仙客十二月','无名氏','元','元曲','yuanqu','','[]','头懒抬，眼慵开，花酒偶然都到来。',332,'元曲/yuanqu.json','["头懒抬，眼慵开，花酒偶然都到来。", "酒浮香，花放彩。", "小玉前来，试演迎仙客。", "正月春气早，斗回杓，灯焰月明三五宵，绮罗人，兰麝飘。", "柳嫩梅娇，斗合鹅儿闹。", "二月春日暄，卖饧天，谁家绿杨不禁烟？闹花边，簇队仙。", "送起秋千，笑语如莺燕。", "三月修禊潭，水如蓝，车马胜游三月三。", "晚归来，酒半酣。", "笑指西南，月影蛾眉淡。", "四月红渐稀，绿成围，串烟碧纱窗外飞。", "洒蔷薇，香透衣。", "煮酒青梅，正好连宵醉。", "五月结艾人，赏蕤宾，菖蒲酒香开玉樽。", "彩丝缠，角粽新。", "楚些招魂，细写怀沙恨。", "六月庭院雅，闹蜂衙，开尽海榴无数花。", "剖甘瓜，点嫩茶。", "笋指韶华，又过了今年夏。", "七月乞巧楼，月如钩，聚散几回银汉秋。", "遣人愁，何日休？织女牵牛，万古情依旧。", "八月风露清，月华明，明月万家欢笑声。", "洗金觥，拂玉筝。", "月也多情，唤起南楼兴。"]'),
('yuanqu-10498','中吕・朝天子','无名氏','元','元曲','yuanqu','','[]','尽教，便了，□尔纵横闹。',357,'元曲/yuanqu.json','["尽教，便了，□尔纵横闹。", "纱笼影里马头高，早雪拥蓝关道。", "休喜休欢，休烦休恼，只争个迟共早。", "比甘罗不小，比太公未老，须有日应心道。", "一悭，二奸，困煞英雄汉。", "陈抟占却一半山，不复梦周公旦。", "雨笠烟蓑，星驰云栈，利和名自古难。", "这番，上杆，休□了梯儿看。", "尽教，便了，彼各休相笑。", "正沙堤稳稳马头高，又贬上潮阳道。", "休喜休欢，休烦休恼，只争个迟共早。", "比太公未老，比甘罢又不小，此一梦何时觉。", "杜康，醉乡，竹叶樽琼花酿。", "人生三万六千场，既有限谁无恙。", "眨眼秋霜，飞来头上，趁春光倒玉觞。", "唤将，四娘，燕子舞莺儿唱。", "画堂，绮窗，玉错落金波酿。", "春风枉羡杜韦娘，试听宣娥唱。", "月窟新声，云鬟宫样，怎禁他粉黛香。", "这场，醉乡，勒留住山中相。", "楚阑，小蛮，锦瑟调银筝按。", "西园公子兴未阑，盏到休辞惮。", "明月帘栊，疏星河汉，倚红楼十二阑。", "夜寒，烛残，酒尽后人方散。"]'),
('yuanqu-10499','中吕・普天乐','无名氏','元','元曲','yuanqu','','[]','夜深沉，秋潇洒。',308,'元曲/yuanqu.json','["夜深沉，秋潇洒。", "风筛槛竹，雾锁窗纱。", "绣幕垂，朱扉亚。", "霜落梧桐雕阑谢，月明天啼杀宫鸦。", "香锁宝鸭，帘敲玉马，灯谢瑶花。", "海棠娇，梨花嫩。", "春妆成媚色，玉扌若就精神。", "柳眉颦翡翠弯，杏脸腻姻脂晕。", "款步香尘双鸳印，立东风一片巫云。", "淹的转身，嘻的喑哑，参的销魂。", "木犀风，梧桐月。", "珠帘鹦鹉，绣枕胡蝶。", "玉人娇一晌欢，碧酝酿十分悦。", "断角疏钟淮南夜，撼西风唤起离别。", "知他是团圆也梦也，欢娱也醉也，烦恼也醒也。", "大德天寿贺词凤凰朝，麒麟见。", "明君天下，大德元年。", "万乘尊，诸王宴。", "四海安然朝金殿，五云楼瑞霭祥烟。", "群臣顿首，山呼万岁，洪福齐天。", "嘲风情楚台云，秦楼月。", "云生时月缺，月满处云遮。", "磨杆儿汤着折，炮架儿实难拽。", "柳宠花娇恩情热，识破也便是英杰。"]'),
('yuanqu-10500','中吕・四换头','无名氏','元','元曲','yuanqu','','[]','清明时候，才子佳人醉玉楼。',341,'元曲/yuanqu.json','["清明时候，才子佳人醉玉楼。", "纷纷花柳，飘飘襟袖。", "行歌载酒，花老人依旧。", "西湖烟岸，莲荡风生六月寒。", "邻船歌板，诗囊文翰。", "醉余兴阑，悲有限欢无限。", "江湖豪迈，为惜黄花归去来。", "名无言责，身无俗债。", "任家私匾窄，但醉里乾坤大。", "冲寒乘骑，信步孤山为访梅。", "溪桥流水，云林斜日。", "三花五蕊，漏泄了春消息。", "两叶眉头，怎锁相思万种愁？从他别后，无心挑绣。", "这般证候，天知道和天瘦！从他别后，满眼风光总是愁。", "实心儿有，须索禁受。", "为他些证候，迤逗的人来瘦。", "牵肠割肚，一自别来信也无。", "多情何处？教人思虑。", "凭栏伫目，空望断遥天暮。", "东墙花月，好景良宵恁记者。", "低低的说，来时节，明日早些，不志诚随灯灭。", "声说不的，满腹离愁诉与谁！负心天识，酩子里输了身起。", "呆才好看，自做得不出气。", "言盟说誓，岂信闲人讲是非？忘餐失寐，形骸憔悴。"]'),
('yuanqu-10501','大石调・初生月儿','无名氏','元','元曲','yuanqu','','[]','初生月儿悬太虚，恰似嫦娥鬓上梳，冰轮未满羡叹处。',162,'元曲/yuanqu.json','["初生月儿悬太虚，恰似嫦娥鬓上梳，冰轮未满羡叹处。", "漫长吁，离恨苦，冷清清凤只鸾孤。", "初生月儿一半弯，那一半团圆直恁难，雕鞍去后何日还？捱更阑，淹泪眼，虚檐外凭损阑干。", "初生月儿明处少，又被浮云遮蔽了，香消烛灭人静悄。", "夜迢迢，难睡着，窗儿外雨打芭蕉。", "初生月儿一似弓，梦里相逢恩爱同，觉来时锦被一半空。", "去无踪，难再逢，窗儿外烛影摇红。"]'),
('yuanqu-10502','小石调・归来乐','无名氏','元','元曲','yuanqu','','[]','罢罢耍耍，茫茫世界尽宽大。',427,'元曲/yuanqu.json','["罢罢耍耍，茫茫世界尽宽大。", "五斗米折不得彭泽腰，一碗饭受不得淮阴跨。", "种几亩邵平瓜，卜几文君平卦。", "哈哈，快活煞！心窝里无牵挂，耳跟厢没嘈杂。", "哈哈，世上人劳劳堪讶！你看那秦代长城替别人打，汉朝陵寝被偷儿挖。", "魏时铜雀台，到如今无片瓦。", "哈哈，名利场最兜搭！班定远玉门关，枉白了青丝发。", "马新息铜柱标，抵不得明珠价。", "哈哈，却更有几般堪讶！动不动说甚么玉堂金马，虚费了文园笔札。", "只恐怕渴死了汉相如，空落下文君再寡。", "哈哈，到头来都是假！总饶你事业伊周，文章董贾，少不得北邙山下。", "哈哈，俺归去也呀！身不关陶唐禹夏，梦不想谋王定霸。", "容膝的是竹椽茅檐，点景的是琴棋书画，忘机的是鸥鱼凫鸭。", "更有那橘柚园遮周匝，兰地平坡凸凹。", "俺可也不痴又不呆，不聋又不哑。", "谁肯把韶光来虚那？哈哈，俺归去也呀！从负郭问桑麻，遇邻翁数花甲。", "铁笛儿在牛角上挂，酒瓢儿在渔竿上插，诗囊儿在驴背上跨。", "眼底事抛却了万万千千，杯中物直饮到七七八八。", "欢百岁谁似咱？哈哈，要罢便罢！分付与风月烟霞，准备着归家来耍耍。"]'),
('yuanqu-10503','十二月・正月','无名氏','元','元曲','yuanqu','','[]','年时节，元夜时，云鬓插小桃枝。',477,'元曲/yuanqu.json','["年时节，元夜时，云鬓插小桃枝。", "今年早，不见你，泪珠儿，滴满了春衫袖儿。", "二月踏青去，二月时，则不肯上车儿。", "强那步，困又止，脱鞋儿，要人兜凌波袜儿。", "三月春三月，花满枝，秋千惹绿杨丝。", "才蹴罢，舒玉指，摸腰儿，谁拾得鲛绡帕儿？四月清和节，近洛时，寻思了又寻思。", "新荷叶，浑厮似，面花儿，贴在我芙蓉额儿。", "五月曾齐唱，端午词，香艾插交枝。", "琼酥腕，系彩丝，酒浓时，压匾了黄金钏儿。", "六月炎天热，无限时，香汗湿凝脂。", "谁如我，看定你，睡着时，才敢住了白纨扇儿。", "七月金风动，玉露滋，牛女会合时。", "人别后，无意思，折花枝，闲倚定桐梧树儿。", "八月中秋夜，饮玉卮，满酌不须辞。", "沉醉后，仰望时，月明儿，便似个青铜镜儿。", "九月重阳节，秋暮时，为折傲霜枝。", "归兰舍，忆旧时，梦魂儿，飞入销金帐儿。", "十月长思虑，长叹咨，烟外碧参差。", "或时诗句，或时词，写相思，无一个胭脂叶儿。", "十一月香闺静，憔悴死，玉壶内结冰澌。", "沉烟细，袅碧丝，断肠时，纱窗印梅花月儿。", "十二月十二月，十二时，无一刻不嗟咨。", "他来后，方则是，一团儿，香满了青绫被儿。", "嘲女人身长身材大，膊项长，难匹配怎成双？只道是巨无霸的女，原来是显道神的娘。"]'),
('yuanqu-10504','商调・玉抱肚','无名氏','元','元曲','yuanqu','','[]','休来这里闲嗑，俺奶奶知道骂我，逞甚么娄罗？当初有个郑元和，早收心休恋我。',36,'元曲/yuanqu.json','["休来这里闲嗑，俺奶奶知道骂我，逞甚么娄罗？当初有个郑元和，早收心休恋我。"]'),
('yuanqu-10505','越调・天净沙','无名氏','元','元曲','yuanqu','','[]','长途野草寒沙，夕阳远水残霞，衰柳黄花瘦马。',370,'元曲/yuanqu.json','["长途野草寒沙，夕阳远水残霞，衰柳黄花瘦马。", "休题别话，今宵宿在谁家？瘦皆因凤只鸾单，病非干暑湿风寒，空服了千丸万散。", "恹恹情绪，立斜阳目断巫山。", "上官有似花开，下官浑似花衰，花谢花开小哉！常存根在，明年依旧春来。", "江南几度梅花，愁添两鬓霜华，梦儿里分明见他。", "客窗直下，觉来依旧天涯。", "今生或少或多，功名一枕南柯，富贵荣华快活。", "今朝已过，不知明日如何？生红闹簇枯枝，只愁吹破胭脂，说与莺儿燕子。", "东君知道，杏花不耐开时。", "西风谓水长安，淡烟疏雨骊山，不见昭阳玉环。", "夕阳楼上，无言独倚阑干。", "东邻多病萧娘，西邻清瘦刘郎。", "被一堵无端粉墙，将人隔断，抵多少水远山长。", "枯藤老树昏鸦，小桥流水人家，古道西风瘦马。", "夕阳西下，断肠人在天涯。", "平沙细草斑斑，曲溪流水潺潺，塞上清秋早寒。", "一声新雁，黄云红叶青山。", "西风塞上胡笳，月明马上琵琶，那抵昭君恨多？李陵台下，淡烟衰草黄沙。"]'),
('yuanqu-10506','双调・蟾宫曲酒','无名氏','元','元曲','yuanqu','','[]','酒能消闷海愁山，酒到心头，春满人间。',240,'元曲/yuanqu.json','["酒能消闷海愁山，酒到心头，春满人间。", "这酒痛饮忘形，微饮忘忧，好饮忘餐。", "一个烦恼人乞惆似阿难，才吃了两三杯可戏如潘安。", "止渴消烦，透节通关，注血和颜，解暑温寒。", "这酒则是汉钟离的葫芦，葫芦儿里救命的灵丹。", "赞西域吉诚甫酌西凉万斛葡萄，喜有知音，助我诗豪。", "壮士夺旗，忠臣锁树，逐客吹箫。", "检旧曲梨园架阁，举新声乐府勾销。", "胆落儿曹，水倒词源，雷吼江潮。", "归隐问天公许我闲身，结草为标，编竹为门。", "鹿豕成群，鱼虾作伴，鹅鸭比邻。", "不远游堂上有亲，莫居官朝里无人。", "黜陟休云。", "进退休论。", "买断青山，隔断红尘。"]'),
('yuanqu-10507','双调・庆宣和','无名氏','元','元曲','yuanqu','','[]','太华峰高天地窄，翠满云台。',331,'元曲/yuanqu.json','["太华峰高天地窄，翠满云台。", "好打睡先生枕头归，去来，去来。", "七里滩边古钓台，老树苍苔。", "要听渔樵话成败，去来，去来。", "烟水茫茫东大海，望见逢莱。", "八个神仙肯拖戴，去来，去来。", "锦片桃花绕调开，流水天台。", "不见刘郎玉真怪，去来，去来。", "五柳庄头陶令宅，大似彭泽。", "无限黄花有谁戴？去来，去来。", "花过清明也是客，客更伤怀。", "杜宇声三更里破窗外，去来，去来。", "扪月清江李太白，可惜高才。", "一步青山谢公宅，去来，去来。", "千亩青林七个客，无点尘埃。", "卖酒人家瓮初开，去来，去来。", "投至侯门深似海，日转千阶。", "和尚在知他是钵盂在，去来，去来。", "充腹黄粮暖炕柴，送老山斋。", "枸杞茶甜如蕨薇菜，去来，去来。", "寄语寒窗老秀才，一经头白。", "更等甚三年选场开？去来，去来。", "倚遍阑干十二曲，短叹长吁。", "望断行皋碧云暮，几声，杜宇。"]'),
('yuanqu-10508','双调・庆东原','无名氏','元','元曲','yuanqu','','[]','花阴话，柳影歌，世不曾口绽些儿个。',191,'元曲/yuanqu.json','["花阴话，柳影歌，世不曾口绽些儿个。", "行院每炒勃，姨夫每恼聒，奶奶行收撮。", "落得个担儿沉，又惹得风声大。", "难收救，怎结煞？小恩情播弄得天来大。", "顽涎儿按捺，私情儿拽塌，好话儿填扎。", "犹兀自保儿嗔，断不了姨夫骂。", "弹初罢，酒乍醒，拈冰纨笑把雕阑凭。", "林梢雨晴，花前月明，席上风生。", "驾老鉴湖秋，庚亮南楼兴。", "奇遇参旗动，斗柄挪，为多情揽下风流祸。", "眉攒翠蛾，裙拖绛罗，袜冷凌波。", "耽惊怕万千般，得受用些儿个。"]'),
('yuanqu-10509','双调・春闺怨','无名氏','元','元曲','yuanqu','','[]','绛蜡高烧，银屏倦倚。',41,'元曲/yuanqu.json','["绛蜡高烧，银屏倦倚。", "沉香火暖翠帘低，樽前冷落藏阄戏。", "人未回，何处寻梅？风雪画桥西。"]'),
('yuanqu-10510','双调・对玉环','无名氏','元','元曲','yuanqu','','[]','歌舞婵娟，风流胜玉仙。',56,'元曲/yuanqu.json','["歌舞婵娟，风流胜玉仙。", "拆散姻缘，柳青忒爱钱。", "佳人蓦上船，书生缘分浅。", "几句新诗，金山古寺边。", "一曲琵琶，长江秋月圆。"]'),
('yuanqu-10511','双调・快活年','无名氏','元','元曲','yuanqu','','[]','袅袅婷婷似观音，则少个净瓶。',338,'元曲/yuanqu.json','["袅袅婷婷似观音，则少个净瓶。", "玉笋轻舒整乌云，宝髻偏相美。", "脸儿多风韵，多风韵。", "款撒金莲懒抬头，直恁么害羞。", "小小鞋儿四季花头，缠得尖尖瘦。", "推把衫扣，把衫扣。", "眼角眉尖送春情，直恁志诚。", "款步轻移暗传情，不能够相侵近。", "两下里成孤令，成孤令。", "暗想多情不良才，风流般相态，病枕着床几时和谐。", "天若知其爱，敢也和天害，和天害。", "雁字长空点残云，绝无个信音。", "到秋深不想早回程，合寄纸平安信。", "直恁心肠硬，心肠硬。", "独宿孤眠几时休，心中是有。", "眼趁上姻缘不能成就，害得厌厌瘦。", "永夜如何守？如何守？寸禄沾身有赏罚，我其实怕他。", "损人安己要成家，一个个违王法。", "天理难容纳，不是耍。", "贪饕贿赂显荣华，似镜中看花。", "浮名浮利不贪他，万事无牵挂。", "一笔都勾罢，散诞煞。", "利名两字不坚牢，参透也弃了。", "紫袍不恋恋麻袍，其实心儿好。"]'),
('yuanqu-10512','双调・新时令','无名氏','元','元曲','yuanqu','','[]','郑元和，当初有家缘。',91,'元曲/yuanqu.json','["郑元和，当初有家缘。", "骑骏马，来过粉墙边。", "一段风流，佳人二八年；四目相窥，才郎三坠鞭。", "心坚石也穿，如鱼似水效鹣鹣。", "郎君梦撒毡，鸨儿苦爱钱。", "瓦罐爻槌，凄凉受了万千；夜宿卑田，则为李亚仙。"]'),
('yuanqu-10513','双调・十棒鼓','无名氏','元','元曲','yuanqu','','[]','将家私弃了，向山间林下；竹篱茅舍，看红叶黄花。',331,'元曲/yuanqu.json','["将家私弃了，向山间林下；竹篱茅舍，看红叶黄花。", "待学那邵平，邵平多种瓜；闷采茶芽，闲看青松猿戏耍。", "麋鹿衔花，舟横在古渡。", "古渡整钓槎，夕阳西下；把《黄庭》《道德》都看罢，别是生涯。", "将茅庵盖了，独木为桥；提一壶好酒，闲访渔樵。", "洞门儿半掩，半掩无锁钥；白云笼罩，香风不动松花落。", "平生欢笑，松林下饮酒。", "饮得沉醉倒，山声野调；衲被蒙头直到晓，有甚烦恼。", "不贪名利，休争闲气；将衤阑袍脱下，宣敕收拾。", "金银垛到，垛到北斗齐；都成何济，过了一日无一日。", "谁落便宜，有钱不使。", "不使图甚底？谁是呆痴？儿孙自有儿孙力，悔后应迟。", "将簪冠戴了，麻袍宽超；拖一条藜仗，自带椰瓢。", "沿门儿花得，花得皮袋饱；傍人休笑，甘心守分学修道。", "乐乐陶陶，春花秋月。", "秋月何时了？心中欢乐；且自清闲直到老，散诞逍遥。"]'),
('yuanqu-10514','双调・秋江送','无名氏','元','元曲','yuanqu','','[]','财和气，酒共色，四般儿狠利害。',85,'元曲/yuanqu.json','["财和气，酒共色，四般儿狠利害。", "成与败，兴又衰，断送得利名人两鬓白。", "将名缰自解，利锁顿开，不索置田宅。", "何须趱金帛？则不如打稽首疾忙归去来。", "人老了也，少不的北邙山下丘土里埋。"]'),
('yuanqu-10515','双调・祆神急','无名氏','元','元曲','yuanqu','','[]','珠帘闲玉钩，宝篆冷金兽。',61,'元曲/yuanqu.json','["珠帘闲玉钩，宝篆冷金兽。", "银筝锦瑟，生疏了弦上手。", "恩情如纸叶薄，人比花枝瘦。", "雕鞍去，眉黛愁。", "数归期三月三，不觉的又过了中秋。"]'),
('yuanqu-10516','双调・青玉案','无名氏','元','元曲','yuanqu','','[]','插宫花饮御酒同欢乐，功劳薄上写上也么哥，万载标名麒麟阁。',45,'元曲/yuanqu.json','["插宫花饮御酒同欢乐，功劳薄上写上也么哥，万载标名麒麟阁。", "封妻荫子，进禄加官，想人生一世了。"]'),
('yuanqu-10517','双调・皂旗儿','无名氏','元','元曲','yuanqu','','[]','炕暖窗明草舍低，谁及？周公枕上梦初回，呀，直睡到上三竿红日。',30,'元曲/yuanqu.json','["炕暖窗明草舍低，谁及？周公枕上梦初回，呀，直睡到上三竿红日。"]'),
('yuanqu-10518','双调・阿纳忽','无名氏','元','元曲','yuanqu','','[]','双凤头金钗，一虎口罗鞋，天然海棠颜色，宜唱那阿纳忽修来。',144,'元曲/yuanqu.json','["双凤头金钗，一虎口罗鞋，天然海棠颜色，宜唱那阿纳忽修来。", "人立在厅阶，马控在瑶台。", "娇滴滴玉人扶策，宜唱那阿纳忽修来。", "逢好花簪带，遇美酒开怀。", "休问是非成败，宜唱那阿纳忽修来。", "花正开风筛，月正圆云埋。", "花开月圆人在，宜唱那阿纳忽修来。", "越范蠡功成名遂，驾一叶扁舟回归。", "去弄五湖云水，倒大来快活便宜。"]'),
('yuanqu-10519','双调・胡十八','无名氏','元','元曲','yuanqu','','[]','吹箫的楚伍员，乞食的汉韩信，待客的孟尝君，苏秦原是旧苏秦，买臣也曾负薪。',57,'元曲/yuanqu.json','["吹箫的楚伍员，乞食的汉韩信，待客的孟尝君，苏秦原是旧苏秦，买臣也曾负薪。", "负薪的是买臣，你道我穷到老，我也有富时分。"]'),
('yuanqu-10520','双调・山丹花','无名氏','元','元曲','yuanqu','','[]','昨朝满树花正开，胡蝶来，胡蝶来。',34,'元曲/yuanqu.json','["昨朝满树花正开，胡蝶来，胡蝶来。", "今朝花落委苍苔，不见胡蝶来，胡蝶来。"]'),
('yuanqu-10521','双调・鱼游春水','无名氏','元','元曲','yuanqu','','[]','角门儿关，夜香残，空着人直等到更阑。',47,'元曲/yuanqu.json','["角门儿关，夜香残，空着人直等到更阑。", "他今夜不来呵咱身上慢，闪的我孤单。", "孤单不曾惯，鲛俏泪不干。"]'),
('yuanqu-10522','双调・沽美酒过快活年','无名氏','元','元曲','yuanqu','','[]','黄超厮恋缠，冯魁又倚着家缘，俺软弱双郎又无甚钱。',175,'元曲/yuanqu.json','["黄超厮恋缠，冯魁又倚着家缘，俺软弱双郎又无甚钱。", "苏卿这里频频的祝愿，三件事告神天。", "只愿的霹雳火烧了丽春园，天索告圣贤，圣贤。", "浪滚处冲翻了贩茶船，休惊着双知县。", "称了平生愿，深谢天。", "冯魁又酒未醒，唤梅香点上银灯。", "俺软弱双郎何处等。", "唤梢公解开缆绳，早行过豫章城。", "只听得江水潺潺月儿明，听恰才敲二更，二更。", "手按着银筝盼多情，更阑人初静。", "赶不上临川令，苏小卿。"]'),
('yuanqu-10523','黄钟・醉花阴秋怀','无名氏','元','元曲','yuanqu','','[]','窗外芭樵战秋雨，又添上新愁几许。',49,'元曲/yuanqu.json','["窗外芭樵战秋雨，又添上新愁几许。", "珊枕剩绣衾余，落雁沉鱼，眼底知何处。", "酒醒后细踌蹰，一寸柔肠千万缕。"]'),
('yuanqu-10524','喜迁莺・把离人愁助，闹西风翠竹苍梧。萧疏，粉墙外霜砧辘轳。一片秋','无名氏','元','元曲','yuanqu','','[]','声厮断续，不知人心上苦。',28,'元曲/yuanqu.json','["声厮断续，不知人心上苦。", "捱不过追魂铁马，更和那索命铜壶。"]'),
('yuanqu-10525','出队子・记柳边朱户，乍相逢春正初。看一帘花雾暗香浮，爱满地凉蟾素','无名氏','元','元曲','yuanqu','','[]','练铺，听四座笙歌红袖舞。',12,'元曲/yuanqu.json','["练铺，听四座笙歌红袖舞。"]'),
('yuanqu-10526','幺・想多情丰度，论褒弹事事无。他有那西施妖艳不倾吴，小小风流不姓','无名氏','元','元曲','yuanqu','','[]','苏，巫女精神未遇楚。',10,'元曲/yuanqu.json','["苏，巫女精神未遇楚。"]'),
('yuanqu-10527','刮地风・看了他闭月羞花天付与，又何须傅粉涂朱。整罗衫款把寒温叙，','无名氏','元','元曲','yuanqu','','[]','礼法谁如？甫能够一番遭遇，便拚下百年欢聚。',63,'元曲/yuanqu.json','["礼法谁如？甫能够一番遭遇，便拚下百年欢聚。", "死生情山海誓永无忧虑，似鸾凤紧趁逐。", "毕罢了寄简传书，等闲间长就连理树，这言辞岂是虚。"]'),
('yuanqu-10528','西门子・自别来几见垂杨绿，悄然的音信疏。瘦影儿单，好梦儿孤，忆分','无名氏','元','元曲','yuanqu','','[]','携恁时风景殊。',25,'元曲/yuanqu.json','["携恁时风景殊。", "树影儿沉，日色儿哺，摆列下凄凉队伍。"]'),
('yuanqu-10529','古水仙子・我、我、我，自叹吁，罢、罢、罢，姻缘簿仍将姓字书。是、','无名氏','元','元曲','yuanqu','','[]','是、是，断云将楚岫遮拦，敢、敢、敢，桃花把天台截住，来、来、来，生分开比目鱼，呀、呀、呀，两三朝鬼病揶揄，是、是、是，教吹箫月明无伴侣。',97,'元曲/yuanqu.json','["是、是，断云将楚岫遮拦，敢、敢、敢，桃花把天台截住，来、来、来，生分开比目鱼，呀、呀、呀，两三朝鬼病揶揄，是、是、是，教吹箫月明无伴侣。", "他、他、他，把六朝金粉收拾去，单、单、单，留下写恨几行书。"]'),
('yuanqu-10530','尾声・曾指归期在春暮，却又早霜冷菰蒲，把灯花影儿终夜卜。赏玩','无名氏','元','元曲','yuanqu','','[]','杨柳横塘淡烟锁，娇滴滴芙蕖万朵。',49,'元曲/yuanqu.json','["杨柳横塘淡烟锁，娇滴滴芙蕖万朵。", "微雨过晚凉多。", "蝉咽庭柯，午梦方惊破。", "重洗盏泛金波，细细南薰透轻葛。"]'),
('yuanqu-10531','喜迁莺・少年行乐，好光阴暗里过。量度，想欢会人生几何，六代遗宫草','无名氏','元','元曲','yuanqu','','[]','树多。',20,'元曲/yuanqu.json','["树多。", "眼见的都证果，江山依旧，人物消磨。"]'),
('yuanqu-10532','出队子・与知音几个，得清闲非小可。折莫你重ブ列鼎更如何，积玉堆金','无名氏','元','元曲','yuanqu','','[]','待怎么，则待把利锁名缰都顿脱。',15,'元曲/yuanqu.json','["待怎么，则待把利锁名缰都顿脱。"]'),
('yuanqu-10533','刮地风・有时节放一个小小的兰舟随处泊，买娉婷二八秦蛾。碧荷筒旋拆','无名氏','元','元曲','yuanqu','','[]','倾香糯，痛饮狂歌，直吃的雕盘上彩云零落。',71,'元曲/yuanqu.json','["倾香糯，痛饮狂歌，直吃的雕盘上彩云零落。", "罗帕上酒痕湮污，花一攒锦一族仙人满座。", "小壶天风月窝，不受礼法拘缚。", "紫檀槽一曲笙歌佐。", "吹拨喜宫商乐韵和。"]'),
('yuanqu-10534','古水仙子・来、来、来，自忖度，罢、罢、罢，恐青镜流年两鬓皤。将、','无名氏','元','元曲','yuanqu','','[]','将、将，愁布袋丢开，把、把、把，闷葫芦摔破，呀、呀、呀，落些儿闲快活。',91,'元曲/yuanqu.json','["将、将，愁布袋丢开，把、把、把，闷葫芦摔破，呀、呀、呀，落些儿闲快活。", "休、休、休，走红尘万丈风波，喜、喜、喜，纵疏狂醉中天地阔。", "我、我、我，不干求到底无灾祸，他、他、他，进步是非多。"]'),
('yuanqu-10535','刮地风・不觉的滚滚杨花帘外糁，却又早春老江南。问东君未语心先憾，','无名氏','元','元曲','yuanqu','','[]','信断音缄。',63,'元曲/yuanqu.json','["信断音缄。", "只见他愿祷经函，鸾镜缺何时闻勘，凤钗折甚日重簪？连理分被刀砍，不由人梦断春酣。", "恨薄幸陡恁的将名利贪，敢心如痴意似憨。"]'),
('yuanqu-10536','四门子・约重阳回首无停暂，到如今三月三。偷香的胆谁人更敢，实丕丕','无名氏','元','元曲','yuanqu','','[]','已将风月担。',27,'元曲/yuanqu.json','["已将风月担。", "据着你动静又恬，才貌又堪，则将那莺花占揽。"]'),
('yuanqu-10537','赛儿令・偏咱，偏咱憔悴症候忒腌，满怀愁端的为谁耽。衔冤去投谢氏，','无名氏','元','元曲','yuanqu','','[]','无计去问巫咸。',15,'元曲/yuanqu.json','["无计去问巫咸。", "自叹息，自包含。"]'),
('yuanqu-10538','尾声・才郎直恁忒渔滥，设下誓神灵恁甘，哎，你个再出世的狠王魁怎下','无名氏','元','元曲','yuanqu','','[]','的辜负俺。',64,'元曲/yuanqu.json','["的辜负俺。", "思忆雪月风花共裁剪，云雨梦香娇玉软。", "花正发月初圆，雪压风颠。", "正比人天涯远，欲寄断肠篇。", "争奈这无边岸相思。", "好教我难运转。"]'),
('yuanqu-10539','喜迁莺・指沧溟为砚，管城毫健笔如椽。松烟，将太行山做墨研，把万里','无名氏','元','元曲','yuanqu','','[]','青天为锦笺，都做了草圣传。',36,'元曲/yuanqu.json','["青天为锦笺，都做了草圣传。", "我欲待要书，书不尽心事。", "一会家诉，诉不尽熬煎。"]'),
('yuanqu-10540','出队子・记当初相见，见俺那风流的小业冤。两心中便结死生缘，一载间','无名氏','元','元曲','yuanqu','','[]','浑如胶漆坚，谁承望半路里翻腾做离恨天。',19,'元曲/yuanqu.json','["浑如胶漆坚，谁承望半路里翻腾做离恨天。"]'),
('yuanqu-10541','幺篇・二三朝不见，浑如隔了十数年。无一顿茶饭不萦牵，无一刻光阴不','无名氏','元','元曲','yuanqu','','[]','怅念，无一个更儿里将他不梦见。',15,'元曲/yuanqu.json','["怅念，无一个更儿里将他不梦见。"]'),
('yuanqu-10542','刮地风・无一个来人行不问遍，害的我有似风颠。相识每见了重还劝，不','无名氏','元','元曲','yuanqu','','[]','由人不挂牵。',70,'元曲/yuanqu.json','["由人不挂牵。", "思量的眼前活现，作念的口中粘涎。", "襟领前、袖口边，泪痕湮遍。", "想从前语在先，那时节他娇小我当年。", "论聪明贯世何曾见，他敢真诚处有万千。"]'),
('yuanqu-10543','四门子・于咱家为他心无倦，气相和情绻恋。俺也曾坐并膝、语并肩，俺','无名氏','元','元曲','yuanqu','','[]','也曾芰荷香效他交颈鸳，俺也曾把手儿行，共枕儿眠，哎！天也，是我缘薄分浅。',36,'元曲/yuanqu.json','["也曾芰荷香效他交颈鸳，俺也曾把手儿行，共枕儿眠，哎！天也，是我缘薄分浅。"]'),
('yuanqu-10544','水仙子・非干是我自专，真觅得鸾胶续断弦。记枕上盟言，念神前心愿，','无名氏','元','元曲','yuanqu','','[]','我心坚石也穿，暗暗的祷告青天，若咱家少他前世冤，俏冤家不称今生愿，俺、俺、俺、俺，那世里再团圆。',48,'元曲/yuanqu.json','["我心坚石也穿，暗暗的祷告青天，若咱家少他前世冤，俏冤家不称今生愿，俺、俺、俺、俺，那世里再团圆。"]'),
('yuanqu-10545','尾声・嘱付你衷肠莫更变，更相逢不知是动岁经年，则要你身去远莫教心','无名氏','元','元曲','yuanqu','','[]','去远。',3,'元曲/yuanqu.json','["去远。"]'),
('yuanqu-10546','幺・辜恩一去成抛撇，他无情俺倒心呆。悔当时恨不锁雕鞍，扑倒得人香','无名氏','元','元曲','yuanqu','','[]','肌褪雪。',4,'元曲/yuanqu.json','["肌褪雪。"]'),
('yuanqu-10547','出队了・柔肠千结，算今番愁又别。长吁短叹不宁贴，泪眼愁眉怎打叠，','无名氏','元','元曲','yuanqu','','[]','若见他家亲自说。',8,'元曲/yuanqu.json','["若见他家亲自说。"]'),
('yuanqu-10548','幺・玉簪折怎得鸾胶接，见无由成间别。你不来人道你心邪，我先死天教','无名氏','元','元曲','yuanqu','','[]','我业彻，欲寄平安怎地写？。',13,'元曲/yuanqu.json','["我业彻，欲寄平安怎地写？。"]'),
('yuanqu-10549','尾・若把我双郎见时节，向三婆行诉不尽喉舌，则道是思量得小卿成病也。','无名氏','元','元曲','yuanqu','','[]','鸳鸯对，鸾凤鸣，恰寻着美满前程。',33,'元曲/yuanqu.json','["鸳鸯对，鸾凤鸣，恰寻着美满前程。", "团香惜玉好恩情，忽变做了充饥画饼。"]'),
('yuanqu-10550','幺・吉丁的分破菱花镜，扑冬的井坠银瓶。指出卖磨爱钱精，送得我离乡','无名氏','元','元曲','yuanqu','','[]','背井。',3,'元曲/yuanqu.json','["背井。"]'),
('yuanqu-10551','出队子・佳人薄幸，没福消双县令。老娘无赖，放过书生、秀士多魔，遇','无名氏','元','元曲','yuanqu','','[]','着柳青。',14,'元曲/yuanqu.json','["着柳青。", "妾守冯魁，似胲下瘿。"]'),
('yuanqu-10552','幺・恨东君不管人情淡，绽芳丛缬锦争搀。旧游园圃见停骖，思往事离愁','无名氏','元','元曲','yuanqu','','[]','越感。',3,'元曲/yuanqu.json','["越感。"]'),
('yuanqu-10553','出队子・慵临鸾鉴，瘦容颜影自惨。邻姬问我似痴憨，欲语无言心自惨，','无名氏','元','元曲','yuanqu','','[]','似恁熬煎可惯耽。',8,'元曲/yuanqu.json','["似恁熬煎可惯耽。"]'),
('yuanqu-10554','幺・看时节梦凡里将人赚，闪得奴恨不甘。山盟海誓我心贪，负德辜恩他','无名氏','元','元曲','yuanqu','','[]','意敢，悔恨当初我自揽。',11,'元曲/yuanqu.json','["意敢，悔恨当初我自揽。"]'),
('yuanqu-10555','尾・留恋你个三婆等时暂，则这几行书和泪封缄，写着道意不过呵肯来看','无名氏','元','元曲','yuanqu','','[]','探俺。',3,'元曲/yuanqu.json','["探俺。"]'),
('yuanqu-10556','正宫・端正好','无名氏','元','元曲','yuanqu','','[]','本是对美甘甘锦堂欢，生纽做愁切切阳关怨。',55,'元曲/yuanqu.json','["本是对美甘甘锦堂欢，生纽做愁切切阳关怨。", "恰离了莺花寨，早来到野水平川。", "急煎煎千里把程途践，景萧萧宜写在帏屏面。"]'),
('yuanqu-10557','滚绣球・动羁怀的是淅零零暮雨晴，恼人肠的是日迟迟春昼暄，感离情的','无名氏','元','元曲','yuanqu','','[]','是娇滴滴弄喉舌啼莺语燕。',116,'元曲/yuanqu.json','["是娇滴滴弄喉舌啼莺语燕。", "舞飘飘乱纷纷柳絮飞绵，叹浮生的是草萋萋际碧天，绿茸茸柳带烟。", "流尽年光的是兀良响潺潺碧澄澄皱玻璃楚江如练，断送行人的是忄乞登登鞭羸马行色凄然。", "猛想起醉醺醺昨宵欢会知多少，陡恁的冷清清今日凄凉有万千，情默默无言。"]'),
('yuanqu-10558','倘秀才・莫不是黄司理缘薄分浅，多管是双通叔时乖运蹇，小卿你再不向','无名氏','元','元曲','yuanqu','','[]','秦楼动管弦。',23,'元曲/yuanqu.json','["秦楼动管弦。", "彩鸾回舞镜，青鸟罢衔笺，兀良不远。"]'),
('yuanqu-10559','脱布衫・不行动则管里熬煎，休停待莫得俄延。侧着耳听沉沉半晌，唬得','无名氏','元','元曲','yuanqu','','[]','我那胆寒心战。',7,'元曲/yuanqu.json','["我那胆寒心战。"]'),
('yuanqu-10560','醉太平・原来是昏鸦噪暮天，落雁叫沙边。猛听得隔江人唤渡头船，啼红','无名氏','元','元曲','yuanqu','','[]','的是杜鹃。',46,'元曲/yuanqu.json','["的是杜鹃。", "我则见扑簌簌泪湿残妆面，将风流秀士莫留恋，生忄乞察拆散了并头莲，则为他多情的业冤。"]'),
('yuanqu-10561','尾・三杯别酒肚肠断，一曲阳关离恨添。我上车儿倦向前，他上雕鞍懒赠','无名氏','元','元曲','yuanqu','','[]','比各无言两泪涟，各办坚心石也穿。',69,'元曲/yuanqu.json','["比各无言两泪涟，各办坚心石也穿。", "两处相思情意牵，遥望见车儿渐渐的远。", "豪放不羁翠红乡莺花寨，占春风歌舞楼台。", "酒肠宽嫌杀金杯窄，会受用文章伯。"]'),
('yuanqu-10562','滚绣球・都将着玉与帛，换做酒共色，尽教咱百年欢爱，管甚么万贯资财。','无名氏','元','元曲','yuanqu','','[]','鬓发白，容貌改，物和人知他谁在，青春去再不回来。',50,'元曲/yuanqu.json','["鬓发白，容貌改，物和人知他谁在，青春去再不回来。", "一任教佳人宛转歌《金缕》，醉客佯狂饮绣鞋，便是英才。"]'),
('yuanqu-10563','醉太平・会三千剑客，列十二金钗，绮罗丛里玳筵开，俊娇娥侍侧。金莲','无名氏','元','元曲','yuanqu','','[]','款步香尘陌，春葱慢折花枝带，玉簪斜插鬓云歪，是风流腻色。',28,'元曲/yuanqu.json','["款步香尘陌，春葱慢折花枝带，玉簪斜插鬓云歪，是风流腻色。"]'),
('yuanqu-10564','滚绣球・溜秋波情意タ，并香肩语话儿甜。你为我鸳鸯债此生少欠，我为','无名氏','元','元曲','yuanqu','','[]','你风月担尽力粘拈。',89,'元曲/yuanqu.json','["你风月担尽力粘拈。", "我因你鱼书儿修以又修，你为我龟卦儿占了又占。", "想则想争想似更风流昔年双渐，猜则猜休猜做没出活今日江淹。", "则为这蝇头蜗角频勾引。", "非是这凤友鸾交厮弃嫌，辜负了等等潜潜。"]'),
('yuanqu-10565','倘秀才・一个风流如高才子瞻，一个聪明如能文蔡琰，似这等女貌郎才厮','无名氏','元','元曲','yuanqu','','[]','并兼。',24,'元曲/yuanqu.json','["并兼。", "娇羞甜腻腻，君子美谦谦，非是俺将言词故谄。"]'),
('yuanqu-10566','倘秀才・莫说道唤不醒呆庄周胡蝶梦甜，争知道医不可痴倩女揶揄病染，','无名氏','元','元曲','yuanqu','','[]','休猜俺山海恩情似水底盐。',32,'元曲/yuanqu.json','["休猜俺山海恩情似水底盐。", "鸳帏闲凤枕，鸾镜暗雕奁，流不尽腮边泪点。"]'),
('yuanqu-10567','叨叨令・风月情待把青楼占，慷慨情不把黄金俭，锦绣肠堪把秋娘赡，花','无名氏','元','元曲','yuanqu','','[]','月貌争把檀郎验。',31,'元曲/yuanqu.json','["月貌争把檀郎验。", "想杀人也么哥，想杀人也么哥，娇滴滴美玉无暇玷。"]'),
('yuanqu-10568','小梁州・妙舞清歌近绣と，不由人一笑掀髯，惜香怜玉那情タ，端的是心','无名氏','元','元曲','yuanqu','','[]','无厌，锦帐内效鹣鹣。',10,'元曲/yuanqu.json','["无厌，锦帐内效鹣鹣。"]'),
('yuanqu-10569','正宫・月照庭','无名氏','元','元曲','yuanqu','','[]','老足秋容，落日残蝉暮霞，归来雁落平沙。',40,'元曲/yuanqu.json','["老足秋容，落日残蝉暮霞，归来雁落平沙。", "水迢迢，烟淡淡，露湿蒹葭。", "飘红叶，噪晚鸦。"]'),
('yuanqu-10570','幺・古岸苍苍，寂寞渔村数家，茶船上那个娇娃。拥鸳衾，欹珊枕，情绪','无名氏','元','元曲','yuanqu','','[]','如麻。',11,'元曲/yuanqu.json','["如麻。", "愁难尽，闷转加。"]'),
('yuanqu-10571','幺・哭啼啼自咒骂，知他是忆念人么？蓦闻船上抚琴声，遣苏卿无语嗟呀。','无名氏','元','元曲','yuanqu','','[]','分明认得双解元，出兰舟绣鞋忙さ。',38,'元曲/yuanqu.json','["分明认得双解元，出兰舟绣鞋忙さ。", "乍相逢欲诉别离话。", "恶恨酒醒冯魁，惊梦杳无涯。"]'),
('yuanqu-10572','鸳鸯儿煞・觉来时痛恨半霎，梦魂儿依旧在篷窗下。故人不见，满江明月','无名氏','元','元曲','yuanqu','','[]','浸芦花。',4,'元曲/yuanqu.json','["浸芦花。"]'),
('yuanqu-10573','正宫・货郎儿','无名氏','元','元曲','yuanqu','','[]','静悄悄幽庭小院，近花圃相连着翠轩，仕女王孙戏秋千。',39,'元曲/yuanqu.json','["静悄悄幽庭小院，近花圃相连着翠轩，仕女王孙戏秋千。", "板冲开红杏火，裙拂散绿杨烟。"]'),
('yuanqu-10575','醉太平・那两个云游在半天，恰便似平地上登仙。晚来无力揽红绵，下秋','无名氏','元','元曲','yuanqu','','[]','千困倦。',35,'元曲/yuanqu.json','["千困倦。", "慢腾腾倚定花枝颤，汗漫漫湿透芙蓉面；金钗不整鬓云偏，吁吁气喘。"]'),
('yuanqu-10577','正宫・汲沙尾南四景','无名氏','元','元曲','yuanqu','','[]','金殿锁鸳鸯，何时重会情娘。',59,'元曲/yuanqu.json','["金殿锁鸳鸯，何时重会情娘。", "间阻佳期，咫尺雾迷云障。", "思量，常想那樽前席上。", "多丰韵容貌非常，风流艳妆，自古道淑女堪配才郎。"]'),
('yuanqu-10578','脱布衫带过小梁州北・歌《白雪》余韵悠扬，红牙撒尽按宫商。品玉箫鸾','无名氏','元','元曲','yuanqu','','[]','鸣凤叶，舞《霓裳》翠盘宫样。',95,'元曲/yuanqu.json','["鸣凤叶，舞《霓裳》翠盘宫样。", "解语知音所事强，端的是世上无双。", "冰弦慢拨趁奇腔，声嘹亮，口喷麝兰香。", "轻清韵美低低唱，启朱唇皓齿如霜。", "穿一套缟素衣，尽都是依宫样。", "又不是悲秋宋玉，可着我想像赋高唐。"]'),
('yuanqu-10579','渔家傲南・到春来和风荡，喷火夭桃，正宜玩赏，闲游戏拾翠寻芳，正春','无名氏','元','元曲','yuanqu','','[]','光艳阳。',62,'元曲/yuanqu.json','["光艳阳。", "雕梁乳燕呢喃两，游蜂趁蝶舞飞扬，正清和气爽。", "踏青载酒吟诗赋，斗草藏阄云锦乡。", "添情况，满斟着玉觞，遇韶华休负了好时光。"]'),
('yuanqu-10580','醉太平北・喜炎天昼长，避暑纳新凉。浮瓜沉李饮琼浆，听蝉鸣绿杨。榴','无名氏','元','元曲','yuanqu','','[]','花喷火争开放，葵花向日玻璃漾，荷花云锦满池塘。',31,'元曲/yuanqu.json','["花喷火争开放，葵花向日玻璃漾，荷花云锦满池塘。", "直吃的乐入醉乡。"]'),
('yuanqu-10581','普天乐南・玩中秋明月朗，登高在楼台上。东篱下菊蕊含金，正消磨暑气','无名氏','元','元曲','yuanqu','','[]','秋光。',43,'元曲/yuanqu.json','["秋光。", "捧玉觞，葡萄酿，酒友诗朋齐歌唱，玉山颓沉醉何妨。", "朱扉绿窗，任风吹落帽龙山赏重阳。"]'),
('yuanqu-10582','伴读书北・布彤云迷四方，朔风凛毡帘放。暖阁围炉频酾汤，正歌楼酒力','无名氏','元','元曲','yuanqu','','[]','添欢畅。',23,'元曲/yuanqu.json','["添欢畅。", "我则见多娇语笑樽席上，引的人腹热肠狂。"]'),
('yuanqu-10583','笑和尚北・我将慢徐徐语话讲，成就了风流况；共寝在绡金帐，诉衷情到','无名氏','元','元曲','yuanqu','','[]','耳傍，尽今生永成双。',32,'元曲/yuanqu.json','["耳傍，尽今生永成双。", "选良时配鸾凰。", "捧瑶觞赛神羊，将往时苦都撇漾。"]'),
('yuanqu-10585','仙吕・赏花时','无名氏','元','元曲','yuanqu','','[]','卧枕着床染病疾，梦断魂劳怕饮食。',36,'元曲/yuanqu.json','["卧枕着床染病疾，梦断魂劳怕饮食。", "不索请名医，沉吟了半日，这证候儿敢跷蹊。"]'),
('yuanqu-10586','幺・参的寒来恰禁起，忽的浑身如火气逼。厌的皱了双眉。豁的一会价精','无名氏','元','元曲','yuanqu','','[]','细，烘的半晌又昏迷。',10,'元曲/yuanqu.json','["细，烘的半晌又昏迷。"]'),
('yuanqu-10587','煞尾・减精神，添憔悴，把我这瘦损庞儿整理。对着那镜儿里容颜不认得，','无名氏','元','元曲','yuanqu','','[]','呆答孩转转猜疑。',91,'元曲/yuanqu.json','["呆答孩转转猜疑。", "瘦腰围，宽尽罗衣，一日有两三次频将带缋儿移。", "觑了这淹尖病体，比东阳无异，不似俺害相思出落与外人知。", "只为多情忒俊雅，月下星前拖逗煞。", "掩映着牡丹花，潜潜等等，不见劣冤家。"]'),
('yuanqu-10588','幺・今夜相逢打骂咱，忽见人来敢是他。只恐有争差，咨咨认了，正是那','无名氏','元','元曲','yuanqu','','[]','娇娃。',3,'元曲/yuanqu.json','["娇娃。"]'),
('yuanqu-10589','煞尾・悄悄吁，低低话，厮抽抒粘粘掐掐。终是女儿家不惯耍，庞儿不甚','无名氏','元','元曲','yuanqu','','[]','挣达。',74,'元曲/yuanqu.json','["挣达。", "透轻纱，双乳似白牙。", "插入胸前紧紧拿，光油油腻滑。", "颤巍巍拿罢，至今犹自手儿麻。", "春夜深沉庭院幽，偷访吹箫鸾凤友。", "良月过南楼，昨宵许俺，今夜结绸缪。"]'),
('yuanqu-10590','幺・两处相思一样愁，及至相逢却害羞。则是性儿柔，百般哀告，腼腆不','无名氏','元','元曲','yuanqu','','[]','抬头。',3,'元曲/yuanqu.json','["抬头。"]'),
('yuanqu-10591','煞尾・你温柔，咱清秀，本是一对儿风流配偶。咫尺相逢说上手，紧推辞','无名氏','元','元曲','yuanqu','','[]','不肯成头。',50,'元曲/yuanqu.json','["不肯成头。", "又不敢久迟留，只怕奶母追求。", "料想伊家不自由，空耽着闷忧。", "虚陪了消瘦，不承望刚做了个口儿休。"]'),
('yuanqu-10592','仙吕・点疑绛唇','无名氏','元','元曲','yuanqu','','[]','问柳寻芳，惜花怜月，心狂荡。',25,'元曲/yuanqu.json','["问柳寻芳，惜花怜月，心狂荡。", "名姓高扬，处处人瞻仰。"]'),
('yuanqu-10593','混江龙・樽前席上，偶然相遇俏萧娘。闲通局肆，善晓宫商。樊素口偏宜','无名氏','元','元曲','yuanqu','','[]','歌《白雪》，小蛮腰遍称舞《霓裳》。',31,'元曲/yuanqu.json','["歌《白雪》，小蛮腰遍称舞《霓裳》。", "妖娆相。", "花无宿艳，玉无温香。"]'),
('yuanqu-10594','醉中天・行院都皆赏，女伴每尽伏降。宝髻钗攒金凤凰，万种风流相。一','无名氏','元','元曲','yuanqu','','[]','见了教人断肠，可憎模样，宜梳宜画宜妆。',19,'元曲/yuanqu.json','["见了教人断肠，可憎模样，宜梳宜画宜妆。"]'),
('yuanqu-10595','金盏儿・性温良，貌非常。晓诗书通合刺知棋象，兰心蕙性世无双。蛾眉','无名氏','元','元曲','yuanqu','','[]','频扫黛，宫额淡涂黄。',22,'元曲/yuanqu.json','["频扫黛，宫额淡涂黄。", "半弯罗袜窄，十指玉纤长。"]'),
('yuanqu-10596','后庭花煞・有精神有伎俩，诸余里忒四行。出格心肠俏，过人手段强。细','无名氏','元','元曲','yuanqu','','[]','思量，风流模样，少个的亲心爱画眉郎。',45,'元曲/yuanqu.json','["思量，风流模样，少个的亲心爱画眉郎。", "赠妓淡扫蛾眉，粉容香腻，娇无力。", "绿鬓云垂，旖旎腰肢细。"]'),
('yuanqu-10597','混江龙・性资聪慧，对着这风花雪月有新题。金篦击节，翠袖擎杯。妙舞','无名氏','元','元曲','yuanqu','','[]','几番银烛暗，清歌一曲彩云低。',63,'元曲/yuanqu.json','["几番银烛暗，清歌一曲彩云低。", "朝朝宴乐，夜夜佳期。", "偎红倚翠，绣幌罗帏。", "生在这锦营花阵繁华地，逞风流在销金帐里，叙幽情在燕子楼西。"]'),
('yuanqu-10598','油葫芦・则这送旧迎新有尽期，少年时能有几？我则怕镜中白发老来催，','无名氏','元','元曲','yuanqu','','[]','有一日花残色改容颜退，到头来怎是你终身计？床头又囊箧乏，门前又鞍马稀。',56,'元曲/yuanqu.json','["有一日花残色改容颜退，到头来怎是你终身计？床头又囊箧乏，门前又鞍马稀。", "趁青春若得个良人配，怎做得张郎妇李郎妻？。"]'),
('yuanqu-10599','天下乐・引的些俊俏郎君着意迷，使了虚脾；小儿识，陷人坑尽深难见底。','无名氏','元','元曲','yuanqu','','[]','惹得人父母嫌，搬得人妻子离，便趱得钱财多有甚奇。',24,'元曲/yuanqu.json','["惹得人父母嫌，搬得人妻子离，便趱得钱财多有甚奇。"]'),
('yuanqu-10600','那吒令・盈斟着酒杯，则不如桑麻纺织；轻罗细丝，则不如荆钗布衣；珍','无名氏','元','元曲','yuanqu','','[]','馐美味，则不如家常饭食。',29,'元曲/yuanqu.json','["馐美味，则不如家常饭食。", "免得弃旧人迎新婿，到大来无是无非。"]'),
('yuanqu-10601','鹊踏枝・昨日个叙别离，今日个待相识。眼面前秋月春花，头直上兔走乌','无名氏','元','元曲','yuanqu','','[]','叹光阴白驹过隙，我则怕下场头乐极生悲。',19,'元曲/yuanqu.json','["叹光阴白驹过隙，我则怕下场头乐极生悲。"]'),
('yuanqu-10602','寄生草・早寻个归秋日，急回头也是迟，谁待要陪狂伴醉筵间立，谁待要','无名氏','元','元曲','yuanqu','','[]','迎妍卖俏门前倚，谁待要打牙讪口闲淘气。',41,'元曲/yuanqu.json','["迎妍卖俏门前倚，谁待要打牙讪口闲淘气。", "少不得花浓酒酽有时休，那其间东君不管人憔悴。"]'),
('yuanqu-10603','金盏儿・费追陪，笑相随，东家会了西家会，每日家逢场作戏强支持。擎','无名氏','元','元曲','yuanqu','','[]','杯淹翠袖，翻酒污罗衣。',26,'元曲/yuanqu.json','["杯淹翠袖，翻酒污罗衣。", "抵多少惜花春起早，爱月夜眠迟。"]'),
('yuanqu-10604','后庭花・唤官身无了期，做排场抵暮归。则待学不下堂糟糠妇，怎做得出','无名氏','元','元曲','yuanqu','','[]','墙花临路岐？使了些巧心机，那里有真情实意。',50,'元曲/yuanqu.json','["墙花临路岐？使了些巧心机，那里有真情实意。", "迷魂汤滋味美，纸汤瓶热火煨。", "初相逢一面儿喜，才别离便泪垂。"]'),
('yuanqu-10605','尾声・跳不出引魂灵的绮罗丛，迷子弟莺花队，费精神花朝月夕。醉舞狂','无名氏','元','元曲','yuanqu','','[]','歌供宴集，樽席上做小伏低，敛愁眉强整容仪。',54,'元曲/yuanqu.json','["歌供宴集，樽席上做小伏低，敛愁眉强整容仪。", "你便是法酒肥羊不甚美，子不如绩麻拈絮，随缘活计，那其间方是得便宜。"]'),
('yuanqu-10606','仙吕・村里迓鼓四季乐情','无名氏','元','元曲','yuanqu','','[]','正值着丽人天气，可正是赏花赏花的这时候。',87,'元曲/yuanqu.json','["正值着丽人天气，可正是赏花赏花的这时候。", "你看那花红和这柳绿，绕着这舍南舍北、庄前庄后。", "则见那柳飞绵，花似锦，江山清秀。", "他每都携着美酝，穿红杏，摇翠柳，我直吃的笑吟吟醺醺带酒。"]'),
('yuanqu-10607','元和令・锦模糊江景幽，翠がテ远山秀。正值着稻分畦，蚕入簇麦初熟，','无名氏','元','元曲','yuanqu','','[]','太平人闲袖手。',34,'元曲/yuanqu.json','["太平人闲袖手。", "趁着这古堤沙岸绿阴稠，缆船儿执着钓钩，缆船儿执着钓钩。"]'),
('yuanqu-10608','上马娇・我将这锦鲤兜，网索来收。村务内酒初熟，恰归来半醉黄昏后。','无名氏','元','元曲','yuanqu','','[]','暮雨收，牧童儿归去倒骑牛。',13,'元曲/yuanqu.json','["暮雨收，牧童儿归去倒骑牛。"]'),
('yuanqu-10609','游四门・正是枫麻梧叶报新秋，呀呀的寒雁过南楼。正遇着鸡肥蟹壮秋收','无名氏','元','元曲','yuanqu','','[]','候，霜降水痕收。',20,'元曲/yuanqu.json','["候，霜降水痕收。", "朋友每留，乘兴饮两三瓯。"]'),
('yuanqu-10610','胜葫芦・正值着浅碧的这粼粼露远洲，赏红叶一枝秋，我则见三径黄花景','无名氏','元','元曲','yuanqu','','[]','物幽。',24,'元曲/yuanqu.json','["物幽。", "正值着丰年稔岁，太平箫鼓，酒醒时节再扶头。"]'),
('yuanqu-10611','柳叶儿・我真吃到二更的时候，正喧哗交错觥筹，一任教月移梅影横窗瘦。','无名氏','元','元曲','yuanqu','','[]','心相爱，意相投，醉时节纳被蒙头。',16,'元曲/yuanqu.json','["心相爱，意相投，醉时节纳被蒙头。"]'),
('yuanqu-10612','仙吕・八声甘州','无名氏','元','元曲','yuanqu','','[]','杯中酒冷，鼎内香消，台上灯昏。',55,'元曲/yuanqu.json','["杯中酒冷，鼎内香消，台上灯昏。", "夜间人静，书斋中半掩重门。", "愁靠芙蓉绣枕边，闷拥鲛绡锦被。", "空思想意中人，年少芳温。"]'),
('yuanqu-10613','醉中天・一点朱唇嫩，八字柳眉颦。宝髻高梳楚岫云，莲脸施朱粉。包弹','无名氏','元','元曲','yuanqu','','[]','处全无半分，可人意风韵，见他时忽的销魂。',20,'元曲/yuanqu.json','["处全无半分，可人意风韵，见他时忽的销魂。"]'),
('yuanqu-10614','赚尾・为他娇，因他俊，迤逗的俺行痴立盹。便得后冤家行频觑付，偷工','无名氏','元','元曲','yuanqu','','[]','夫短命行温存。',98,'元曲/yuanqu.json','["夫短命行温存。", "是费了些精神，一夜欢娱正了本。", "他于咱意亲，俺于他心顺，不由人终日脚儿勤。", "芳菲过眼，向玉砌雕阑，翠落红翻。", "都来一段，新愁旧恨相烦。", "帘垂永日人乍别，门掩东风花又残。", "无语问春归，天上人间。"]'),
('yuanqu-10615','六幺遍・恨归期晚，寻芳懒。倚遍阑干，盼煞雕鞍，佳音越悭，啼泪不干。','无名氏','元','元曲','yuanqu','','[]','生睚厌厌相思恨，愁烦，闷来独把绣床攀。',19,'元曲/yuanqu.json','["生睚厌厌相思恨，愁烦，闷来独把绣床攀。"]'),
('yuanqu-10616','元和令・谩将龟卦揭，空把雁书盼。料他云雨兴阑珊，天涯何日还。重衾','无名氏','元','元曲','yuanqu','','[]','犹怯五更寒，闷愁心上攒。',12,'元曲/yuanqu.json','["犹怯五更寒，闷愁心上攒。"]'),
('yuanqu-10617','后庭花・瘦来金缕宽，空将宝镜看；髻绾双鬟乱，眉颦八字弯。最心烦，','无名氏','元','元曲','yuanqu','','[]','花开庭院，子规啼数番。',11,'元曲/yuanqu.json','["花开庭院，子规啼数番。"]'),
('yuanqu-10619','梧桐树・刚道声才郎身去心休去，他揽与俺回挽得千条柳难系雕鞍住。到','无名氏','元','元曲','yuanqu','','[]','如今百草枯风吹得红叶舞，正值着秋天暮。',19,'元曲/yuanqu.json','["如今百草枯风吹得红叶舞，正值着秋天暮。"]'),
('yuanqu-10620','感皇恩・呀！骨剌剌风透纱厨，吉丁当漏滴铜壶。薄设设被儿单，昏昏惨','无名氏','元','元曲','yuanqu','','[]','惨灯儿暗，瘦厌厌影儿孤。',36,'元曲/yuanqu.json','["惨灯儿暗，瘦厌厌影儿孤。", "思伊受苦，偏俺负你何辜。", "从春去，因应举，恋皇都。"]'),
('yuanqu-10621','采茶歌・他去了半年余，闪得我受孤独，罗帏寂寞故人无。寒雁来时音信','无名氏','元','元曲','yuanqu','','[]','杳，雁还归去亦无书。',10,'元曲/yuanqu.json','["杳，雁还归去亦无书。"]'),
('yuanqu-10622','尾・知他是谁家月馆风亭宿？何处山村野店居？锦堂春翻做阳关路。多情','无名氏','元','元曲','yuanqu','','[]','弄玉，若见吹箫伴侣，慢慢的说俺从前受过的苦。',87,'元曲/yuanqu.json','["弄玉，若见吹箫伴侣，慢慢的说俺从前受过的苦。", "嘲黑妓脸如百草霜，唇注松烟墨。", "眼横潭底水，牙染连金泥。", "乌玉如肌，眉不显春山翠，似葡萄好乳垂。", "若不是薄荷煎每日充饥，渎牙药逐朝漱洗。"]'),
('yuanqu-10623','梁州・我子道克剌张回回姊妹，却原来是大洪山三圣姨姨。猛回头错认做','无名氏','元','元曲','yuanqu','','[]','砂锅底。',121,'元曲/yuanqu.json','["砂锅底。", "只合去烧窑淘炭，漆碗熏杯。", "怎生去迎新送旧，卖笑求食。", "便是块黑砂糖有甚希奇，便是块试金石难辨高低。", "莫不寨儿中书下的灵符，莫不是房儿中描来的黑鬼，莫不是酒楼前贴下钟馗。", "这妮子幼年间充着壬癸，生长在乌衣国。", "靠定门帘不动衣，百般的辨不得容仪。"]'),
('yuanqu-10624','尾・不索你分星擘两显名儿唤，路上行人口胜碑，这娘子骂得他都易。泪','无名氏','元','元曲','yuanqu','','[]','滴下些黑汁，脚踢起些炭气，吁得青铜镜儿黑。',82,'元曲/yuanqu.json','["滴下些黑汁，脚踢起些炭气，吁得青铜镜儿黑。", "惜春春阴低画阁，梅瓣琼英落。", "晓光浮绿野，草色翠纱娇。", "莺语般挑，断送得风光好，隔墙声尤自巧。", "道游人莫惜千金，春色渐三分过了。"]'),
('yuanqu-10625','梁州・海棠睡娇容似醉，柳风轻绿线如缫，轮蹄碾破青青草。酒家何处，','无名氏','元','元曲','yuanqu','','[]','沾旆招摇；画船无数，舞袖翩跹。',92,'元曲/yuanqu.json','["沾旆招摇；画船无数，舞袖翩跹。", "风流杀凤管鸾箫，多情杀翠髻云翘。", "梨花院爱月眠迟，杏花楼惜花起早，桃花庄觅句相嘲。", "鬓角，二毛。", "晓来镜里都知道，忽忽地又过了年少。", "苦雨酸风昨夜恶，恐一片花飘。"]'),
('yuanqu-10626','尾・绿阴繁渐渐春风老，玉壶暖迟迟夜月高，九十日光阴能有几日笑。朱','无名氏','元','元曲','yuanqu','','[]','帘下着，低垂绣幄，休放那搅春梦呢喃燕来了。',80,'元曲/yuanqu.json','["帘下着，低垂绣幄，休放那搅春梦呢喃燕来了。", "夏景池塘睡锦鸳，楼阁飞双燕。", "红榴招戏蝶，绿柳噪新蝉。", "葵火阶前，竹笋侵墙串，泉流草径边。", "绿茸茸蓑展青毡，密匝匝苔铺翠藓。"]'),
('yuanqu-10627','隔尾・一弯新月添诗卷，十里香风助酒筵。向晚归来小庭院，簟纹铺水渊。','无名氏','元','元曲','yuanqu','','[]','纱厨挂雾烟，一枕珊瑚梦魂远。',82,'元曲/yuanqu.json','["纱厨挂雾烟，一枕珊瑚梦魂远。", "春雪和风动草芽，暖日催花萼。", "桃腮生红脸，柳眼发青胞。", "卷地风号，扑面梨花落，抵多少彤云埋树梢。", "我则见千百片柳絮飞扬，恰便似万万队蛾儿乱搅。"]'),
('yuanqu-10628','梁州第七・担阁了闺院女西园斗草，误了你也富贵郎南陌东郊。只见白茫','无名氏','元','元曲','yuanqu','','[]','茫迷却前村道。',117,'元曲/yuanqu.json','["茫迷却前村道。", "那里也游蜂采蕊，那里也紫燕寻巢，那里也莺声恰恰，那里也蝶翅飘飘。", "洒歌楼酒力微消，望江天万里琼瑶。", "恰便似银砌就枯木寒鸦，玉琢就冰枝冻雀，粉妆成野杏山桃。", "浅桥，填了。", "负薪樵子归岩峤，渔翁冷怎垂钓？古寺里山僧煮茗瀹，对景寂寥。"]'),
('yuanqu-10629','梁州・演步虚轻敲檀板，炼华池净洗胭脂。入山林远闺阁和街市。不跨鹤','无名氏','元','元曲','yuanqu','','[]','超凡小小，不乘鸾得道师师。',117,'元曲/yuanqu.json','["超凡小小，不乘鸾得道师师。", "惯弃俗缠头红锦，惯出家买笑金赀。", "风流客普化相思，疏狂士稽首相辞。", "碧玉簪芙蓉冠新入个名流，青霞帔逍遥服新裁个样子，黄金钟蕊珠经另打个腔儿。", "念兹，在兹。", "心中猿意内马情无二，多财舍有缘施。", "谁种红莲火里枝，朵朵灵芝。"]'),
('yuanqu-10630','尾・参礼透朝云暮雨情如纸，戒得断酒病花愁气似丝，修养出丰标更谁似？','无名氏','元','元曲','yuanqu','','[]','蓬莱山降赐，蟠桃会宴侍，再谪下个神仙度脱你。',79,'元曲/yuanqu.json','["蓬莱山降赐，蟠桃会宴侍，再谪下个神仙度脱你。", "莺眠柳嵌金，蝶宿梨藏玉。", "草泥迷燕嘴，花蕊上蜂须。", "春雨如酥，妆点繁华富，寻芳上苑初。", "花圃内蝶戏蜂游，柳塘边莺啼燕语。"]'),
('yuanqu-10631','梁州・花似锦满枝开放，草如烟遍野均铺。海棠娇滴胭脂露。王孙宝马，','无名氏','元','元曲','yuanqu','','[]','仕女香车。',89,'元曲/yuanqu.json','["仕女香车。", "踏青南陌，载酒西湖。", "一弄儿景致非俗，三般儿巧笔堪图。", "草如烟翠锦笼纱，梨花月琼林捧玉，杨柳露绿线穿珠。", "自想！老夫。", "侬家鹦鹉洲边住，那的是快活外。", "钓得鱼来卧看书，酒满葫芦。"]'),
('yuanqu-10632','尾・绿杨影里鸠啼妇，红杏枝头燕引雏，锦片也似园林无半答儿空闲外。','无名氏','元','元曲','yuanqu','','[]','似邵平杜甫，仆僮共蹇驴，游遍春光看不足。',79,'元曲/yuanqu.json','["似邵平杜甫，仆僮共蹇驴，游遍春光看不足。", "渔隐不沽朝野名，自守烟波分。", "斜风新箬笠，细雨旧丝纶。", "志访玄真，家与秦淮近，清时容钓隐。", "相看着绿水悠悠，回避了红尘滚滚。"]'),
('yuanqu-10633','骂玉郎・一篝灯下ド佳酝，身趔趄，醉醺醺，高歌细和沧浪韵。全不受利','无名氏','元','元曲','yuanqu','','[]','名拘，那里将兴亡记？把什么荣枯问？。',18,'元曲/yuanqu.json','["名拘，那里将兴亡记？把什么荣枯问？。"]'),
('yuanqu-10634','采茶歌・山妻也最甘贫，稚子也颇通文，无忧无虑度朝昏。但得年年生意','无名氏','元','元曲','yuanqu','','[]','好，武陵何用访秦人。',10,'元曲/yuanqu.json','["好，武陵何用访秦人。"]'),
('yuanqu-10635','尾・茫茫烟水无穷尽，泛泛萍踪少定根。为甚生平怕求进？想王侯大勋，','无名氏','元','元曲','yuanqu','','[]','博渔樵一哂，争似我一叶江湖钓船稳。',76,'元曲/yuanqu.json','["博渔樵一哂，争似我一叶江湖钓船稳。", "香绵梨云梦渺漫，柳絮春零乱。", "轻盈怜鲁缟，皎洁胜齐纨。", "雾霭雕盘，韩寿衣沾爨，风流引俊潘。", "蜘蛛丝晓挂雕檐，胡蝶粉时飘谢馆。"]'),
('yuanqu-10636','尾・揭鹅脂铺锦被鸳鸯交颈三千段，分茧套办妆奁翡翠笼欢一万端。遮莫','无名氏','元','元曲','yuanqu','','[]','黑雪乌风夜将半，将着这几般，床儿上垛满，用意温存正睡得暖。',93,'元曲/yuanqu.json','["黑雪乌风夜将半，将着这几般，床儿上垛满，用意温存正睡得暖。", "盼望难摘镜里花，怎捞江心月？空闻三足乌，不识两头蛇。", "四件情节，堪比虚疼热。", "听叮咛仔细说，谎恩情如炭火上消冰，虚疼热似滚汤中化雪。"]'),
('yuanqu-10637','尾・晓行藏知起倒翻身跳出鸳鸯社，能进退识高低大步冲开狼虎穴。暗想','无名氏','元','元曲','yuanqu','','[]','人儿性薄劣，再休寄陷郎君的缄贴。',107,'元曲/yuanqu.json','["人儿性薄劣，再休寄陷郎君的缄贴。", "赚孤老的话啜，则今番辞了莺花路儿也。", "春日即事草堂外岚光映日妍，粉墙边梅萼冲寒谢。", "小沼上绿波随雨涨，画阑前新柳受风斜。", "春意奇绝，老眼偏欢悦，闲情且打叠。", "散床头有限黄金，怕镜里无情白雪。"]'),
('yuanqu-10638','梁州・裁漉酒笼头纱帻，制踏青可脚乌靴。与知音三五词林社。超群洒落，','无名氏','元','元曲','yuanqu','','[]','异众豪杰。',109,'元曲/yuanqu.json','["异众豪杰。", "厌谈名利，不尚娇奢。", "喜的是一村村径路曲折，爱的是一程程风景全别。", "买花钱滴溜溜杖上挑着，沽酒店闹炒炒桥边问也，载诗囊胀膨膨驴背上驮者。", "看了他这些，那些。", "翠屏锦帐参差列，寻疏篱，觅茅舍。", "随定狂蜂与浪蝶，任意跋涉。"]'),
('yuanqu-10639','尾・醉依芳草须拚藉，笑对青山不忍的别。残角江楼正呜咽，却又早鸦归','无名氏','元','元曲','yuanqu','','[]','古堞。',80,'元曲/yuanqu.json','["古堞。", "烟迷绿野，堪付与老手王维画图中写。", "棋黄金罢酒筹，彩笔停诗兴。", "青云盈座榻，红日满檐楹。", "闲展揪枰，初布势求全胜，后分途起战争。", "保无虞端可藏机，观有衅方堪入境。"]'),
('yuanqu-10640','梁州・响铮铮交锋递子，密匝匝彼此排兵。王质斧烂腰间柄。机深脱骨，','无名氏','元','元曲','yuanqu','','[]','智浅逢征。',89,'元曲/yuanqu.json','["智浅逢征。", "坚牢正走，取败斜行。", "势将颓锐意侵陵，局已胜专保求生。", "两家持各指鸿沟，几番诈宵奔马陵，数重围夜遁平城。", "猛听，一声。", "盘中子落将军令，黑白满势才定。", "紧紧收拾未见赢，怎敢消停。"]'),
('yuanqu-10641','尾声・壮如霸王来扛鼎，险似韩侯出井陉。悬权岂敢轻相应，切勿食饵兵，','无名氏','元','元曲','yuanqu','','[]','便休图小成。',83,'元曲/yuanqu.json','["便休图小成。", "细看来孙武权谋，其实的细相等。", "道情公行天理明，私意人心暗。", "古书读未了，世事饱经谙。", "图什么贪婪，名利境多坑陷，羡青门瓜正甘。", "园林茂堪置幽居，山水秀真为胜览。"]'),
('yuanqu-10642','梁州・流水绕一村桑柘，乱山围四壁烟岚。颠峰倒影澄波蘸。遥岑叠翠，','无名氏','元','元曲','yuanqu','','[]','远水揉蓝。',89,'元曲/yuanqu.json','["远水揉蓝。", "鸢飞鹭落，鱼跃深潭。", "偃怡场水府山岩，安乐窝土洞石龛。", "景不嫌物少人稀，食不厌茶浑酒淡，家不离水北山南。", "有何，不堪？篮舆到水轻舟泛，稼穑外得时暂。", "闲饮渔樵酒半酣，阔论高谈。"]'),
('yuanqu-10643','中吕・粉蝶儿','无名氏','元','元曲','yuanqu','','[]','男子当途，受皇恩稳食天禄，凭着济世才列郡分符。',49,'元曲/yuanqu.json','["男子当途，受皇恩稳食天禄，凭着济世才列郡分符。", "事君忠，于亲孝，下安黎庶。", "驷马高车，正清朝太平时世。"]'),
('yuanqu-10644','醉春风・娶一个鸳帐凤帏人，一个雾鬓云鬟女。退□时开宴后堂中，此心','无名氏','元','元曲','yuanqu','','[]','是足，足。',27,'元曲/yuanqu.json','["是足，足。", "一个吴越妖娆，一个幽燕佳丽，都有那可人情绪。"]'),
('yuanqu-10645','迎仙客・一个带玉钗，一个插犀梳，天然一双美艳姝。一个是晓莺啼，一','无名氏','元','元曲','yuanqu','','[]','个是雏凤语。',22,'元曲/yuanqu.json','["个是雏凤语。", "一个生长在皇都，一个妾本钱塘住。"]'),
('yuanqu-10646','红绣鞋・一个看白草风吹北固，一个赏红莲烟水西湖。眼落处逢场取欢娱，','无名氏','元','元曲','yuanqu','','[]','向南来乘著画舸。',22,'元曲/yuanqu.json','["向南来乘著画舸。", "投北去载着香车，同居深院宇。"]'),
('yuanqu-10647','石榴花・停头的和顺做妻夫，则要你休争竞，厮宾伏。两间罗幕碧纱厨，','无名氏','元','元曲','yuanqu','','[]','收拾着睡处，准备活路。',43,'元曲/yuanqu.json','["收拾着睡处，准备活路。", "樽前席上同完聚，醉时节左右相扶。", "宴阑时各自归房去，同欢庆不偏辜。"]'),
('yuanqu-10648','耍孩儿・桃腮杏脸娇人物，五百年姻缘眷属。一个入时颜色动京师，一个','无名氏','元','元曲','yuanqu','','[]','繁华南国娇姝。',57,'元曲/yuanqu.json','["繁华南国娇姝。", "一个道杜鹃声里奴宅舍，一个道朝马尘中妾祖居，彼各夸乡故。", "一个道玩日华五云楼观，一个道看潮鸣八月江湖。"]'),
('yuanqu-10649','三煞・仙衣观剪裁绮罗，新制出一个绣援蓝衫子拖他绿。一个白罗帕兜映','无名氏','元','元曲','yuanqu','','[]','遮尘笠，一个乌云髻斜簪压鬓梳。',35,'元曲/yuanqu.json','["遮尘笠，一个乌云髻斜簪压鬓梳。", "一个赴筵会娇乘翠辇，一个随人情稳坐肩舆。"]'),
('yuanqu-10650','二煞・一个要白熟饼烂煮羊，一个要炊香粳喇纂鱼，同茶同饭同樽俎。醉','无名氏','元','元曲','yuanqu','','[]','来时枕遍黄金串，情极处亲偎白玉肤，相怜处。',43,'元曲/yuanqu.json','["来时枕遍黄金串，情极处亲偎白玉肤，相怜处。", "到夏里洒扫净凉亭水阁，到冬来安排着暖阁红炉。"]'),
('yuanqu-10651','一煞・一个休寻常看侍妾，一个莫等闲抛调奴，把凭似玉天仙手掌擎心肝','无名氏','元','元曲','yuanqu','','[]','般戏。',49,'元曲/yuanqu.json','["般戏。", "一个演习那渐间言语呼郎婿，一个撇着些都下乡音唤丈夫，休相妒。", "你莫琴书上意懒，你休针线上清疏。"]'),
('yuanqu-10652','尾・一般儿难主张，两下里自暗忖。五花诰使不得人情与，看那一个娇羞','无名氏','元','元曲','yuanqu','','[]','做得主。',58,'元曲/yuanqu.json','["做得主。", "阅世自汉浮生，怎生来恁般薄命。", "从幼年间踢透聪明，折末作文章，通经史，诗词歌咏。", "今日长达刑名，颇谙知古今律令。"]'),
('yuanqu-10653','醉春风・折末围棋赶个相知，打双陆攀个门庭。折末妆跷小踢赛个输赢，','无名氏','元','元曲','yuanqu','','[]','不是我逞，逞，逞。',30,'元曲/yuanqu.json','["不是我逞，逞，逞。", "折末共释道清谈，渔樵闲话，我可也略通蹊径。"]'),
('yuanqu-10654','剔银灯・折末道谜续麻合笙，折末道字说书打令，诸般乐艺都曾领。向人','无名氏','元','元曲','yuanqu','','[]','前举目回情，疏狂性，湖海情，更爱的是弟兄。',21,'元曲/yuanqu.json','["前举目回情，疏狂性，湖海情，更爱的是弟兄。"]'),
('yuanqu-10655','蔓青菜・脚到处人相敬，都为我忒惺惺，倒担阁了半生。几番待发志气修','无名氏','元','元曲','yuanqu','','[]','身于功名，争奈一缕顽涎硬。',13,'元曲/yuanqu.json','["身于功名，争奈一缕顽涎硬。"]'),
('yuanqu-10656','石榴花・一片惜花心常是引了人魂灵，但沾着便留情。玉箫檀板紫鸾笙，','无名氏','元','元曲','yuanqu','','[]','向花阵锦营，燕燕莺莺。',52,'元曲/yuanqu.json','["向花阵锦营，燕燕莺莺。", "悲欢聚散常无定，落得去秦楼谢馆贪滥风声。", "好光阴过眼如翻饼，到担阁了锦片也似好前程。"]'),
('yuanqu-10657','满庭芳・屈指数班行后生，少甚么无才无德，无义无能。一跳身平步登台','无名氏','元','元曲','yuanqu','','[]','省，一个头角峥嵘。',52,'元曲/yuanqu.json','["省，一个头角峥嵘。", "更做八字拙难和我命争，怎生二十年一事无成。", "我这里羞临镜，我呆心儿自惊，又早白发鬓边生。"]'),
('yuanqu-10658','耍孩儿・叹荣枯得失皆前定，富贵由人生五行。花花草草煞曾经，不恋他','无名氏','元','元曲','yuanqu','','[]','薄利虚名。',53,'元曲/yuanqu.json','["薄利虚名。", "则不如盖三间茅舍埋头住，买数亩荒田亲自耕。", "或临溪崖，或是环山径。", "受用些竹篱茅舍，拜辞了月馆风亭。"]'),
('yuanqu-10659','二・偎山边建草堂，临江滨买只钓艇。我和樵夫渔父相随趁。说今来古往','无名氏','元','元曲','yuanqu','','[]','非和是，讲沧海桑田废与兴。',29,'元曲/yuanqu.json','["非和是，讲沧海桑田废与兴。", "耳畔常清净，无来无往，无送无迎。"]'),
('yuanqu-10660','三・新茅柴沽满瓶，活鲜鱼旋煮铛。粗衣淡饭无监禁。闷来时看四周翠岫','无名氏','元','元曲','yuanqu','','[]','烟霞景，闲来时诵一卷黄庭道德经。',35,'元曲/yuanqu.json','["烟霞景，闲来时诵一卷黄庭道德经。", "倒大来身心静。", "非是无钱断酒，临老修行。"]'),
('yuanqu-10661','四・叹人生似水上萍，富贵如风里灯。出门来一步一个风光景。量着六斗','无名氏','元','元曲','yuanqu','','[]','米司吏何足数，便升做千两俸人员有甚荣，图个甚闲争竞。',42,'元曲/yuanqu.json','["米司吏何足数，便升做千两俸人员有甚荣，图个甚闲争竞。", "想十大功韩信，到不如五斗酒刘伶。"]'),
('yuanqu-10662','尾・说着做郎君脸上羞，千功名脑袋疼。丽春园子弟埋名姓，邯郸道先生','无名氏','元','元曲','yuanqu','','[]','这回省。',59,'元曲/yuanqu.json','["这回省。", "思情花落春残，舞东风乱红飘散，黛眉颦宝鉴空闲。", "似这般苦相思，活地狱，几曾经惯。", "隔天涯何处雕鞍，望关河杳无鱼雁。"]'),
('yuanqu-10663','醉春风・粉脸带胭憔，香魂和梦返。一天风月冷阳关，畅好是懒、懒。看','无名氏','元','元曲','yuanqu','','[]','了这锁径苍苔，扑帘柳絮，绕栏花瓣。',17,'元曲/yuanqu.json','["了这锁径苍苔，扑帘柳絮，绕栏花瓣。"]'),
('yuanqu-10664','迎仙客・淹泪眼，锁愁颜，青丝半堆云乱挽。我则道歇秋千，闲画板。不','无名氏','元','元曲','yuanqu','','[]','能够遗兴消烦，则落的一口儿长吁叹。',17,'元曲/yuanqu.json','["能够遗兴消烦，则落的一口儿长吁叹。"]'),
('yuanqu-10665','红绣鞋・盼子盼佳期枉盼，难应难要见应难，信音悭端的是信音悭。骂子','无名氏','元','元曲','yuanqu','','[]','骂谁行骂，还子还几时还，捱子捱捱不得恹恹红日晚。',24,'元曲/yuanqu.json','["骂谁行骂，还子还几时还，捱子捱捱不得恹恹红日晚。"]'),
('yuanqu-10666','十二月・莺慵燕懒，凤只鸾单。似这般云酸雨涩，端的是蝶乱蜂烦。霎时','无名氏','元','元曲','yuanqu','','[]','间香消篆冷，捱不过夜静更阑。',14,'元曲/yuanqu.json','["间香消篆冷，捱不过夜静更阑。"]'),
('yuanqu-10667','耍孩儿・金针绣作皆疏懒，方胜同心倦挽。回纹织锦断肠诗，无青鸾寄不','无名氏','元','元曲','yuanqu','','[]','到云间。',36,'元曲/yuanqu.json','["到云间。", "屏闲孔雀金翎断，衾剩鸳鸯翠羽寒。", "倚枕春魂散，梦中唤觉，万水千山。"]'),
('yuanqu-10668','尾声・离恨多，离恨多，相思罕，相思罕。乍相逢使不得娇妆扮，只除是','无名氏','元','元曲','yuanqu','','[]','锦被里朦胧再合眼。',9,'元曲/yuanqu.json','["锦被里朦胧再合眼。"]'),
('yuanqu-10669','般涉调・耍孩儿拘刷行院','无名氏','元','元曲','yuanqu','','[]','昨朝有客来相访，是几个知音故友。',65,'元曲/yuanqu.json','["昨朝有客来相访，是几个知音故友。", "道我数载不疏狂，特地来邀请闲游。", "自开宝匣抬乌帽，遂掇雕鞍辔紫骝。", "联辔儿相驰骤，人人济楚，个个风流。"]'),
('yuanqu-10670','十三煞・穿长街蓦短衢，上歌台入酒楼。忙呼乐探差祗候：众人暇日邀官','无名氏','元','元曲','yuanqu','','[]','舍，与你几贯青蚨唤粉头。',31,'元曲/yuanqu.json','["舍，与你几贯青蚨唤粉头。", "休辞生受，请个有声名旦色，迭标垛娇羞。"]'),
('yuanqu-10671','十一・待呼小卿不姓苏，待唤月仙不姓周。你桂英性子实村纣，施施所事','无名氏','元','元曲','yuanqu','','[]','皆无礼，似盼盼多应也姓刘。',30,'元曲/yuanqu.json','["皆无礼，似盼盼多应也姓刘。", "满饮阑门酒，似线牵傀儡，粉做骷髅。"]'),
('yuanqu-10672','九・有玉箫不会品，有银筝不会ㄐ，查沙着一对生姜手。眼М间准备钳肴','无名氏','元','元曲','yuanqu','','[]','馔，酩子里安排搠按酒。',31,'元曲/yuanqu.json','["馔，酩子里安排搠按酒。", "立不住腔腔嗽，新清来的板齿，恰刷起黄头。"]'),
('yuanqu-10673','八・〔青哥儿〕怎地弹，〔白鹤子〕怎地讴，燥躯老第四如何纽。恣胸怀','无名氏','元','元曲','yuanqu','','[]','休想我一缕儿顽涎退，白珠玉别得他浑身拙汗流。',45,'元曲/yuanqu.json','["休想我一缕儿顽涎退，白珠玉别得他浑身拙汗流。", "倒敢是十分丑。", "匾扑沙拐孤撇尺，光笃鹿瓠子髑髅。"]'),
('yuanqu-10674','四・忍不得腹内饥，揩不得脸上羞，休猜做饱谙世事慵开口。俺座间虽无','无名氏','元','元曲','yuanqu','','[]','百宝妆腰带，您席上怎能够真珠络臂鞲。',39,'元曲/yuanqu.json','["百宝妆腰带，您席上怎能够真珠络臂鞲。", "闻不得腥臊臭，半年两番小产，一日九遍昏兜。"]'),
('yuanqu-10675','三・〔江儿里水〕唱得生，〔小姑儿〕听记得熟。入席来把不到三巡酒，','无名氏','元','元曲','yuanqu','','[]','索怯薛侧脚安排趄，要赏钱连声不住口。',39,'元曲/yuanqu.json','["索怯薛侧脚安排趄，要赏钱连声不住口。", "没一盏茶时候，道有教坊散乐，拘刷烟月班头。"]'),
('yuanqu-10676','二・提控有小朱，权司是老刘，更有那些随从村禽兽。唬得烟迷了苏小小','无名氏','元','元曲','yuanqu','','[]','夜月莺花市，惊得云锁了许盼盼春风燕子楼。',43,'元曲/yuanqu.json','["夜月莺花市，惊得云锁了许盼盼春风燕子楼。", "慌煞俺曹娥秀，抬乐器眩了眼脑，觑幅子叫破咽候。"]'),
('yuanqu-10677','一・上瓦里封了门，下瓦里觅了舟。他道眼睁睁见死不救。比怕阎罗王罪','无名氏','元','元曲','yuanqu','','[]','恶多些人气，似征李志甫巡军少个犯由。',39,'元曲/yuanqu.json','["恶多些人气，似征李志甫巡军少个犯由。", "恰便似遭遗漏，小王抗着毡缕，小李不放泥头。"]'),
('yuanqu-10678','尾・老卜儿藉不得板一地走，狠撅丁夹着锣则顾得走。也不是沿村串疃钻','无名氏','元','元曲','yuanqu','','[]','山兽，则是喑气吞声丧家狗。',13,'元曲/yuanqu.json','["山兽，则是喑气吞声丧家狗。"]'),
('yuanqu-10679','逍遥乐・我从来眼硬，不由人对景伤情，一哭一个放声。想当初又不曾约','无名氏','元','元曲','yuanqu','','[]','定离情，常言道：乐极悲生。',48,'元曲/yuanqu.json','["定离情，常言道：乐极悲生。", "伴吹箫玉人不见影，洞房中冷冷清清。", "空闲了罗帏锦帐，绣枕鸳衾，翠榻银屏。"]'),
('yuanqu-10680','金菊香・虚飘飘幽梦盼着难成，静悄悄孤眠睡着又醒，瘦怯怯身躯温着又','无名氏','元','元曲','yuanqu','','[]','夜迢迢捱不到天明，料应来司天台上多打二三更。',22,'元曲/yuanqu.json','["夜迢迢捱不到天明，料应来司天台上多打二三更。"]'),
('yuanqu-10681','梧叶儿・问明月浑无语，唤梅花不肯应，长叹倚空庭。何处品青鸾管？谁','无名氏','元','元曲','yuanqu','','[]','家奏彩凤笙？都吹出断肠声，不管离人怕听。',20,'元曲/yuanqu.json','["家奏彩凤笙？都吹出断肠声，不管离人怕听。"]'),
('yuanqu-10682','醋葫芦・几番上危楼将曲槛凭，不承望愁先在楼上等。望不见娇滴滴天上','无名氏','元','元曲','yuanqu','','[]','董双成，泻长空苍苍烟树暝。',24,'元曲/yuanqu.json','["董双成，泻长空苍苍烟树暝。", "残霞掩映，江上数峰青。"]'),
('yuanqu-10683','幺・论文学不什么明，论江湖不甚么省。则我这粗贱才堪配玉聘婷，我将','无名氏','元','元曲','yuanqu','','[]','这女娘行恩情在等秤上称。',32,'元曲/yuanqu.json','["这女娘行恩情在等秤上称。", "称了时和咱比并，十分情重全无有半星儿轻。"]'),
('yuanqu-10684','后庭花・丽春园曾惯经，教坊司也惯行。人都说金钗客无缘分，我只道玉','无名氏','元','元曲','yuanqu','','[]','天仙有眼睛。',71,'元曲/yuanqu.json','["天仙有眼睛。", "他将我好看承，我将他心窝里相敬。", "扯嗉儿不手生，跄跪儿不腿疼。", "常将笑脸儿迎，勤把热气儿腾。", "活观音额上顶，夜明珠掌上擎，夜明珠掌上擎。"]'),
('yuanqu-10685','青歌儿・呀，他是我今生、今生性命，那世、那世魂灵。一去教人不快情。','无名氏','元','元曲','yuanqu','','[]','遮莫有锦阵花营，酒友诗朋，象板银筝，歌舞吹笙。',39,'元曲/yuanqu.json','["遮莫有锦阵花营，酒友诗朋，象板银筝，歌舞吹笙。", "花朵人儿将玉杯擎，我只是无情兴。"]'),
('yuanqu-10686','柳叶儿・呀，我这里担着寂寞，不知你在那搭儿里泪眼盈盈，离恨天高越','无名氏','元','元曲','yuanqu','','[]','显的人孤另。',27,'元曲/yuanqu.json','["显的人孤另。", "则我这相思病。", "诉与天听，连天也瘦的来伶仃。"]'),
('yuanqu-10687','尾声・他忧时为我忧，我病时因他病。我为了他害杀了有甚么不相应。有','无名氏','元','元曲','yuanqu','','[]','一日再团圆，画堂春自生。',115,'元曲/yuanqu.json','["一日再团圆，画堂春自生。", "紧紧的将他搂定，我将这满怀愁尽向他耳朵儿里倾。", "喜相逢并头花下友，天配偶两娇羞。", "一对儿冤家合欠，还今生谐老鸳俦。", "意相投似漆如胶，契相合万种绸缪。", "画堂前满斟香糯酒，喜孜孜共饮金瓯。", "则吃的天边明月转，楼上换更筹。"]'),
('yuanqu-10688','字字锦南・瑶阶羡晚游，闲行携素手。金莲款款移，细柳腰肢瘦。看花楼','无名氏','元','元曲','yuanqu','','[]','抚景偏优，笑吟吟转过见新月一钩。',71,'元曲/yuanqu.json','["抚景偏优，笑吟吟转过见新月一钩。", "休辜负好景，香醪再酬。", "低低悄语私情授，向兰房锦鸾早俦。", "慢松丁香细钮，香散绣帏。", "娇滴滴温柔玉体，非宿世怎生消受。"]'),
('yuanqu-10689','醋葫芦北・温柔谁并肩，风流为世首。弹弦品竹最精熟，吟诗作赋时下有。','无名氏','元','元曲','yuanqu','','[]','一团儿玲珑剔透，天生的秀气，他两个总全周。',21,'元曲/yuanqu.json','["一团儿玲珑剔透，天生的秀气，他两个总全周。"]'),
('yuanqu-10690','醋葫芦北・姊妹每一个所事全，一个件件周。好似那二乔镜像影儿留，占','无名氏','元','元曲','yuanqu','','[]','梨园委实无对手。',29,'元曲/yuanqu.json','["梨园委实无对手。", "常想着欢娱时候，我和他契相合情相好意相投。"]'),
('yuanqu-10691','皂罗袍南・美满恩深情厚，愿百年谐老，共守白头。相逢谁似恁风流，终','无名氏','元','元曲','yuanqu','','[]','朝弦管笙歌奏。',34,'元曲/yuanqu.json','["朝弦管笙歌奏。", "池亭东畔，湖山西首，金怀慢举佳肴广，有蓬莱仙境无如右。"]'),
('yuanqu-10692','逍遥乐・非是把盟言辜负，多应是身事牵萦，致令的佳期间阻。抛撇下红','无名氏','元','元曲','yuanqu','','[]','粉娇姝，自别来消息全无。',47,'元曲/yuanqu.json','["粉娇姝，自别来消息全无。", "怎能够萧娘一纸书，多应是水底沉鱼。", "好教我难捱白昼，最怕黄昏，几遍嗟吁。"]'),
('yuanqu-10693','金菊香・无奈这逼人富贵太拘束，拈脂光阴忒迅速，一树红芳替他难做主。','无名氏','元','元曲','yuanqu','','[]','等闲间减翠消绿，却教我感时抚景怎支吾。',19,'元曲/yuanqu.json','["等闲间减翠消绿，却教我感时抚景怎支吾。"]'),
('yuanqu-10694','幺・我也曾絮叨叨讲口舌，实丕丕倾肺腑。下了些调风弄月死工夫，想章','无名氏','元','元曲','yuanqu','','[]','台是一条直路途。',26,'元曲/yuanqu.json','["台是一条直路途。", "被谁拦住？莫不是姻缘簿上把我姓名除。"]'),
('yuanqu-10695','幺・我和他受孤凄有业缘，永团圆无分福。断弦破镜怎接续？枉自求神与','无名氏','元','元曲','yuanqu','','[]','问卜。',19,'元曲/yuanqu.json','["问卜。", "莫逃天数，料孤辰寡宿单照我身躯。"]'),
('yuanqu-10696','幺・我似那鸳鸯怕自飞，我似那鸾鹤该并舞。由来天性怎生拂。我和他久','无名氏','元','元曲','yuanqu','','[]','交欢乍知离别苦。',22,'元曲/yuanqu.json','["交欢乍知离别苦。", "百无是处，眼睁睁伶俐变糊突。"]'),
('yuanqu-10697','梧叶儿・相思病何时退？睡魔神镇日侮，害的我忒荼毒。刁骚了双蓬鬓，','无名氏','元','元曲','yuanqu','','[]','扑簌的两泪珠，缑山岭恁崎岖，隔断了吹箫伴侣。',22,'元曲/yuanqu.json','["扑簌的两泪珠，缑山岭恁崎岖，隔断了吹箫伴侣。"]'),
('yuanqu-10698','后庭花・这些时捻霜毫懒写摸，理冰弦乖律吕。倦开眼亲黄卷。怎舒情倒','无名氏','元','元曲','yuanqu','','[]','玉壶。',62,'元曲/yuanqu.json','["玉壶。", "天气更萧肃，你便是铁石人也耽不去。", "妒黄花金色铺，泣丹枫血泪枯。", "望空江练一幅，对遥山青几矗。", "别离怀容易触，别离人生怕睹。"]'),
('yuanqu-10699','青哥儿・呀，自别了风流风流人物，终须是有日有日欢娱，对付我心肠谅','无名氏','元','元曲','yuanqu','','[]','不殊。',40,'元曲/yuanqu.json','["不殊。", "且看他俊俏规模，香软肌肤，巧妙妆束，耍笑喧呼。", "行行步步紧随逐，谩把流年度。"]'),
('yuanqu-10700','浪来里煞・杜少陵秋兴诗，欧阳子秋声赋。都对不着我的题目，大都来一','无名氏','元','元曲','yuanqu','','[]','见他万事足。',125,'元曲/yuanqu.json','["见他万事足。", "别无甚忧虑，成就了碧桃花下凤鸾雏。", "佳遇记当年宴青楼初见影，兜的就飞去了俏魂灵。", "只疑是玉天仙空中谪降，又猜做美嫦娥月里相迎。", "猛可里翠屏帏密转秋波，没揣的绿纱窗暗恼春情。", "感承他会佳期预先花下等，成就了片霎儿前程。", "也不让人间秦弄玉，天上许飞琼。"]'),
('yuanqu-10701','金菊香・往常时追欢谢馆可曾经，今日个买笑章台惯索行。几番家静守幽','无名氏','元','元曲','yuanqu','','[]','居深自省，天与聘婷，刚道喜又还惊。',17,'元曲/yuanqu.json','["居深自省，天与聘婷，刚道喜又还惊。"]'),
('yuanqu-10702','醋葫芦・喜呵，好姻缘成的未深；惊呵，歹离别来的最灵。都只为阻蓝桥','无名氏','元','元曲','yuanqu','','[]','如间阻百重城，咫尺间地北天南分凤颈。',39,'元曲/yuanqu.json','["如间阻百重城，咫尺间地北天南分凤颈。", "不能够相偎相并，把一场好恩情分付在短长亭。"]'),
('yuanqu-10703','幺・我为他枕边厢洒了泪痕，他为我被窝中劳了些梦境。谁承望胶漆的恩','无名氏','元','元曲','yuanqu','','[]','爱半途坑，几回家望断孤鸿楼外影。',37,'元曲/yuanqu.json','["爱半途坑，几回家望断孤鸿楼外影。", "都只是天高云淡，闪的个美幽欢生做了断肠声。"]'),
('yuanqu-10704','幺・我将他并不曾冷气呵，他见我常时把热脸儿迎。他也曾画堂春排宴请','无名氏','元','元曲','yuanqu','','[]','高朋，听了些一曲新腔音调整。',33,'元曲/yuanqu.json','["高朋，听了些一曲新腔音调整。", "助了些诗人高兴，俺也曾厌厌夜饮到更深。"]'),
('yuanqu-10705','幺・想着他和明月品着玉萧，唱阳春奏着锦筝。想着他纤纤素手进瑶觥，','无名氏','元','元曲','yuanqu','','[]','他也曾醉舞霓裳娇态逞。',31,'元曲/yuanqu.json','["他也曾醉舞霓裳娇态逞。", "出落的十分端正，他比那海棠花睡起更轻盈。"]'),
('yuanqu-10706','幺・他也曾斗娇姿花外游，他也曾叙幽情月底行。他和我唱新词曾把字儿','无名氏','元','元曲','yuanqu','','[]','评，我与他立尽花梢明月影。',32,'元曲/yuanqu.json','["评，我与他立尽花梢明月影。", "遂了这风流佳庆，曾说的楼头北斗柄儿横。"]'),
('yuanqu-10707','逍遥乐・自从钗分金凤，止不过数日程途，阻隔着云山万重。走红尘萍梗','无名氏','元','元曲','yuanqu','','[]','飘蓬，叹青春湖海西东。',43,'元曲/yuanqu.json','["飘蓬，叹青春湖海西东。", "几番家恼人愁越重，一声声风送帘栊。", "猿啼峻岭，雁过南楼，鹤唳高松。"]'),
('yuanqu-10708','金菊香・瑶琴闲挂锦囊中，宝剑慵弹锦袋中，翠衾倦铺锦帐空。砚匣尘蒙，','无名氏','元','元曲','yuanqu','','[]','都是一般潇洒月明中。',10,'元曲/yuanqu.json','["都是一般潇洒月明中。"]'),
('yuanqu-10709','梧叶儿・愁填满东洋海，闷弥高太华峰，愁和闷锁眉丛。这些时笔砚无心','无名氏','元','元曲','yuanqu','','[]','近，经史不待攻。',23,'元曲/yuanqu.json','["近，经史不待攻。", "我这里怨天公，几时得凄凉卷终。"]'),
('yuanqu-10710','后庭花・想则想蹴金莲三寸弓，启樱桃半点红。想则想整酥体一团玉，露','无名氏','元','元曲','yuanqu','','[]','春纤十指葱。',57,'元曲/yuanqu.json','["春纤十指葱。", "透酥胸，麝兰香送。", "傍妆台整玉容，列华筵捧玉钟。", "按红牙思转浓，拔银筝兴不穷。", "望瑶池云乱封，盼青鸾信不通。"]'),
('yuanqu-10711','柳叶儿・呀，想着俺多娇情重，更那堪剔透玲珑。路迢迢雾锁桃源洞，团','无名氏','元','元曲','yuanqu','','[]','圆梦总成空，楚阳台云雨无踪。',14,'元曲/yuanqu.json','["圆梦总成空，楚阳台云雨无踪。"]'),
('yuanqu-10712','尾・越思量越惨凄，转伤悲转疼痛，几宵魂梦与伊同。往常时醉归来画堂','无名氏','元','元曲','yuanqu','','[]','红袖拥，到如今有谁人陪奉，都做了断肠词权写付云鸿。',102,'元曲/yuanqu.json','["红袖拥，到如今有谁人陪奉，都做了断肠词权写付云鸿。", "夜深沉画堂门半掩，正明月转雕檐。", "响珊珊竹声幽院，颤巍巍花影重檐。", "酒才醒幽思沉沉，漏初分凉夜厌厌。", "早秋天万般愁闷添，更凄凉风景相兼。", "旧愁深肺腑，新恨上眉尖。"]'),
('yuanqu-10713','逍遥乐・玉容娇艳，记当时柳画宫眉，花明笑靥。尽欢娱无甚拘钳，似于','无名氏','元','元曲','yuanqu','','[]','飞燕燕鹣鹣。',37,'元曲/yuanqu.json','["飞燕燕鹣鹣。", "微利驱人成弃闪，走天涯旅邸顿腌。", "肠如线结，心如锥剜，肉似刀签。"]'),
('yuanqu-10714','金菊香・早鸦灵鹊不须占，蓍草金钱徒自检，灯花喜蛛都是诌。无准信龟','无名氏','元','元曲','yuanqu','','[]','卦神签，更那堪半衾幽梦睡初タ。',15,'元曲/yuanqu.json','["卦神签，更那堪半衾幽梦睡初タ。"]'),
('yuanqu-10715','幺・凤凰翅活不剌手中ㄎ，鸳鸯弹圆滴滴石上掂，翡翠羽恶支沙泥内染。','无名氏','元','元曲','yuanqu','','[]','连理枝雪虐霜严，好花开处雨纤纤。',16,'元曲/yuanqu.json','["连理枝雪虐霜严，好花开处雨纤纤。"]'),
('yuanqu-10716','醋葫芦・彩云深白雁稀，碧波寒锦鲜潜。素书银字不曾瞻，隔云山万重天','无名氏','元','元曲','yuanqu','','[]','路险。',22,'元曲/yuanqu.json','["路险。", "旧恩情不堪追念，都做了镜中花影水中盐。"]'),
('yuanqu-10717','幺・择兔毫斑管拈，洒鸾笺香墨染。写平安端肃更谦谦，诉离怀半缄情越','无名氏','元','元曲','yuanqu','','[]','从别后绝无瑕玷，封皮儿上两行情泪带愁粘。',20,'元曲/yuanqu.json','["从别后绝无瑕玷，封皮儿上两行情泪带愁粘。"]'),
('yuanqu-10718','越调・斗鹌鹑元宵','无名氏','元','元曲','yuanqu','','[]','圣主宽仁，尧民尽喜。',56,'元曲/yuanqu.json','["圣主宽仁，尧民尽喜。", "一统华夷，诸邦进礼。", "雨顺风调，时丰岁丽。", "元夜值，风景奇。", "闹穰穰的迓鼓喧天，明晃晃的金莲遍地。"]'),
('yuanqu-10719','紫花儿序・香馥馥绮罗还往，密匝匝车马喧阗，光灼灼灯月交辉。满街上','无名氏','元','元曲','yuanqu','','[]','王孙公子，相携着越女吴姬。',45,'元曲/yuanqu.json','["王孙公子，相携着越女吴姬。", "偏宜，凤烛高张照珠履。", "果然豪贵，只疑是洞府神仙，闲游在阆苑瑶池。"]'),
('yuanqu-10720','小桃花・归来梅影小窗移，兰麝香风细。翠袖琼簪两行立，捧金杯，绛绡','无名氏','元','元曲','yuanqu','','[]','楼上笙歌沸。',23,'元曲/yuanqu.json','["楼上笙歌沸。", "冰轮表里，通宵不寐，是爱月夜眠迟。"]'),
('yuanqu-10721','金蕉叶・拚沉醉频斟绿蚁，恣赏玩朱帘挂起。歌舞动欢声笑喜，一任铜壶','无名氏','元','元曲','yuanqu','','[]','漏滴。',3,'元曲/yuanqu.json','["漏滴。"]'),
('yuanqu-10722','尾・须将酩酊酬佳致，乐意开怀庆喜。但愿岁岁赏元宵，则这的是人生落','无名氏','元','元曲','yuanqu','','[]','得的。',51,'元曲/yuanqu.json','["得的。", "绿柳凋残，黄花放彻。", "塞雁声悲，寒蛩韵切。", "旧恨千般，新愁万叠。", "正美满，忍间别。", "雨歇云收，花残月缺。"]'),
('yuanqu-10723','紫花儿序・摘楞的瑶琴弦断，不通的井坠银瓶，吉丁的碧玉簪折。音书难','无名氏','元','元曲','yuanqu','','[]','寄，去路遥赊。',34,'元曲/yuanqu.json','["寄，去路遥赊。", "伤嗟，目断云山千万叠。", "最苦是离别，鸳被空舒，凤枕虚设。"]'),
('yuanqu-10724','金蕉叶・那的是情牵恨惹，那的是肠荒腹热。怕的是纱窗外风飘败叶，又','无名氏','元','元曲','yuanqu','','[]','听的铁马儿丁当韵切。',10,'元曲/yuanqu.json','["听的铁马儿丁当韵切。"]'),
('yuanqu-10725','调笑令・把眉峰暗结，最苦是离别，不烦恼除非心似铁。冷清清捱落西楼','无名氏','元','元曲','yuanqu','','[]','月，又听得戍楼上画角呜噎。',32,'元曲/yuanqu.json','["月，又听得戍楼上画角呜噎。", "奏《梅花》数声砧韵切，业心肠越不宁贴。"]'),
('yuanqu-10726','秃厮儿・正欢悦谁知间别，才美满又早离别。俺两个云期雨约难弃舍，似','无名氏','元','元曲','yuanqu','','[]','团圆一轮月，被云遮。',10,'元曲/yuanqu.json','["团圆一轮月，被云遮。"]'),
('yuanqu-10727','圣药王・好教我愁万结，恨万叠，满怀愁闷对谁说。成间别，时运拙，气','无名氏','元','元曲','yuanqu','','[]','长吁多似篆烟斜，和绛蜡也啼血。',15,'元曲/yuanqu.json','["长吁多似篆烟斜，和绛蜡也啼血。"]'),
('yuanqu-10728','鬼三台・也是我前生业，今世里填还彻，一寸愁肠千万结。想啼痕一点点','无名氏','元','元曲','yuanqu','','[]','尽成血，越教人哽噎。',45,'元曲/yuanqu.json','["尽成血，越教人哽噎。", "本待要宁宁帖帖刚睡些，怎禁那啾啾唧唧蛩韵切。", "觉来时宝鼎烟消，铜壶漏绝。"]'),
('yuanqu-10729','紫花儿序・惊好梦几声儿寒雁，伴人愁的一点孤灯，照离情半窗残月。临','无名氏','元','元曲','yuanqu','','[]','歧执手，不忍分别。',44,'元曲/yuanqu.json','["歧执手，不忍分别。", "只待稳步蟾宫将仙桂折，到如今暮秋时节。", "他只待金榜名标，那里问玉箫声绝。"]'),
('yuanqu-10730','尾・受凄惶甚识分明夜，把捱过的凄凉记者。来时节一句句向枕头儿上言，','无名氏','元','元曲','yuanqu','','[]','一星星向被窝儿里说。',65,'元曲/yuanqu.json','["一星星向被窝儿里说。", "半世飘蓬，闲茶浪洒。", "十载追陪，狂朋怪友。", "倚翠偎红，眠花卧柳。", "怪胆儿聪，耍性儿柔。", "成会了心厮爱夫妻，情厮当配偶。"]'),
('yuanqu-10731','紫花儿序・受用春内谢馆，晓日章台，夜月秦楼。向红裙中插手，锦被里','无名氏','元','元曲','yuanqu','','[]','舒头。',29,'元曲/yuanqu.json','["舒头。", "风流，不许傍人下钓钩。", "燕侣莺俦，百匹酬歌，红锦缠头。"]'),
('yuanqu-10732','金蕉叶・寨儿里相知是有，一见咱望风举手。若论着点砌排科惯熟，敢教','无名氏','元','元曲','yuanqu','','[]','那罢剪嘴姨夫闭口。',9,'元曲/yuanqu.json','["那罢剪嘴姨夫闭口。"]'),
('yuanqu-10733','调笑令・声名儿岁久，急难收。则恐怕扶侍冤家不到头，风月脚到处须成','无名氏','元','元曲','yuanqu','','[]','誓不曾落人机彀，搬的他燃香剪发百事有。',29,'元曲/yuanqu.json','["誓不曾落人机彀，搬的他燃香剪发百事有。", "虚心冷气，使尽刚柔。"]'),
('yuanqu-10734','圣药王・春事休，夏当游，向芰荷香里泛兰舟。到中秋，月色幽，醉醺醺','无名氏','元','元曲','yuanqu','','[]','无日不登楼，兀剌抵多少风雨替花愁。',17,'元曲/yuanqu.json','["无日不登楼，兀剌抵多少风雨替花愁。"]'),
('yuanqu-10735','尾・花阴柳影，霎时驰骤，急回首三旬左右。罢却爱月惜花心，闲着题诗','无名氏','元','元曲','yuanqu','','[]','画眉手。',56,'元曲/yuanqu.json','["画眉手。", "（媚）（媚）姿姿，淹淹润润。", "袅袅婷婷，风风韵韵。", "脸衬朝霞，指如嫩笋。", "一搦腰，六幅裙，万种妖娆，千般可人。"]'),
('yuanqu-10736','紫花儿序・曲弯弯蛾眉扫黛，慢松松凤髻高盘，高耸耸蝉鬓堆云。一团儿','无名氏','元','元曲','yuanqu','','[]','旖旎，百倍儿精神。',37,'元曲/yuanqu.json','["旖旎，百倍儿精神。", "超群，越女吴姬怎生衬。", "席上殷勤，百媚庞儿，端的一笑风生。"]'),
('yuanqu-10737','秃厮儿・瘦怯怯金莲窄稳，娇滴滴皓齿朱唇，肌如美玉无玷损。但见了，','无名氏','元','元曲','yuanqu','','[]','总消魂，绝伦。',7,'元曲/yuanqu.json','["总消魂，绝伦。"]'),
('yuanqu-10738','圣药王・酒半醺，更漏分，画堂银烛照黄昏。枕上恩，被底亲，丁香笑吐','无名氏','元','元曲','yuanqu','','[]','兰麝喷，灯下看佳人。',10,'元曲/yuanqu.json','["兰麝喷，灯下看佳人。"]'),
('yuanqu-10739','尾・好姻缘休到别离恨，只恐怕两下里魂牵梦引。我罗衫衤肯儿宽，你唐','无名氏','元','元曲','yuanqu','','[]','裙带儿尽。',53,'元曲/yuanqu.json','["裙带儿尽。", "雪艳霜姿，香肌玉软。", "杏脸红娇，桃腮粉浅。", "金凤斜簪，云鬟半偏。", "插玉梳，贴翠钿。", "舞态轻盈，歌喉宛转。"]'),
('yuanqu-10740','紫花儿序・他有苏卿般才貌，我学双渐真诚，望博个美满姻缘。俳优体样，','无名氏','元','元曲','yuanqu','','[]','乐府梨园。',32,'元曲/yuanqu.json','["乐府梨园。", "天然，不若如桃源洞里仙。", "可爱堪怜、一搦腰肢，半折金莲。"]'),
('yuanqu-10741','小桃红・初出兰堂立樽前，似月里嫦娥现，一撮精神胜飞燕。正当年，柳','无名氏','元','元曲','yuanqu','','[]','眉星眼芙蓉面。',23,'元曲/yuanqu.json','["眉星眼芙蓉面。", "绛衣缥缈，麝兰琼树，花里遇神仙。"]'),
('yuanqu-10742','天净沙・初相逢恨惹情牵，间深里都受熬煎，各办着心真意坚。有时得便，','无名氏','元','元曲','yuanqu','','[]','赴佳期月底星前。',8,'元曲/yuanqu.json','["赴佳期月底星前。"]'),
('yuanqu-10743','尾・狠毒娘间阻得难相见，统镘的姨夫恋缠。我为甚着探脚儿勤，只恐怕','无名氏','元','元曲','yuanqu','','[]','离别路儿远。',54,'元曲/yuanqu.json','["离别路儿远。", "雨意云情，十朝五朝。", "霜艳天姿，千娇万娇。", "凤髻浓梳，蛾眉淡扫。", "樱桃口，杨柳腰。", "玉笋纤纤，金莲小小。"]'),
('yuanqu-10744','紫花儿序・歌骊珠一串，舞端雪千回，无福也难消。超群旖旎，出格妖娆。','无名氏','元','元曲','yuanqu','','[]','风流，一笑千金价不高。',30,'元曲/yuanqu.json','["风流，一笑千金价不高。", "世间绝妙，特意厚情深，引得人梦断魂劳。"]'),
('yuanqu-10745','秃厮儿・儿中眉尖眼角，寨儿中口强心乔，谢琼姬不嫌王子高。同跨凤，','无名氏','元','元曲','yuanqu','','[]','宴蟠桃，吹箫。',7,'元曲/yuanqu.json','["宴蟠桃，吹箫。"]'),
('yuanqu-10746','小桃红・倚阑无语忆多才，往事今何在，玉体厌厌为谁害，瘦形骸，今春','无名氏','元','元曲','yuanqu','','[]','更比前春赛。',22,'元曲/yuanqu.json','["更比前春赛。", "雕阑玉砌，绿窗朱户，深院锁苍苔。"]'),
('yuanqu-10747','醉扶归・松却香罗带，慵整短金钗，无语无言闷答孩。不厌倦衫儿窄，几','无名氏','元','元曲','yuanqu','','[]','度将龟儿卦买，何日佳期再。',13,'元曲/yuanqu.json','["度将龟儿卦买，何日佳期再。"]'),
('yuanqu-10748','天净沙・也是咱运拙时乖，致令得雨杳云埋，侧脚里相知不该。胡喧乱讲，','无名氏','元','元曲','yuanqu','','[]','纸糊锹怎撅得倒阳台。',10,'元曲/yuanqu.json','["纸糊锹怎撅得倒阳台。"]'),
('yuanqu-10749','尾・把一片偷香窃玉心宁耐，喑气吞声慢捱。怕甚风月闷愁乡，烟波是非','无名氏','元','元曲','yuanqu','','[]','妓好睡莫不是陈抟的姨姨，庄周的妹妹，宰予的家属，谢安的亲戚。',64,'元曲/yuanqu.json','["妓好睡莫不是陈抟的姨姨，庄周的妹妹，宰予的家属，谢安的亲戚。", "华胥梦里姻缘，邯郸道上配偶。", "两件儿，试问你，可甚爱月迟眠，惜花早起。"]'),
('yuanqu-10750','紫花儿・西厢底莺莺立睡，茶船上小卿着昏，东墙下秀英如痴。真乃是弃','无名氏','元','元曲','yuanqu','','[]','生就死，便休想废寝忘食。',40,'元曲/yuanqu.json','["生就死，便休想废寝忘食。", "休题，除睡人间总不知。", "正是困人天气，啼杀流莺，叫死晨鸡。"]'),
('yuanqu-10751','幺・推着倒鸾交凤友，倩人扶燕侣莺俦，合着眼蝶使蜂媒。绣衾未展，玉','无名氏','元','元曲','yuanqu','','[]','山先颓。',44,'元曲/yuanqu.json','["山先颓。", "其实，倒枕着床是你记得的。", "胡突了一世，恰便似楚阳台半死的梅香，兰昌宫殉葬的奴婢。"]'),
('yuanqu-10752','小桃红・莫不是离魂倩女醉杨妃，是个有觉的平康妓。难道娇娥不出气，','无名氏','元','元曲','yuanqu','','[]','懵憧的最怜伊。',34,'元曲/yuanqu.json','["懵憧的最怜伊。", "颠鸾倒凤先及第，直压的珊瑚枕低。", "黄金钏碎，平地一声雷。"]'),
('yuanqu-10753','圣药王・子弟每，做伴的，安排着好梦做夫妻。你也休问谁，我也不答你。','无名氏','元','元曲','yuanqu','','[]','陷人坑上被儿里，直挺着块望夫石。',16,'元曲/yuanqu.json','["陷人坑上被儿里，直挺着块望夫石。"]'),
('yuanqu-10754','尾・对苍天曾说牙疼誓，直睡到红日三竿未起。若要战退睡魔王，差三千','无名氏','元','元曲','yuanqu','','[]','个追魂大力鬼。',67,'元曲/yuanqu.json','["个追魂大力鬼。", "离恨送玉傅香，撩蜂拨蝎。", "病枕愁衾，寻毒觅螫。", "掷闷果的心劳，画颦眉的手拙。", "恨岳高，泪海竭。", "难凭信鹊验龟灵。", "无定准鱼封雁帖。"]'),
('yuanqu-10755','紫花儿序・莫不是金华字减消了官诰，芙容翠低小了云冠，鲛绡盖乍窄了','无名氏','元','元曲','yuanqu','','[]','香车？闷弓儿常拽，愁窖儿频掘。',52,'元曲/yuanqu.json','["香车？闷弓儿常拽，愁窖儿频掘。", "伤嗟，一纳头相思害不彻。", "赤紧的俏心儿先热，无倒断暮雨朝云，无拘束粉祟胭邪。"]'),
('yuanqu-10756','小桃红・锦笺和泪寄离别，好事成抛撇。恨杀梅香性偏劣，闭喉舌，今翻','无名氏','元','元曲','yuanqu','','[]','瘦损罗裙褶。',30,'元曲/yuanqu.json','["瘦损罗裙褶。", "他把那游蜂儿蜜劫，粉蝶儿香卸，生撅的风月担儿折。"]'),
