('yuanqu-10807','胡十八・不下怀，自惊怪，悲间阻，想和谐，巫山依旧楚云埋。雁书又乖，','无名氏','元','元曲','yuanqu','','[]','鱼笺倦裁，一身无限愁，十日九番害。',17,'元曲/yuanqu.json','["鱼笺倦裁，一身无限愁，十日九番害。"]'),
('yuanqu-10808','拨不断・细裁画，命合该，姻缘顷刻多成败。鬼病千般强打捱，凄凉万种','无名氏','元','元曲','yuanqu','','[]','难担载，几曾得片时轻快。',12,'元曲/yuanqu.json','["难担载，几曾得片时轻快。"]'),
('yuanqu-10809','离亭宴煞・楚阳台步步荆榛隘，担阁下两厢情色。相思卷何年结束，糊突','无名氏','元','元曲','yuanqu','','[]','谜甚日明白。',37,'元曲/yuanqu.json','["谜甚日明白。", "传示你权宁耐，切莫把鲰生见责。", "是送暖的意儿虚，非偷香的性儿歹。"]'),
('yuanqu-10811','天仙子・棘里兔，难配扑天鹄。馋眼痴心，看之不足。猛可里见姨夫，败','无名氏','元','元曲','yuanqu','','[]','坏风俗。',17,'元曲/yuanqu.json','["坏风俗。", "好花怎教他做主，不辨贤愚。"]'),
('yuanqu-10812','离亭宴煞・锦笺空写多情句，枉可惜口谈珠玉。假做苏卿伴侣，被冯魁已','无名氏','元','元曲','yuanqu','','[]','早图谋。',81,'元曲/yuanqu.json','["早图谋。", "使尽心，才得悟，则不如将取孛兰便数。", "咱看上脸儿甜，止不过钞儿苦。", "楚阳台远暮云遮，烟水恨连叠。", "沈郎多病腰肢怯，喜相逢可惯离别。", "悄悄鸳帏惭冷，薄怯怯绣衾空设。"]'),
('yuanqu-10814','搅筝琶・空摧扌颠，直恁信音绝。欲寄相思，凭谁人话说。除纸笔，带喉','无名氏','元','元曲','yuanqu','','[]','舌，短叹长嗟。',21,'元曲/yuanqu.json','["舌，短叹长嗟。", "不流泪料来心似铁，寸肠千结。"]'),
('yuanqu-10815','离亭宴煞・难睚漏水如年夜，正值着暮秋时节。坐不稳自敝自焦，睡不着','无名氏','元','元曲','yuanqu','','[]','不宁不帖。',81,'元曲/yuanqu.json','["不宁不帖。", "寒雁哀，寒蛩切，忽聚散阶前落叶。", "却是那透户一帘风，穿窗半弯月。", "夜阑深院暮寒加，愁听漏声多。", "银台画烛烧残蜡，伴离人心绪杂咱。", "有分红愁绿惨，无心赏白洒黄花。"]'),
('yuanqu-10816','搅筝琶・《阳关》罢，香脸褪残霞。针线慵拈，匙杓倦把。和泪盼雕鞍，','无名氏','元','元曲','yuanqu','','[]','目断天涯，幽雅。',24,'元曲/yuanqu.json','["目断天涯，幽雅。", "离添病人憔悴煞，瘦得来不似人家。"]'),
('yuanqu-10818','沉醉东风・全不想对月拈香剪发，指神誓奠酒浇茶。信口开，连心耍，向','无名氏','元','元曲','yuanqu','','[]','娼门买行踏。',25,'元曲/yuanqu.json','["娼门买行踏。", "但有半句儿真诚敬重咱，无样般相思报答。"]'),
('yuanqu-10819','离亭宴煞・早是可曾经心绪愁牵挂，又逢暮秋潇洒。恰不听寒蛩唧唧，又','无名氏','元','元曲','yuanqu','','[]','听的寒雁哑哑。',86,'元曲/yuanqu.json','["听的寒雁哑哑。", "傍枕衾，临床榻，暂合眼一时半霎。", "又听的疏雨洒窗纱，西风弄檐马。", "离情万金良夜霎时欢，犹恨不松宽。", "停延初试春风面，便安排病沈愁潘。", "从寄巧歌《金缕》，娇羞半掩霜纨。"]'),
('yuanqu-10820','新水令・乐昌妆镜破双鸾，今古恨短长亭畔。两下里几多般，受过的凄凉','无名氏','元','元曲','yuanqu','','[]','被俏萦占。',28,'元曲/yuanqu.json','["被俏萦占。", "分明少个莺花伴，奈今生缘分浅，凉打叠起更休算。"]'),
('yuanqu-10821','搅筝琶・夕阳外，山隐隐水漫漫。似恁的凄凉，如何倒颠。终有日相逢，','无名氏','元','元曲','yuanqu','','[]','心苦眉攒。',20,'元曲/yuanqu.json','["心苦眉攒。", "憔悴了玉容谁是管，越不成烟爨。"]'),
('yuanqu-10822','离亭宴煞・后期远约今秋判，那其间甚娘情款。受儿度枕冷衾寒，捱几宵','无名氏','元','元曲','yuanqu','','[]','月苦风酸。',37,'元曲/yuanqu.json','["月苦风酸。", "酒满斟，他亲劝，先摘得都无少半。", "本待一饮不留残，到被别离泪添满。"]'),
('yuanqu-10823','双调・珍珠马南情','无名氏','元','元曲','yuanqu','','[]','箫声唤起瑶台月，独倚阑干情惨切。',43,'元曲/yuanqu.json','["箫声唤起瑶台月，独倚阑干情惨切。", "此恨与谁说，又值那黄昏时节。", "花飞也，一点点似离人泪血。"]'),
('yuanqu-10824','步步骄南・暗想当年，罗帕上把新诗写，偷绾同心结。心猿乘，意马劣，','无名氏','元','元曲','yuanqu','','[]','都将软玉温香，嫩枝柔叶。',28,'元曲/yuanqu.json','["都将软玉温香，嫩枝柔叶。", "琴瑟正和协，不觉花影转过梧桐月。"]'),
('yuanqu-10825','雁儿落北・不觉的梧桐月转过西银台上，昏惨惨灯将灭。怎禁他纱窗外铁','无名氏','元','元曲','yuanqu','','[]','马儿敲，这些时一团娇香肌瘦怯。',15,'元曲/yuanqu.json','["马儿敲，这些时一团娇香肌瘦怯。"]'),
('yuanqu-10826','沉醉东风南・一团娇香肌瘦怯，半含羞翠钿轻帖。微笑对人悄说：休负了','无名氏','元','元曲','yuanqu','','[]','今宵月。',39,'元曲/yuanqu.json','["今宵月。", "等闲间将海棠偷折，山盟共设：不许暂时少撇，若有个负心的教他随灯儿便灭。"]'),
('yuanqu-10827','得胜令北・呀，若有一个负心的教他随灯灭，惨可可山盟海誓对谁说。海','无名氏','元','元曲','yuanqu','','[]','神庙现放着勾魂帖，那神灵仔细写。',43,'元曲/yuanqu.json','["神庙现放着勾魂帖，那神灵仔细写。", "你休要心斜，非是掩难割舍；你休要痴呆，殷勤将春心漏泄。"]'),
('yuanqu-10828','忒忒令南・他殷勤将春心漏泄，我风流寸肠中热。因此上楚云深锁黄金阙，','无名氏','元','元曲','yuanqu','','[]','休把佳期暂撇。',21,'元曲/yuanqu.json','["休把佳期暂撇。", "燕山绝，湘江竭，断鱼封雁帖。"]'),
('yuanqu-10829','沽美酒北・湘北断鱼雁帖，他一去了信音绝，想着他负德辜恩将谎话说。','无名氏','元','元曲','yuanqu','','[]','眼见的花残月缺，自别来甚时节甚时节。',18,'元曲/yuanqu.json','["眼见的花残月缺，自别来甚时节甚时节。"]'),
('yuanqu-10830','川拨棹北・又被西风将锦帐揭，倚帏屏情惨切。这些时信断音绝，眼中流','无名氏','元','元曲','yuanqu','','[]','心内刀切，泪痕千叠，因此上渭城人肌肤瘦怯。',21,'元曲/yuanqu.json','["心内刀切，泪痕千叠，因此上渭城人肌肤瘦怯。"]'),
('yuanqu-10831','桃红菊南・渭城人肌肤瘦怯，楚天秋应难并叠。停勒了画眉郎京尹，补填','无名氏','元','元曲','yuanqu','','[]','了河阳令满缺。',7,'元曲/yuanqu.json','["了河阳令满缺。"]'),
('yuanqu-10832','七弟兄北・补填了河阳令满缺，一片似火也。心间事与谁说，好教我行眠','无名氏','元','元曲','yuanqu','','[]','立盹无明夜。',47,'元曲/yuanqu.json','["立盹无明夜。", "今日个吹箫无伴彩云赊，闻筝的月下疏狂劣。", "画眉郎手脚拙，窃玉的性情别，把好梦成吴越。"]'),
('yuanqu-10833','川拨棹南・成吴越，怎禁他巧言搬斗喋。平白地送暖偷寒，平白地送暖偷','无名氏','元','元曲','yuanqu','','[]','寒，猛可的搬唇递舌。',24,'元曲/yuanqu.json','["寒，猛可的搬唇递舌。", "水晶丸不住撇，点钢锹一味撅。"]'),
('yuanqu-10834','梅花酒北・他将那点钢锹一迷里撅，劈贤刀手中撇。打捞起块丹枫叶，鸳','无名氏','元','元曲','yuanqu','','[]','鸯被半床歇。',27,'元曲/yuanqu.json','["鸯被半床歇。", "胡蝶梦冷些些，破香囊后成血，楚馆着火焚者。"]'),
('yuanqu-10835','锦衣香南・他将那楚馆焚，秦楼来拽。洛浦填，泾河截。梅家庄水罐汤瓶','无名氏','元','元曲','yuanqu','','[]','打为磁屑，贾充宅守定粉墙缺，武陵溪涧花儿钉了桩橛。',64,'元曲/yuanqu.json','["打为磁屑，贾充宅守定粉墙缺，武陵溪涧花儿钉了桩橛。", "楚襄王梦惊回者，汉相如赶翻车辙。", "深锁芙蓉阙，紫箫吹裂，碧桃花下凤凰将翎毛生扯。"]'),
('yuanqu-10836','收江南北・呀，你敢在碧桃花下将凤毛扯，人生最苦是离别。山长永远路','无名氏','元','元曲','yuanqu','','[]','途赊，何年是彻，响当当菱花镜碎玉簪折。',19,'元曲/yuanqu.json','["途赊，何年是彻，响当当菱花镜碎玉簪折。"]'),
('yuanqu-10838','南吕・一枝花四景春','无名氏','元','元曲','yuanqu','','[]','衮香绵柳絮飞，飘白雪梨花淡。',62,'元曲/yuanqu.json','["衮香绵柳絮飞，飘白雪梨花淡。", "怨东风墙杏色，醉晓日海堂酣。", "景物偏堪，车马人游览，赏清明三月三。", "绿苔撒点点青钱，碧草铺茸茸翠毯。"]'),
('yuanqu-10839','梁州・流水泛江汀暖浪，轻云锁山市睛岚。恐无多光景疾相探。雕鞍玉辔，','无名氏','元','元曲','yuanqu','','[]','纱帽罗衫。',85,'元曲/yuanqu.json','["纱帽罗衫。", "珍羞满卓，玉液盈坛。", "歌姬舞妓那堪，诗朋酒侣相谈。", "生存花屋平昙，兴足竹林阮咸，醉居相府曹参。", "放开，酒胆。", "恨狂风尽把花摇憾，叹阳和又虚赚。", "拚了陶陶饮兴酣，于理相干。"]'),
('yuanqu-10840','尾・紫霜毫入砚深深蘸，吟几首莺花诗满函，一望红稀绿暗。正游入不甘，','无名氏','元','元曲','yuanqu','','[]','奈顽童执骖，不由咱卷把骄骏辔头儿揽。',75,'元曲/yuanqu.json','["奈顽童执骖，不由咱卷把骄骏辔头儿揽。", "夏蔷薇满院香，菡萏双池锦。", "海榴浓喷火，萱草淡堆金。", "暑气难禁，天地炎蒸甚，闲行近绿阴。", "清风台榭开怀，傍流水亭轩赏心。"]'),
('yuanqu-10841','尾・倾残竹叶千尊，摘尽枇杷一树金。深喜娇娥见咱恁，向沙厨用心。安','无名氏','元','元曲','yuanqu','','[]','排下簟枕，专等归来醉时寝。',77,'元曲/yuanqu.json','["排下簟枕，专等归来醉时寝。", "秋金凤凋杨柳衰，玉露养芙蓉艳。", "竹轻摇苍凤尾，松密长老龙鳞。", "残暑都潜，爽气被楼台占，称情怀景色添。", "火龙鳞红叶萧萧，金兽眼黄花苒苒。"]'),
('yuanqu-10842','梁州・南浦晓云飞画栎，西山暮雨洒珠帘。小糟酒摘珍珠酽。银盘馔满，','无名氏','元','元曲','yuanqu','','[]','生鼎香粘。',90,'元曲/yuanqu.json','["生鼎香粘。", "黄橙味美，紫蟹肥甜。", "趁苍空天似白亻兼，玩清光月拥银蟾。", "不学那愁脉脉呆汉江淹，则学兴悠悠诗仙子瞻，陶陶醉客陶潜。", "意忻金樽到手谁曾厌，我待把醉乡占。", "不管衣襟被酒淹，无事拘钳。"]'),
('yuanqu-10843','尾・赏心事休教欠，饮兴吟怀似妻添。醉倒尊前，任君潜扌弃。指点、便','无名氏','元','元曲','yuanqu','','[]','嫌，胜似你红尘路上险。',69,'元曲/yuanqu.json','["嫌，胜似你红尘路上险。", "冬青山失翠微，白玉无瑕玷。", "梨花和雨舞，柳絮带风ㄎ。", "泼粉堆盐，祥瑞天无欠，丰年气象添。", "乱飘湿僧舍茶烟，密洒透歌楼酒帘。"]'),
('yuanqu-10844','梁州・金盏内羊羔满泛，红炉兽炭频添。兰堂画角多妆点。锦茵绣榻，翠','无名氏','元','元曲','yuanqu','','[]','幕毡帘。',88,'元曲/yuanqu.json','["幕毡帘。", "鸾箫谩品，颦鼓轻敲。", "唱仙音余韵淹淹，捧牙版玉指纤纤。", "绮筵间盏到休推，宝鸭内香残再拈，玉壶中酒尽重添。", "况兼、兴タ。", "金波潋滟霞光闪，接入手不辞厌。", "为爱琼瑶尽意瞻，赏玩休嫌。"]'),
('yuanqu-10845','梁州・昨日闹垓垓兵临孟水，今日冷清清草满章华。叹兴亡世事如嚼蜡。','无名氏','元','元曲','yuanqu','','[]','则不如ド半缸绿蚁，啜一盏清茶。',102,'元曲/yuanqu.json','["则不如ド半缸绿蚁，啜一盏清茶。", "感时怀苦，对景嗟呀。", "水穿云碧玉流霞，山叠翠青锦蒙纱。", "黄菊绽猛兽睁睛，红叶落火龙退甲。", "苍松盘怪蟒张牙。", "景幽，静雅。", "一轮皓月林梢挂，醉后将骞驴跨。", "稚子山妻引到家，煞强如大纛高牙。"]'),
('yuanqu-10846','尾・南山射虎弓藏，北海诛龙剑隐匣。两字功名不牵挂，书房中卧咱。松','无名氏','元','元曲','yuanqu','','[]','阴下坐咱，无是无非快活煞。',13,'元曲/yuanqu.json','["阴下坐咱，无是无非快活煞。"]'),
('yuanqu-10847','越调・斗鹌鹑忆别','无名氏','元','元曲','yuanqu','','[]','焰腾腾祆庙烧残，白茫茫蓝桥水起。',48,'元曲/yuanqu.json','["焰腾腾祆庙烧残，白茫茫蓝桥水起。", "昏邓邓楚岫云遮，黑淹淹阳台路迷。", "桃源洞雾锁云埋，武陵溪砖填土塞。"]'),
('yuanqu-10848','紫花儿序・冷落了流苏绣幕，萧疏了画阁兰堂，寂寞了锦帐罗帏。生折散','无名氏','元','元曲','yuanqu','','[]','鸾孤凤只，硬分开燕约莺期，暗暗的伤悲，永远山长隔万里。',51,'元曲/yuanqu.json','["鸾孤凤只，硬分开燕约莺期，暗暗的伤悲，永远山长隔万里。", "一思量一番憔悴，离愁断九曲柔肠，蹙损了八字蛾眉。"]'),
('yuanqu-10849','小桃红・伯苏东云燕西飞，一点芳心醉。鱼雁无凭怎寻觅，信音稀。牙床','无名氏','元','元曲','yuanqu','','[]','冷落了鸳鸯被，减尽了千娇百媚。',32,'元曲/yuanqu.json','["冷落了鸳鸯被，减尽了千娇百媚。", "害的人一丝两气，方信道最苦是别离。"]'),
('yuanqu-10850','耍厮儿・美恩情眉南面北，好姻缘画饼充饥，相逢笑谈除是梦里。这凄凉','无名氏','元','元曲','yuanqu','','[]','怎支持？谁知！。',8,'元曲/yuanqu.json','["怎支持？谁知！。"]'),
('yuanqu-10851','圣药王・想着我星月底，言海誓，尽今生一世效于飞。我如今废寝忘餐染','无名氏','元','元曲','yuanqu','','[]','病疾，上看山不见故人回，险化做望夫石。',19,'元曲/yuanqu.json','["病疾，上看山不见故人回，险化做望夫石。"]'),
('yuanqu-10852','尾声・别离苦恨从头记，有一日捱出凄凉日期。则俺那薄幸短命若回程，','无名氏','元','元曲','yuanqu','','[]','我将这一件件一桩桩诉与你。',16,'元曲/yuanqu.json','["我将这一件件一桩桩诉与你。", "小令。"]'),
('yuanqu-10853','仙吕・小醋大情','无名氏','元','元曲','yuanqu','','[]','暗潮拍岸，断江风扫芦花，鸥鹭破烟飞落汀沙。',76,'元曲/yuanqu.json','["暗潮拍岸，断江风扫芦花，鸥鹭破烟飞落汀沙。", "见渔舍两三家，在夕阳下，一簇晚景堪画。", "闷无语时将珠泪洒，愁转加，瘦损丰标只为他。", "事萦心鬓添白发，蹉跎负却年华。"]'),
('yuanqu-10855','正宫・白练序春愁','无名氏','元','元曲','yuanqu','','[]','沉吟久，奈何事从来不自由？芙蓉帐未暖又还分手，别后万种愁。',54,'元曲/yuanqu.json','["沉吟久，奈何事从来不自由？芙蓉帐未暖又还分手，别后万种愁。", "叹晓梦高唐一旦休，添亻孱亻愁。", "梨花细雨，燕子空楼。"]'),
('yuanqu-10856','太平令・消瘦纤腰似柳，近日绛裙罗带频收。闲衾易冷，人在小小云兜，','无名氏','元','元曲','yuanqu','','[]','堪羞。',34,'元曲/yuanqu.json','["堪羞。", "凄凄孤影伴灯篝，倚窗下倦听银漏。", "这般时候，三更酒醒，满枕春愁。"]'),
('yuanqu-10857','捣白练・绸缪，两配偶，思量起故友。在花阴下同欢会，燕侣鸾俦。无由','无名氏','元','元曲','yuanqu','','[]','愿再酬，恨飞絮飘香逐水流，成迤逗。',27,'元曲/yuanqu.json','["愿再酬，恨飞絮飘香逐水流，成迤逗。", "钗分凤折，线断银钩。"]'),
('yuanqu-10858','太平令・悠悠，青霄路有，绣鞍归晓，山盟虚缪。分开美玉连环结，未能','无名氏','元','元曲','yuanqu','','[]','够两情依旧。',40,'元曲/yuanqu.json','["够两情依旧。", "频修银笺锦字到皇州，每一字字泪痕湮透。", "甚时相守，金杯满酌，艳曲低讴。"]'),
('yuanqu-10861','破挂真・引子忆别娇容情分浅，终朝废寝忘餐。离绪恹恹，情怀攘攘，别','无名氏','元','元曲','yuanqu','','[]','后又添悒怏。',6,'元曲/yuanqu.json','["后又添悒怏。"]'),
('yuanqu-10862','绣带宜春令・幽窗下沉吟半晌，追思俏的娇娘。娉婷处不弱似莺莺，娇娆','无名氏','元','元曲','yuanqu','','[]','处可比双双。',43,'元曲/yuanqu.json','["处可比双双。", "非奖，最堪夸他性格儿温柔，难描他身材儿生得停当。", "说不尽风流可喜，万般模样。"]'),
('yuanqu-10863','太平白练序・想当日月下星前，吐胆倾心，把誓盟深讲。行思坐想，望尽','无名氏','元','元曲','yuanqu','','[]','老今生，同佼攵鸾凰。',44,'元曲/yuanqu.json','["老今生，同佼攵鸾凰。", "谁想，蓦然平地浪波生，怎知道祸从天降。", "雾迷云障，被鸨母苦死打开怨鸯。"]'),
('yuanqu-10864','三段鲍老催・此情怎当，罗衣尚存兰麝香。鸾笺仗托纸半纸，人何在，谩','无名氏','元','元曲','yuanqu','','[]','叹息，空惆怅。',16,'元曲/yuanqu.json','["叹息，空惆怅。", "恼得潘郎两鬓似霜。"]'),
('yuanqu-10865','出队莺乱啼・咱这里因因他来狂荡，他因咱痛感伤。几番欲待不思量，不','无名氏','元','元曲','yuanqu','','[]','思量以后怎做得铁打心肠？江淹闷，韩生忿，怎么得咱家闷？千般恨才离了心上，又早来蹙在眉尖。',59,'元曲/yuanqu.json','["思量以后怎做得铁打心肠？江淹闷，韩生忿，怎么得咱家闷？千般恨才离了心上，又早来蹙在眉尖。", "天还可怜，便霎时相见又且何妨。"]'),
('yuanqu-10866','南吕・香遍满闺情','无名氏','元','元曲','yuanqu','','[]','鸾凰同聘，寻思那时忒志成。',47,'元曲/yuanqu.json','["鸾凰同聘，寻思那时忒志成。", "谁信今番心不定，顿将人来薄幸。", "可怜无限情，也似纸样轻，把往事空思省。"]'),
('yuanqu-10867','懒画眉・花开花谢闷如醒，日远日蔬冷似冰，眼前光景总凄清。漫水流花','无名氏','元','元曲','yuanqu','','[]','径，庭院黄昏门半扃。',10,'元曲/yuanqu.json','["径，庭院黄昏门半扃。"]'),
('yuanqu-10868','挂梧桐・谩教人忆茂陵，调琴谁共听？少个知音，斗帐沉烟冷。孤眠最若，','无名氏','元','元曲','yuanqu','','[]','怕良宵永，这样凄凉如何教我捱到明。',37,'元曲/yuanqu.json','["怕良宵永，这样凄凉如何教我捱到明。", "心肠纵然如铁硬，苦也思量，扑扑簌簌泪倾。"]'),
('yuanqu-10869','浣溪沙・谁惯轻，害相思病，怨只怨枕闲衾剩。两三杯酒全无兴，空教我','无名氏','元','元曲','yuanqu','','[]','十二栏干独自凭。',29,'元曲/yuanqu.json','["十二栏干独自凭。", "心耿耿，想起虚脾情；耳边言，那取真本兰亭。"]'),
('yuanqu-10870','刘泼帽・对景、对景无心咏，倦时闻枝上流莺。如何唤的春愁醒？羞对画','无名氏','元','元曲','yuanqu','','[]','花间翡翠双双并，万虑生，独守着房栊静。',19,'元曲/yuanqu.json','["花间翡翠双双并，万虑生，独守着房栊静。"]'),
('yuanqu-10871','东瓯令・人何在，梦难成。永远山遥不计程，雕鞍宝马无踪影。他那里胡','无名氏','元','元曲','yuanqu','','[]','行径，朱颜绿鬓易凋零，无奈痛伤情。',17,'元曲/yuanqu.json','["行径，朱颜绿鬓易凋零，无奈痛伤情。"]'),
('yuanqu-10872','金钱花・想你掩耳偷铃，为你缄口如瓶。待君归兮细评论，夫妻债雁同鸣，','无名氏','元','元曲','yuanqu','','[]','欢会事凤和鸣。',7,'元曲/yuanqu.json','["欢会事凤和鸣。"]'),
('yuanqu-10873','尾・金钗钿盒重新整，翠被香温叙旧情，鲛绡带绾重再整。四时思慕','无名氏','元','元曲','yuanqu','','[]','柳径花溪，梅梢褪粉丽日迟，桃杏芬芳蜂媒蝶使。',48,'元曲/yuanqu.json','["柳径花溪，梅梢褪粉丽日迟，桃杏芬芳蜂媒蝶使。", "树拖烟笼绿柳，柳花绵片片飞。", "为咱思念伊，恐怕春又归。"]'),
('yuanqu-10874','东瓯令・花容貌，柳颦眉，云鬓堆鸦，温柔旖旎。方才款步我这金莲浸罗','无名氏','元','元曲','yuanqu','','[]','袜冷，腾腾困困娇无力。',30,'元曲/yuanqu.json','["袜冷，腾腾困困娇无力。", "雕栏曲槛，游蜂粉蝶飞，婷婷袅袅欲缓迟。"]'),
('yuanqu-10875','四团花・懒懒愁画眉，看看身渐蠃，情书欲写无凭寄。不见才郎，何时归','无名氏','元','元曲','yuanqu','','[]','把阑干遍倚，将花头倦折。',22,'元曲/yuanqu.json','["把阑干遍倚，将花头倦折。", "莺声呖呖，芳心自知。"]'),
('yuanqu-10876','东瓯令・薰风至，火云飞，则见那萱草葵榴初绽蕊。炎天酷暑浑无寐，迷','无名氏','元','元曲','yuanqu','','[]','迷闷闷醒如醉。',26,'元曲/yuanqu.json','["迷闷闷醒如醉。", "自怜月下月下影儿随，悒悒怏怏懒入罗帏。"]'),
('yuanqu-10877','梧桐树・泪暗垂，添憔悴，渐渐的这腰肢掩过裙儿衤至。一声、一声，塞','无名氏','元','元曲','yuanqu','','[]','雁、塞雁，伤泪滴，远望云山，信杳音稀。',42,'元曲/yuanqu.json','["雁、塞雁，伤泪滴，远望云山，信杳音稀。", "未知多情把奴山盟记，莫得要再求，再求新亲配美。"]'),
('yuanqu-10878','东瓯令・梧桐叶，晚风吹，则这无限的离情我便分付与谁？蓦听的阶下数','无名氏','元','元曲','yuanqu','','[]','声寒蛩叫，扑扑簌簌红叶儿坠。',33,'元曲/yuanqu.json','["声寒蛩叫，扑扑簌簌红叶儿坠。", "碧天寒雁听了感伤悲，凄凄凉凉越添病疾。"]'),
('yuanqu-10879','浣溪沙・雪片飞，寒风起，闷恹恹自守孤帏。薄衾寒浸透香肌，盼情人阻','无名氏','元','元曲','yuanqu','','[]','隔何日归。',41,'元曲/yuanqu.json','["隔何日归。", "戍楼悠悠《三弄》品，气丝丝废寝忘食。", "鸾笺锦字诉与别离，痛伤情泪痕湮透湿。"]'),
('yuanqu-10880','东鸥令・朔风紧，冻云垂，灵鹊儿檐间喳喳的来报喜。不承望今夜画堂里','无名氏','元','元曲','yuanqu','','[]','刚刚的重完全，双双共入罗帏里。',34,'元曲/yuanqu.json','["刚刚的重完全，双双共入罗帏里。", "欢娱无奈被这晓鸡啼，咭咭聒聒好梦惊回。"]'),
('yuanqu-10882','商调・字字锦','无名氏','元','元曲','yuanqu','','[]','群芳绽锦鲜，香逐东风软。',114,'元曲/yuanqu.json','["群芳绽锦鲜，香逐东风软。", "莺簧转巧声，题起伤春怨。", "睹名园，杏障桃屏，桃屏上映着柳眉翠钿。", "天天，桃花窨约，恰似去年。", "因何去年、去年人不见，空蹙破两眉翠尖。", "奈奈山长永远，他在那里和谁两个欢欢喜喜？咱这思思想想，寻寻觅觅，欲待见他一面。"]'),
('yuanqu-10883','赚・离绪恹恹，奈少个人儿在眼前。空嗟怨，不知何日再团圆。泪涟涟，','无名氏','元','元曲','yuanqu','','[]','极目关山隔雾前，写下花笺谁与传？心事无告托，冤家直恁误人方便，怎生消遣。',36,'元曲/yuanqu.json','["极目关山隔雾前，写下花笺谁与传？心事无告托，冤家直恁误人方便，怎生消遣。"]'),
('yuanqu-10884','满园春・南楼外雁翩翩，悄没个音信传。长空败叶飘飘舞，金风动，铁马','无名氏','元','元曲','yuanqu','','[]','儿声喧，纱窗外透银蟾。',40,'元曲/yuanqu.json','["儿声喧，纱窗外透银蟾。", "想杀人也天，盼杀人也天，短命冤家，音稀信杳，莫不误约盟言。"]'),
('yuanqu-10885','幺篇・彤云布，朔风起，遍长空柳花飘棉。几朵早梅开放蕊，销金帐共谁','无名氏','元','元曲','yuanqu','','[]','两个欢宴？独自个守炉边。',41,'元曲/yuanqu.json','["两个欢宴？独自个守炉边。", "想杀人也天，盼杀人也天，短命冤家，音稀信杳，莫不误约盟言。"]'),
('yuanqu-10887','双调・一机锦离思','无名氏','元','元曲','yuanqu','','[]','宝钗分，鸾镜缺，瓶坠簪断折，《三叠阳光》争忍，别。',63,'元曲/yuanqu.json','["宝钗分，鸾镜缺，瓶坠簪断折，《三叠阳光》争忍，别。", "心儿里痛哽咽，眼儿里弹泪血。", "空教我扌绝耳揉腮，执手和伊相看，也没一句话儿说。"]'),
('yuanqu-10888','江儿水・又早三秋至，寒雁飞。牛星女宿重相会，只听的捣砧声透入在罗','无名氏','元','元曲','yuanqu','','[]','帏内。',31,'元曲/yuanqu.json','["帏内。", "景凄凉阶下寒蛩唧，桂子飘香拂鼻。", "叶落丹枫，满目黄花铺地。"]'),
('yuanqu-10890','南吕・一剪梅秋闺思','无名氏','元','元曲','yuanqu','','[]','草满中庭苔满墙，雨潇潇风送幽窗，此凄凉外怎不凄凉？无限心机，多病相妨。',69,'元曲/yuanqu.json','["草满中庭苔满墙，雨潇潇风送幽窗，此凄凉外怎不凄凉？无限心机，多病相妨。", "玉笋重弹孤凤凰，一蓦来地远山长。", "杯深蘸甲润鹅黄，今夜醺醺，有个商量。"]'),
('yuanqu-10891','采桑子・辘轳金井梧桐晚，几树惊秋，昼雨和愁。百尽虾须在玉钩，琼窗','无名氏','元','元曲','yuanqu','','[]','春暖双蛾皱。',24,'元曲/yuanqu.json','["春暖双蛾皱。", "回首头边，欲寄鳞游，九曲寒波不逆流。"]'),
('yuanqu-10892','木兰花慢・爱幽花带露，凝晓色淡秋塘。恨太华峰高，庐山社远，尘世相','无名氏','元','元曲','yuanqu','','[]','谁争半溪佳景？且闲将华发照沧浪。',66,'元曲/yuanqu.json','["谁争半溪佳景？且闲将华发照沧浪。", "羡煞风流公子，一生何限清香？仙家幽野水云乡，高韵却浓妆，看脉脉盈荷觞。", "明日醒来，华信新声，付与秋娘。"]'),
('yuanqu-10893','惜芳春・绿柳长亭晚，珠帘卷暮寒。闷对东风掩泪眼，桃花谢，杏花残。','无名氏','元','元曲','yuanqu','','[]','人未还，盼雕鞍和月凭栏杆。',13,'元曲/yuanqu.json','["人未还，盼雕鞍和月凭栏杆。"]'),
('yuanqu-10894','桃花女破法嫁周公・仙吕/点绛唇','王晔','元','元曲','yuanqu','','[]','俺则见四野田畴，禾苗丰茂。',32,'元曲/yuanqu.json','["俺则见四野田畴，禾苗丰茂。", "登场后，鼓腹歌讴，现如今无士马绝征斗。"]'),
('yuanqu-10895','桃花女破法嫁周公・油葫芦','王晔','元','元曲','yuanqu','','[]','你两个自小儿相随到白头，端的是老故友，但同行共坐笑无休。',136,'元曲/yuanqu.json','["你两个自小儿相随到白头，端的是老故友，但同行共坐笑无休。", "我则道别逢闲汉频摇手，你可也敢则是饱谙世事慵开口。", "俺则见这壁厢闷闷的迎，那壁厢郁郁的忧。", "(带云)伯伯。", "(唱)你为甚么这等悄无言则办的眉儿皱，泪簌簌不住点儿流？(云)伯伯，我去整治些酒菜儿来，与俺父亲饮几杯去。", "(唱)。"]'),
('yuanqu-10896','桃花女破法嫁周公・天下乐','王晔','元','元曲','yuanqu','','[]','却不道一盏能消万古愁，则俺这村也波坊，不比那府共州，那里取笙歌绮罗拥上楼。',67,'元曲/yuanqu.json','["却不道一盏能消万古愁，则俺这村也波坊，不比那府共州，那里取笙歌绮罗拥上楼。", "这快乐俺这里无，这快乐您那里有。", "伯伯也俺这里止不过是村务酒。"]'),
('yuanqu-10897','桃花女破法嫁周公・寄生草','王晔','元','元曲','yuanqu','','[]','俺这里有的是黄鸡嫩，白酒熟，伯伯也你莫不为茅檐草舍庄家陋？(彭大云)俺每都是庄农人家，一村疃儿居住的，有甚么好房子在那里？(正旦云)我也道来。',200,'元曲/yuanqu.json','["俺这里有的是黄鸡嫩，白酒熟，伯伯也你莫不为茅檐草舍庄家陋？(彭大云)俺每都是庄农人家，一村疃儿居住的，有甚么好房子在那里？(正旦云)我也道来。", "(唱)也一般儿青山绿树风光秀，(带云)况我父亲呵，(唱)又和你倾心吐胆交情厚。", "(彭大云)儿也，你不知道。", "我家主人周公，今日与我算一卦，道我没寿，以此吃酒不下。", "(正旦云)伯伯，你没寿今年也六十九岁了。", "(唱)但愿的乐丰年醉倒有百千场，何必要炼丹砂学取那松乔寿？。"]'),
('yuanqu-10898','桃花女破法嫁周公・后庭花','王晔','元','元曲','yuanqu','','[]','你则管里絮叨叨说事头，舌剌剌不住口。',148,'元曲/yuanqu.json','["你则管里絮叨叨说事头，舌剌剌不住口。", "你便待准备着哭啼啼长休饭，伯伯也咱与你换上这喜孜孜欢庆酒。", "休得要泪交流，我着你依前如旧，包管你病羊儿奔似虎彪，困鱼儿脱了钓钩。", "(彭大云)我那周公开了三十年卦铺，止算差的一个，你怎么道他又算差了？(正旦唱)倒将咱佯不瞅，说周公百事有。", "转阴阳得自由，更山川变宇宙。"]'),
('yuanqu-10899','桃花女破法嫁周公・柳叶儿','王晔','元','元曲','yuanqu','','[]','你卖弄他光前、光前绝后，不由我不邓邓火上浇油。',91,'元曲/yuanqu.json','["你卖弄他光前、光前绝后，不由我不邓邓火上浇油。", "(彭大云)如今世上，除了那周公一人妙算，再无敌对哩。", "(正旦唱)你道是周公世上无敌手，早激的我嗔难忍，怒难收，伯伯也则教他到我行纳下降筹。"]'),
('yuanqu-10900','桃花女破法嫁周公・赚煞','王晔','元','元曲','yuanqu','','[]','直等到月转矮墙西，人约黄昏后。',172,'元曲/yuanqu.json','["直等到月转矮墙西，人约黄昏后。", "摆祭物浇茶奠酒，只待那七位星官来领受。", "伯伯也早唬的你颤笃波魂魄悠悠，那其间你可便休落了芒头，要记的语句儿滑熟，(彭大云)那星官是甚么形相？我可害怕，怎生告他来？(正旦唱)忍着怕担着惊告北斗，比似你做阴司下鬼囚，争似得他这天堂上阳寿，(带云)伯伯，则今夜且和俺父亲吃一个烂醉者，(唱)管着你笑吟吟同做醉乡侯。", "(下)。"]'),
('yuanqu-10901','桃花女破法嫁周公・正宫/端正好','王晔','元','元曲','yuanqu','','[]','则为这镜儿昏，我可也难梳裹，就东庄头巧匠明磨。',52,'元曲/yuanqu.json','["则为这镜儿昏，我可也难梳裹，就东庄头巧匠明磨。", "去时节大斋时，急回来可早日头儿末，不知俺家中有甚的人焦聒。"]'),
('yuanqu-10902','桃花女破法嫁周公・滚绣球','王晔','元','元曲','yuanqu','','[]','我头直上发似揪，耳轮边热似火。',240,'元曲/yuanqu.json','["我头直上发似揪，耳轮边热似火。", "我行行里袖传一课，急慌忙把脚步儿频挪。", "我这里穿人道桑拓林，穿小径荆棘科。", "(带云)早来到门首也。", "(唱)则见乱交加不知是那个，则听的沸滚滚热闹镬铎。", "(任二公云)彭大公，你使这等见识，我拼的和你做一场。", "(正旦唱)俺父亲揎拳捋袖因何事？(彭大云)你要打我么？由你打，由你打，只要许了这亲事便罢。", "(正旦云)原来是彭大公。", "(唱)他这般唱叫扬疾，不徕，便可也为甚么？(彭大做见正旦科，云)好、好、好！女孩儿来了也。", "我有说话，要和你讲哩。", "(正旦唱)有甚的好话评跋？。"]'),
('yuanqu-10903','桃花女破法嫁周公・倘秀才','王晔','元','元曲','yuanqu','','[]','那问亲的无礼法将我来劫夺，若是我不许聘我可有甚么罪过？(彭大云)哎哟！你这小孩子家就学得放泼那？(正旦唱)知他是您行凶也那我放泼？(媒婆云)喜事不要嚷！姐姐，你',170,'元曲/yuanqu.json','["那问亲的无礼法将我来劫夺，若是我不许聘我可有甚么罪过？(彭大云)哎哟！你这小孩子家就学得放泼那？(正旦唱)知他是您行凶也那我放泼？(媒婆云)喜事不要嚷！姐姐，你则许了罢。", "(正旦唱)你休言语，怎成合，可正是望梅止渴。", "(彭大云)孩儿也，周公家这门好亲事，我可着你受用一世儿哩。", "我就与你做个落花的媒人，也不亏了你。", "(正旦云)谁听你这话来？(唱)。"]'),
('yuanqu-10904','桃花女破法嫁周公・滚绣球','王晔','元','元曲','yuanqu','','[]','则你这媒人一个个，啜人口似蜜钵，都只是随风倒舵，索媒钱嫌少争多。',97,'元曲/yuanqu.json','["则你这媒人一个个，啜人口似蜜钵，都只是随风倒舵，索媒钱嫌少争多。", "女亲家会放水，男亲家点着火，你将那好言语往来收撮，则办得两下里挑唆。", "你将那半句话搬调做十分事，一尺水翻腾做百丈波，则你那口似悬河。"]'),
('yuanqu-10905','桃花女破法嫁周公・叨叨令','王晔','元','元曲','yuanqu','','[]','你道是石哥哥我不合救了他亡身祸，因此上被周公家知道我这赔钱货。',114,'元曲/yuanqu.json','["你道是石哥哥我不合救了他亡身祸，因此上被周公家知道我这赔钱货。", "我则道多是你这撮合山要赚松纹锞，那里管赤绳儿曾把姻缘缚？兀的不气杀人也波哥，兀的不气杀人也波哥。", "(带云)彭大公，你好歹也！(唱)我则问你个彭大公怎么的也这等迎风箕欠。"]'),
('yuanqu-10906','桃花女破法嫁周公・呆骨朵','王晔','元','元曲','yuanqu','','[]','想当日泪漫漫哭的你那喉咙破，怕不眼睁睁的待见阎罗。',139,'元曲/yuanqu.json','["想当日泪漫漫哭的你那喉咙破，怕不眼睁睁的待见阎罗。", "周公也他算着你身亡，我端的救了你命活。", "(彭大云)儿也，你是我的恩人，怎忘得你？(正旦唱)哎！你个彭大公才得消磨难，倒着我桃花女平白地遭摧挫。", "(彭大云)这是周公家要求媳妇，干我甚事？(正旦唱)也是我不合搭救你，你将这恶言词展赖我。"]'),
('yuanqu-10907','桃花女破法嫁周公・伴读书','王晔','元','元曲','yuanqu','','[]','你休则管里闲撺掇，休则管里空担荷。',75,'元曲/yuanqu.json','["你休则管里闲撺掇，休则管里空担荷。", "我如今绿鬓朱颜如花朵，我又不苍颜皓首年高大。", "到来日你可便牵羊携酒来相贺，(带云)大公也。", "(唱)你看道是谁家结下丝萝。"]'),
('yuanqu-10908','桃花女破法嫁周公・煞尾','王晔','元','元曲','yuanqu','','[]','则怕我到家来有危有难如何躲，我劝你所作依公莫太过。',74,'元曲/yuanqu.json','["则怕我到家来有危有难如何躲，我劝你所作依公莫太过。", "投至得到我根前问个定夺，讨个提掇，决个死活。", "哎！周公徕，你便有灵验的阴阳，敢可也近不的我。", "(下)。"]'),
('yuanqu-10909','桃花女破法嫁周公・彭大云','王晔','元','元曲','yuanqu','','[]','兄弟，你女儿己许下亲事，我便与媒婆回周公话去也。',135,'元曲/yuanqu.json','["兄弟，你女儿己许下亲事，我便与媒婆回周公话去也。", "(做别科)(任二公做扯住科，云)哥哥也，还吃钟喜酒去。", "(媒婆云)任二公不劳了。", "周公在那里悬望，要准备下财礼迎娶过门，许多事务，都只在明日一日，放彭大公早些去罢。", "(任二公云)这等，一发待成亲之后，同你来吃喜酒便了。", "(同下)。"]'),
('yuanqu-10910','桃花女破法嫁周公・中吕/粉蝶儿','王晔','元','元曲','yuanqu','','[]','别人家聘女求妻，也索是两家门对，写婚书要立官媒。',62,'元曲/yuanqu.json','["别人家聘女求妻，也索是两家门对，写婚书要立官媒。", "下花红，送羊酒，都选个良辰吉日。", "大纲来为正礼当宜，那里取这不明白强人婚配？。"]'),
('yuanqu-10911','桃花女破法嫁周公・醉春风','王晔','元','元曲','yuanqu','','[]','你去那《周易》内显神通，怎如我六壬中识详细。',72,'元曲/yuanqu.json','["你去那《周易》内显神通，怎如我六壬中识详细。", "也不待到家门就要算的我一身亏，你道波可有这个理、理？由你有百般的阴谋，千般的巧计，怎当我万般的堤备。"]'),
('yuanqu-10912','桃花女破法嫁周公・迎仙客','王晔','元','元曲','yuanqu','','[]','他道是日游神为祸祟，我桃花女受灾危，怎知有千只眼先驱能辟鬼？(媒婆做扶出门科)(正旦唱)我行出宅门前，离得这闺阁里。',80,'元曲/yuanqu.json','["他道是日游神为祸祟，我桃花女受灾危，怎知有千只眼先驱能辟鬼？(媒婆做扶出门科)(正旦唱)我行出宅门前，离得这闺阁里。", "我呵若不是妆束巍巍，险些儿被金神打的天灵碎。"]'),
('yuanqu-10913','桃花女破法嫁周公・醉高歌','王晔','元','元曲','yuanqu','','[]','坐车儿倒背我这身奇，手帕儿遮檬了我面皮。',75,'元曲/yuanqu.json','["坐车儿倒背我这身奇，手帕儿遮檬了我面皮。", "(彭大云)怎么这新人车儿不向前走，到往后退那？(正旦唱)大公也，你可怎生不解其中意，我则怕撞着那凶神的这太岁。"]'),
('yuanqu-10914','桃花女破法嫁周公・石榴花','王晔','元','元曲','yuanqu','','[]','今日是会新亲待客做筵席，倒准备着长休饭、永别杯。',90,'元曲/yuanqu.json','["今日是会新亲待客做筵席，倒准备着长休饭、永别杯。", "莫不找拜先灵打着面豹纛旗，你畅好是下的。", "使这般狡幸心机。", "娶新人指望成佳配，结百年谐老大妻。", "怎么未成亲先使这拖刀计，早难道人善得人欺。"]'),
('yuanqu-10915','桃花女破法嫁周公・斗鹌鹑','王晔','元','元曲','yuanqu','','[]','你送的我九死一生，哎！周公也枉坏了你那三财的这六礼。',567,'元曲/yuanqu.json','["你送的我九死一生，哎！周公也枉坏了你那三财的这六礼。", "(做倒席行科，彭大云)你只管里把这两领席，倒来倒去，是甚么主意？(正旦唱)这的是我避难的机谋，躲灾的见识。", "为甚么走走行行铺下净席？则要你盖了这里。", "他拣定这黑道的凶辰，(带云)我将这净席呵，(唱)与他换过了黄道的吉日。", "(彭大云)这一会儿可不听的他言语了，待我看咱。", "(做看正旦科)(正旦云)伯伯，你看我怎的？(彭大云)没。", "(周公上，问彭大科，云)如何？(彭大云)不济事。", "(周公云)这一番准着他板僵身死。", "(彭大云)他还活活儿的哩！(周公云)他怎生活了来？(彭大云)他早知道了，说今日是黑道日，他把两领净席，铺在地下，行一领倒一领，换过黄道走了，因此他可不死，还是活活儿的哩。", "(周公云)嗨，这妮子好强也。", "(彭大云)你可不济哩。", "(周公云)等我再算一卦。", "乾、坎、艮、震、巽、离、坤、兑。", "如今他该入门了，正是星日马当直，新人犯了他，跑也跑杀，踢也踢杀。", "怕他不板僵身死？彭祖，你去请新人入门咱。", "(下)(彭大做摇头科，云)周公，你好忒狠也！媒婆，扶着新人入门者！(正旦云)且慢者！今日是星日马当直，我过的这门限去。", "正汤着他脊背，可不被这马跑也跑杀，踢也踢杀，那里取我的这性命来？石小大哥，与我取马鞍一副，搭在这门限上波。", "(石留住做搭马鞍科)(彭大云)他把门限上放上这马鞍子，又做甚么勾当？(正旦唱)。"]'),
('yuanqu-10916','桃花女破法嫁周公・上小楼','王晔','元','元曲','yuanqu','','[]','你争知就里，阴阳凶吉。',605,'元曲/yuanqu.json','["你争知就里，阴阳凶吉。", "现如今星日马当日，降临凡世，正是该期。", "我可也怎敢的，擅便道，汤他脊背？先与他停停当当，鞍上这一重鞍辔。", "(彭大云)嗨，这一会儿我可不听见他言语了。", "(做看正旦科)(正旦云)伯伯，你看我怎的？(彭大云)没。", "(周公上，问彭大科，云)如何？(彭大云)罢么，我道你老了不济事了。", "(周公云)他可板僵身死了么？(彭大云)老官人，他还活活儿的哩。", "(周公云)他怎的活了来？(彭大云)我去请他入门。", "他道今日是星日马直日，把一副鞍子来搭在门限上，那马便顺顺的伏了他，跑也不敢跑一跑，踢也不敢踢一踢，因此不死，还活活儿的哩。", "(周公云)这妮子好强也。", "(彭大云)我说道，你可不济事哩。", "(周公云)等我再算一卦。", "乾、坎、艮、震、巽、离、坤、兑。", "我如今请他入这墙院子来，却是鬼金羊，昴日鸡当直。", "这两个神祗巡绰，若见了新人呵，鸡儿啄也啄杀他，羊角儿触也触杀他，必然板僵身死也。", "(下)(彭大做掩泪科，云)儿口乐，这一番可送了孩儿的性命也。", "媒婆，请新人入墙院子来，(媒婆做请科)(正旦云)且慢者！这早晚正值鬼金羊，昴日鸡两个神祗巡绰，我入这墙院子去，必受其祸。", "石小大哥，取一面镜子来，与我照面，再取那碎草米谷，和这染成的五色铜钱，等我行一步，与我撒一步者。", "(石留住云)兀的不是镜子？我便撒那碎草米谷去。", "(正旦做取镜，自照科)(石留住做撒草谷科)(彭大云)这孩儿有许多琐碎。", "(媒婆做扶入墙院科)(正旦云)伯伯，你可那里知道？(唱)。"]'),
('yuanqu-10917','桃花女破法嫁周公・幺篇','王晔','元','元曲','yuanqu','','[]','我着这草喂了羊，谷喂了鸡。',71,'元曲/yuanqu.json','["我着这草喂了羊，谷喂了鸡。", "(带云)这铜钱呵，(唱)着小孩儿每，吵吵闹闹斗争相戏。", "趁哄里，向堂前，将身平立。", "哎！周公也可早则颓气了你那巽离坤兑。"]'),
('yuanqu-10918','桃花女破法嫁周公・普天乐','王晔','元','元曲','yuanqu','','[]','我这里说真实，言端的今日是犯着丧门吊客。',126,'元曲/yuanqu.json','["我这里说真实，言端的今日是犯着丧门吊客。", "我早把弓箭忙射，弓拽开似明月弯，箭发去似流星坠。", "(石留住云)关上门者，等我射箭。", "一箭，两箭，三箭。", "(正旦唱)我这里笑吟吟挪身来宅内，周公也可不教我直挺挺板死在门闱？羞杀你晓三才的孔明，知六壬的鬼谷，画八卦的伏羲。"]'),
('yuanqu-10919','桃花女破法嫁周公・快活三','王晔','元','元曲','yuanqu','','[]','我则怕这雷霆白虎威，因此上要一个做相陪。',40,'元曲/yuanqu.json','["我则怕这雷霆白虎威，因此上要一个做相陪。", "忽被那鼓声惊动怎支持，倒惹了你的凄惶泪。"]'),
('yuanqu-10920','桃花女破法嫁周公・尾煞','王晔','元','元曲','yuanqu','','[]','算人间死与生，较阴阳高共低。',46,'元曲/yuanqu.json','["算人间死与生，较阴阳高共低。", "再休提天文地理星家历，周公也你在我桃花女根前如何过去得。", "(下)。"]'),
('yuanqu-10921','桃花女破法嫁周公・双调/新水令','王晔','元','元曲','yuanqu','','[]','则问你为甚么腰横利斧出城东，怎生的我根前还来打哄？我心间无限事，尽在不言中。',396,'元曲/yuanqu.json','["则问你为甚么腰横利斧出城东，怎生的我根前还来打哄？我心间无限事，尽在不言中。", "不由我忿气冲冲，谢得公婆家将俺来厮知重。", "(彭大云)儿也，实不相瞒，委的是周公着我砍桃树儿去哩。", "(正旦云)伯伯，想当初是我救你来，今日可要你救我。", "(彭大云)儿也，你着我今日可怎生救你？(正旦云)伯伯，你砍那桃树去，休要伤了他根儿，你只半中间砍折。", "你若拿这桃枝进门，那时节我须死了。", "只要你记着我的言语，将那桃枝去门限上敲一敲，着周公家死一口。", "(彭大云)敲两敲呢？(正旦云)着周公家死两口。", "(彭大云)敲三敲呢？(正旦云)死三口。", "(彭大云)这等我直敲到晚，只是你不死。", "我与你报冤便好。", "你也死了，就把周公家七代先灵都死绝了。", "你怎得见？(正旦云)只等周公死后，你向我耳朵根边高叫三声：桃花女快苏醒者！我便得还魂也。", "(彭大云)这话有准么？(正旦云)岂有不准之理？(彭大云)孩儿放心，我牢记着哩。", "我如今砍桃树去也。", "(下)(正旦唱)。"]'),
('yuanqu-10922','桃花女破法嫁周公・雁儿落','王晔','元','元曲','yuanqu','','[]','我这里困腾腾睡正浓，则听的闹嚷嚷声惊动。',38,'元曲/yuanqu.json','["我这里困腾腾睡正浓，则听的闹嚷嚷声惊动。", "还不够半竿日影斜，早唤醒一枕游仙梦。"]'),
('yuanqu-10923','桃花女破法嫁周公・得胜令','王晔','元','元曲','yuanqu','','[]','呀，笑杀那注《易》的老周公，枉了也砍折这小桃红。',75,'元曲/yuanqu.json','["呀，笑杀那注《易》的老周公，枉了也砍折这小桃红。", "他道是推休咎凭他用，怎如我转阴阳妙不穷。", "他道是英雄，要把我残生送。", "我如今从也波容，也等他一家儿似梦中。"]'),
('yuanqu-10924','桃花女破法嫁周公・川拨棹','王晔','元','元曲','yuanqu','','[]','你须是俺公公，比旁人自不同。',106,'元曲/yuanqu.json','["你须是俺公公，比旁人自不同。", "我实指望承奉欢容，扶助家风。", "怎知你逞尽顽凶，设就牢笼，不许我身安寿永，到今日爻与卦两无功。", "(周公云)媳妇儿，你则可怜见，救我两个孩儿咱。", "(正旦再用水喷增福科)(增福做醒科)(正旦唱)。"]'),
('yuanqu-10925','桃花女破法嫁周公・收江南','王晔','元','元曲','yuanqu','','[]','呀，今日个桃花依旧笑春风，再不索树头树底觅残红。',56,'元曲/yuanqu.json','["呀，今日个桃花依旧笑春风，再不索树头树底觅残红。", "多谢你使心作幸白头翁，若不是这些懵懂，怎能够一家儿团聚喜融融？。"]'),
('yuanqu-10926','桃花女破法嫁周公・鸳鸯煞尾','王晔','元','元曲','yuanqu','','[]','从今后再休提一求一肯机谋中，越显你千占千验声名重。',89,'元曲/yuanqu.json','["从今后再休提一求一肯机谋中，越显你千占千验声名重。", "也不索家贮神龟，户纳钱龙。", "畅道术似君平，财如邓通，赢得个车马填门四远里人传颂。", "你知我为甚的所事儿玲珑？则我这桃花元是那上天的种。"]'),
('yuanqu-10927','尾声・若道是成就了洞房中惜玉怜香愿，媒合了翠馆内清风皓月筵，六片','萨都剌','元','元曲','yuanqu','','[]','儿香皮做烟眷。',32,'元曲/yuanqu.json','["儿香皮做烟眷。", "茶コ架边，蔷薇洞前，管教你到底团圆不离了半步儿远。"]'),
('yuanqu-10928','赵匡义智娶符金锭・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','母亲道年长青春未配人，我拚了个雨打梨花深闭门。',103,'元曲/yuanqu.json','["母亲道年长青春未配人，我拚了个雨打梨花深闭门。", "我怎肯将名利似浮云。", "(夫人云)孩儿，你则不出门呵便了也。", "(正旦唱)我从来有忠信，(云)父亲母亲你但放心。", "梅香，俺回去来。", "(唱)我又索纱窗下捱黄昏。", "(同梅香下)。"]'),
('yuanqu-10929','赵匡义智娶符金锭・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','你看那绿柳低垂，燕雏成对，莺声碎。',28,'元曲/yuanqu.json','["你看那绿柳低垂，燕雏成对，莺声碎。", "花老芳池，一派游春意。"]'),
('yuanqu-10930','赵匡义智娶符金锭・混江龙','无名氏','元','元曲','yuanqu','','[]','非是我懒临园内，隔花阴怕有外人知。',68,'元曲/yuanqu.json','["非是我懒临园内，隔花阴怕有外人知。", "自从我初离绣幕，莲步轻移。", "春事已随流水去，落花空惹杜鹃啼。", "冷清清花影疏林内，我则见山光隐隐，绿柳依依。"]'),
('yuanqu-10931','赵匡义智娶符金锭・油葫芦','无名氏','元','元曲','yuanqu','','[]','二月江南莺乱啼，绕花阴双燕飞，则见那秋千闲控玉人归。',175,'元曲/yuanqu.json','["二月江南莺乱啼，绕花阴双燕飞，则见那秋千闲控玉人归。", "(梅香云)可惜我们不曾拿的酒来。", "姐姐，你且在这里耍，我去崇文门外头买两瓶酒来你吃。", "(正旦唱)便休将诗酒为佳致，可不道山翁之兴何须醉。", "(梅香云)姐姐，你看那梨花，桃花杏花开的真是好看。", "(正旦唱)梨花开雪片妆，桃花放红焰飞。", "你看那浸浸红杏烧林际，端的可也不尽眼中题。", "(梅香云)无一个人也呵。", "(正旦唱)。"]'),
('yuanqu-10932','赵匡义智娶符金锭・天下乐','无名氏','元','元曲','yuanqu','','[]','抵多少宴罢青楼月下归，不由我猜疑，心上喜。',73,'元曲/yuanqu.json','["抵多少宴罢青楼月下归，不由我猜疑，心上喜。", "(梅香云)姐姐。", "你喜欢甚么？(正旦唱)牡丹风似人摇锦机。", "趁风和花草香，落残红衬燕泥，我则索慢行过芳树底。"]'),
('yuanqu-10933','赵匡义智娶符金锭・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','我这里猛听的，似呆痴。',42,'元曲/yuanqu.json','["我这里猛听的，似呆痴。", "又不是月下星前，暗约偷期。", "不由我听沉了半会，是谁人乱作胡为？。"]'),
('yuanqu-10934','赵匡义智娶符金锭・寄生草','无名氏','元','元曲','yuanqu','','[]','又不曾待月在西厢下，听琴在旅店里。',171,'元曲/yuanqu.json','["又不曾待月在西厢下，听琴在旅店里。", "踏青惹下弥天罪，赏春光引起鸳鸯会，看群花误到天台地。", "(云)我依着你。", "我吟一首诗，看他说甚么。", "紫燕双双起，鸳鸯对对飞。", "无言匀粉面，只有落花知。", "(赵匡义云)好个聪明女子也。", "我出去见他一面，怕些甚么。", "(做见科，云)小娘子拜揖。", "(正旦云)先生万福。", "一人好聪明俊秀才！(唱)我见他乌纱小帽晃人明，久以后必然金榜题名讳。"]'),
('yuanqu-10935','赵匡义智娶符金锭・醉中天','无名氏','元','元曲','yuanqu','','[]','正二九青年际。',104,'元曲/yuanqu.json','["正二九青年际。", "(赵匡义云)曾许聘他人不曾？(正旦唱)不曾得见良媒，独倚纱窗懒画眉。", "(赵匡义云)小娘子，小生愿为媒证，许聘他人，可不好那。", "(正旦唱)多谢你相周济。", "争奈听姻缘事迟，城难躲避，我又怕惹蜂蝶泄漏春机。"]'),
('yuanqu-10936','赵匡义智娶符金锭・金盏儿','无名氏','元','元曲','yuanqu','','[]','也是我命低微，惹灾危，若是俺尊堂知道可也甘当罪。',94,'元曲/yuanqu.json','["也是我命低微，惹灾危，若是俺尊堂知道可也甘当罪。", "(赵匡义云)这厮合死也。", "(正旦唱)他那里揎拳裸袖皱双眉。", "(韩松云)这个是甚么人？我怕你不成也。", "(正旦唱)那里也画堂欢宴，早难道是花下燕莺期。"]'),
('yuanqu-10937','赵匡义智娶符金锭・赚煞尾','无名氏','元','元曲','yuanqu','','[]','不承望有今朝，到着我愁无计，又怕俺双亲得知，忙步金莲趁早回，休忘厂蝶使蜂媒。',169,'元曲/yuanqu.json','["不承望有今朝，到着我愁无计，又怕俺双亲得知，忙步金莲趁早回，休忘厂蝶使蜂媒。", "(赵匡义云)小娘子，我便着官媒来议亲也呵。", "(正旦唱)便休要忒延迟误了佳期，准备兰堂宴罢归。", "(家童冲上，云)姐姐，相公有请。", "(梅香云)叫我们哩。", "我去来。", "(正旦唱)你休要喧喧闹起，再无个商议。", "(云)二舍，你休怪，我去也。", "(唱)抵多少青楼歌罢宴酣回。", "(同梅香家童下)。"]'),
('yuanqu-10938','赵匡义智娶符金锭・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','俺须是官员仕宦家，又不是黎庶闾阎客。',83,'元曲/yuanqu.json','["俺须是官员仕宦家，又不是黎庶闾阎客。", "俺兄弟养成彪虎志，久以后必有胆天才。", "好着我心下疑猜，恨不的两步为一蓦，急煎煎不放怀。", "俺兄弟困恹恹病在膏肓，猛可里便苦腾腾石沉大海。"]'),
('yuanqu-10939','赵匡义智娶符金锭・梁州','无名氏','元','元曲','yuanqu','','[]','自从俺已有了徐卿二子，怕甚么令巍峨王氏三槐。',143,'元曲/yuanqu.json','["自从俺已有了徐卿二子，怕甚么令巍峨王氏三槐。", "俺门户中未有三千客，出来的谈天论地，胸卷江淮。", "不离了龙韬虎略，弓箭旗牌。", "展胸襟个个英才，论机谋转转安排。", "大兄弟虎狼丛惹事招非，刀剑洞大宽地窄，死生巢一迷里裁排。", "威哉？壮哉？博一个腰金衣紫官三代。", "暗地里自分解，不知是暑湿风寒天降来，不见个明白。"]'),
('yuanqu-10940','赵匡义智娶符金锭・隔尾','无名氏','元','元曲','yuanqu','','[]','他莫不是功名不遂心无奈？(赵弘殷云)不是。',117,'元曲/yuanqu.json','["他莫不是功名不遂心无奈？(赵弘殷云)不是。", "(正旦唱)他莫不是思念哥哥不下怀？(赵弘殷云)不是。", "(正旦唱)莫不是少欠人钱使人怪？(赵弘殷云)不是。", "孩儿，你都猜不着。", "(正旦唱)这谜儿怎猜。", "我实难布摆。", "天那，莫不他斗打相争受了些外人的歹？。"]'),
('yuanqu-10941','赵匡义智娶符金锭・牧羊关','无名氏','元','元曲','yuanqu','','[]','见兄弟面色儿恹恹瘦，容颜儿惭惭改，怎生来形体如柴。',141,'元曲/yuanqu.json','["见兄弟面色儿恹恹瘦，容颜儿惭惭改，怎生来形体如柴。", "(云)兄弟，你这病我试猜咱。", "(赵匡义云)姐姐。", "我试猜咱。", "(正旦唱)莫不为身事难求？莫不为经营买卖？赵匡义云)不是。", "你猜不着。", "(正旦唱)莫不是霜露侵肌体？莫不是月下被风筛？(赵匡义云)都不是。", "(正旦唱)止不过心念别姻眷，一庄庄我自猜。"]'),
('yuanqu-10942','赵匡义智娶符金锭・骂玉郎','无名氏','元','元曲','yuanqu','','[]','我这里听言道罢添惊怪，有甚么难分诉你与我诉个明白。',97,'元曲/yuanqu.json','["我这里听言道罢添惊怪，有甚么难分诉你与我诉个明白。", "你莫不在章台走马垂杨陌？(赵匡义云)姐姐，我这病则为前日赏春去，遇着个女子，以此上得了这个病证也。", "(正旦唱)您将那心上愁，腹内思，悦与我方何碍。"]'),
('yuanqu-10943','赵匡义智娶符金锭・感皇恩','无名氏','元','元曲','yuanqu','','[]','呀，便着你鱼水和谐，你也可稳放宽怀。',111,'元曲/yuanqu.json','["呀，便着你鱼水和谐，你也可稳放宽怀。", "我如今遣官媒，亲问候，便有个好音来。", "(赵匡义云)姐姐，你不知韩松那厮，倚逞权豪，他要强娶他哩。", "(正旦云)不妨事。", "(唱)遮莫他官居一品，怕甚么日转千街，凭着俺人力勇，弟兄多，便着他有非灾。"]'),
('yuanqu-10944','赵匡义智娶符金锭・采茶歌','无名氏','元','元曲','yuanqu','','[]','父亲你走将来快安排，今日个洛阳花酒一时来。',77,'元曲/yuanqu.json','["父亲你走将来快安排，今日个洛阳花酒一时来。", "(赵匡义云)姐姐，那韩松若知道呵，必然与俺争竞也。", "(正旦云)不怕他。", "(唱)统领军卒驱士马，我着他闻咱名姓命先衰。"]'),
('yuanqu-10945','赵匡义智娶符金锭・煞','无名氏','元','元曲','yuanqu','','[]','心中愁闷当时解，参透韩松大会垓。',52,'元曲/yuanqu.json','["心中愁闷当时解，参透韩松大会垓。", "兄弟你今朝且耽待。", "我忙回住宅，自有个计划。", "便着你花烛筵开会宾客。", "(下)。"]'),
('yuanqu-10946','赵匡义智娶符金锭・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','一会家心下念想，这姻缘怎生主张？我在那绣房中自在参详。',133,'元曲/yuanqu.json','["一会家心下念想，这姻缘怎生主张？我在那绣房中自在参详。", "(梅香云)姐姐，你则拣着好姐夫嫁了便罢也。", "(正旦云)你那里知道也。", "(唱)我须知你主意，则着我别寻投向。", "(梅香云)姐姐，你便想我那姐夫，不知我那姐夫想你也不想你也，(正旦唱)你这个无礼的梅香，你将我假支吾故来抵当。"]'),
('yuanqu-10947','赵匡义智娶符金锭・迎仙客','无名氏','元','元曲','yuanqu','','[]','父亲你听拜禀，诉衷肠，这亲礼两家儿两家儿可便那下里强？(王朴云)小姐，你则心顺的便成也。',102,'元曲/yuanqu.json','["父亲你听拜禀，诉衷肠，这亲礼两家儿两家儿可便那下里强？(王朴云)小姐，你则心顺的便成也。", "(正旦唱)我若是肯依随，休要讲，主张在尊堂。", "(夫人云)你休要这般说，我自有个主意也。", "(正旦唱)母亲你便有主张休谦让。"]'),
('yuanqu-10948','赵匡义智娶符金锭・红绣鞋','无名氏','元','元曲','yuanqu','','[]','狠媒证人前闲强，你着我嫁韩松罗锦千箱，我则待布袄荆钗守寒窗。',94,'元曲/yuanqu.json','["狠媒证人前闲强，你着我嫁韩松罗锦千箱，我则待布袄荆钗守寒窗。", "(媒婆云)他家那饮馔也用不了。", "(正旦唱)便做道珍羞百味，干使碎你那好心肠。", "(媒婆云)你可嫁也不嫁？(正旦唱)劝你这强媒人休再往。"]'),
('yuanqu-10949','赵匡义智娶符金锭・上小楼','无名氏','元','元曲','yuanqu','','[]','他正那人前闹嚷，指望待成亲名望。',89,'元曲/yuanqu.json','["他正那人前闹嚷，指望待成亲名望。", "看不上他-来一往，施展衣服，卖弄轻狂。", "(梅香云)小姐，你则丢下那绣球儿去来罢。", "(正旦唱)你着我将绣球儿，忙掷下，韩松身上，可不教那有情人每朝指望。"]'),
('yuanqu-10950','赵匡义智娶符金锭・幺篇','无名氏','元','元曲','yuanqu','','[]','他那里慢慢的来，我这里暗暗的慌。',79,'元曲/yuanqu.json','["他那里慢慢的来，我这里暗暗的慌。", "羞的我不敢抬头，连忙遮面，无处潜藏。", "(梅香云)绣球儿在这里，丢下去罢。", "(正旦唱)一见了绣球儿，心中悒怏，我着他霎时间共同鸳帐。"]'),
('yuanqu-10951','赵匡义智娶符金锭・般涉调耍孩儿','无名氏','元','元曲','yuanqu','','[]','我这里可咛觑了他模样，办着片志诚心便央。',323,'元曲/yuanqu.json','["我这里可咛觑了他模样，办着片志诚心便央。", "我则见军民士户在楼前，唬的我不敢名扬。", "(梅香云)姐姐丢下去罢。", "(正旦唱)我待要时间抛掷心中惧，又则怕错了教他向那厢。", "(梅香云)姐姐，你则望着我这赵姐夫抛了罢。", "(正旦唱)你也有心偏向，我将这绣球儿抛下。", "准备着齐整的陪房。", "(正旦云)我望着这赵匡义身上丢下去。", "(做抛下绣球科，赵匡义做接了科，韩松做夺了绣球科，云)是我的，你将的那里去？两个兄弟，俺得了绣球儿也，俺回家去来。", "(同胡缠歪缠下)(郑恩云)这厮好无礼也。", "是你的绣球儿，他夺的去了，更待干罢。", "俺打这厮去来。", "(符彦卿云)赵匡义，你休赶他去，我见绣球儿已是你的，你明日拣好日辰来娶，休要致怨。", "小姐，你下楼来，先回去罢。", "(正旦同做下楼科，云做见科，下)(唱)。"]'),
('yuanqu-10952','赵匡义智娶符金锭・煞尾','无名氏','元','元曲','yuanqu','','[]','到今日趁了心，绣球儿有忖量，至来朝约定同鸳帐，成就了一世儿夫妻慢慢的赏。',43,'元曲/yuanqu.json','["到今日趁了心，绣球儿有忖量，至来朝约定同鸳帐，成就了一世儿夫妻慢慢的赏。", "(同梅香下)。"]'),
('yuanqu-10953','赵匡义智娶符金锭・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','今日个婚姻才定准，亏了英雄十数人。',99,'元曲/yuanqu.json','["今日个婚姻才定准，亏了英雄十数人。", "(郑恩云)姐姐，若不是此计，怎生瞒过他也。", "(正旦唱)我若是半霎儿到家门，端的是机谋可便敬谨。", "(云)你见了俺父母呵。", "(唱)也少不的排佳宴，可兀的庆新婚。", "(同梅香下)。"]'),
('yuanqu-10954','赵匡义智娶符金锭・双调/新水令','无名氏','元','元曲','yuanqu','','[]','我虽是洞房无用的女妖娆，不错了圣人之道，夫妻是正理，休信外人教。',50,'元曲/yuanqu.json','["我虽是洞房无用的女妖娆，不错了圣人之道，夫妻是正理，休信外人教。", "不负了夜月花朝，当日个彩楼上众人闹。"]'),
('yuanqu-10955','赵匡义智娶符金锭・沈醉东风','无名氏','元','元曲','yuanqu','','[]','则听的聒耳笙歌闹吵，珍羞端的奇标。',110,'元曲/yuanqu.json','["则听的聒耳笙歌闹吵，珍羞端的奇标。", "新婚今日成，受了那我少闲焦燥，谢神天保护的便坚牢。", "(符彦卿云)多亏了妙计，今日才得成就也。", "(正旦唱)今日个夫妇团圆成就好。", "(郑恩云)小姐，这一场也多亏了我也。", "(正旦唱)多谢你个仁兄智巧。"]'),
('yuanqu-10956','赵匡义智娶符金锭・雁儿落','无名氏','元','元曲','yuanqu','','[]','情理这韩松使燥暴、脑背后都来到。',58,'元曲/yuanqu.json','["情理这韩松使燥暴、脑背后都来到。", "俺这里郑恩暗暗的藏，他那里不在声高高的闹。", "(赵弘殷云)他临后怎么去了来？(正旦唱)。"]'),
('yuanqu-10957','赵匡义智娶符金锭・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，打的是无处乱奔逃，那其间怒气怎生消。',88,'元曲/yuanqu.json','["呀，打的是无处乱奔逃，那其间怒气怎生消。", "才得今朝定，则他这将军个个劳。", "(符彦卿云)既亏了郑恩，俺慢慢的谢他也。", "(正旦唱)父亲你量度，便把他恩临报。", "郑恩你休焦，今日个婚姻已定了。"]'),
('yuanqu-10958','赵匡义智娶符金锭・沽美酒','无名氏','元','元曲','yuanqu','','[]','父亲你休动劳，你孩儿正当报，则因那养育三年将我这性命保。',42,'元曲/yuanqu.json','["父亲你休动劳，你孩儿正当报，则因那养育三年将我这性命保。", "指望终身待老，别离事在今朝。"]'),
('yuanqu-10959','赵匡义智娶符金锭・太平令','无名氏','元','元曲','yuanqu','','[]','多亏你个恩人说道，将亲事不错分毫。',267,'元曲/yuanqu.json','["多亏你个恩人说道，将亲事不错分毫。", "都则为韩松暴虐，将平人姻缘打落。", "(赵匡义云)夫妻皆是前定，岂他人能破的也呵。", "(正旦唱)呀，我这里说着，念着，笑倒，险些儿无着无落。", "(王朴云)今日个天下喜事，夫妻团圆。", "听我与您下断：您本是柴世忠良，一个个胆量高强。", "则因为赏春之景，来到你符氏门墙。", "赵匡义花下闲走，正见您年小红妆。", "既结下目前姻眷，搭彩楼招做新郎。", "有韩松依权挟势，遣官媒故意商量。", "恼犯了郑恩兄弟，施手段显耀刚强。", "诈妆做青春妇女，韩松见魂魄皆亡。", "今日个已成婚配，开筵会酒泛肴觞。", "赵匡义文武兼济，符金锭本性温良。", "今日个夫妻完备，一齐的拜谢吾皇。"]'),
('yuanqu-10960','正宫・鹦鹉曲','冯子振','元','元曲','yuanqu','','[]','序云：白无咎有〔鹦鹉曲〕云：“侬家鹦鹉洲边住，是个不识字渔父。',252,'元曲/yuanqu.json','["序云：白无咎有〔鹦鹉曲〕云：“侬家鹦鹉洲边住，是个不识字渔父。", "浪花中一叶扁舟，睡煞江南烟雨。", "觉来时满眼青山，抖擞绿蓑归去。", "算从前错怨天公，甚也有安排我处。", "”余壬寅岁留上京，有北京伶妇御园秀之属，相从风雪中，恨此曲无续之者。", "且谓前后多亲炙士大夫，拘于韵度，如第一个“父”字，便难下语；又“甚也有安排我处”，“甚”字必须去声字，“我”字必须上声字，音律始谐，不然不可歌，此一节又难下语。", "诸公举酒，索余和之，以汴、吴、上都、天京风景试续之。", "山亭逸兴嵯峨峰顶移家住，是个不唧溜樵父。", "烂柯时树老无花，叶叶枝枝风雨。"]'),
('yuanqu-10961','・故人曾唤我归来，却道不如休去。指门前万叠云山，是不费青蚨买处。荣华短梦','冯子振','元','元曲','yuanqu','','[]','幺朱门空宅无人住，村院快活煞耕父。',32,'元曲/yuanqu.json','["幺朱门空宅无人住，村院快活煞耕父。", "霎时间富贵虚花，落叶西风残雨。"]'),
('yuanqu-10962','・总不如水北相逢，一棹木兰舟去。待霜前雪后梅开，傍几曲寒潭浅处。愚翁放浪','冯子振','元','元曲','yuanqu','','[]','幺东家西舍随缘住，是个忒老实愚父。',32,'元曲/yuanqu.json','["幺东家西舍随缘住，是个忒老实愚父。", "赏花时暖薄寒轻，彻夜无风无雨。"]'),
('yuanqu-10963','・占长红小白园亭，烂醉不教人去。笑长安利锁名缰，定没个身心稳处。农夫渴雨','冯子振','元','元曲','yuanqu','','[]','幺年年牛背扶犁住，近日最懊恼杀农父。',33,'元曲/yuanqu.json','["幺年年牛背扶犁住，近日最懊恼杀农父。", "稻苗肥恰待抽花，渴煞青天雷雨。"]'),
('yuanqu-10964','幺・恨残霞不近人情，截断玉虹南去。望人间三尺甘霖，看一片闲云起处。燕南百五','冯子振','元','元曲','yuanqu','','[]','东风留得轻寒住，百五闹蝶母峰父。',31,'元曲/yuanqu.json','["东风留得轻寒住，百五闹蝶母峰父。", "好花枝半出墙头，几点清明微雨。"]'),
('yuanqu-10965','・绣弯弯湿透罗鞋，绮陌踏青回去。约明朝后日重来，靠浅紫深红暖处。故园归计','冯子振','元','元曲','yuanqu','','[]','幺重来京国多时住，恰做了白发伧父。',31,'元曲/yuanqu.json','["幺重来京国多时住，恰做了白发伧父。", "十年枕上家山，负我湘烟潇雨。"]'),
('yuanqu-10966','幺・','冯子振','元','元曲','yuanqu','','[]','断回肠一首阳关，早晚马头南去。',66,'元曲/yuanqu.json','["断回肠一首阳关，早晚马头南去。", "对吴山结个茅庵，画不尽西湖巧处。", "野渡新晴孤村三两人家住，终日对野叟田父。", "说今朝绿水平桥，昨日溪南新雨。"]'),
('yuanqu-10967','・碧天边云归岩穴，白鹭一行飞去。便芒鞋竹杖行春，问底是青帘舞处。渔父','冯子振','元','元曲','yuanqu','','[]','幺沙鸥滩鹭衤离依住，镇日坐钓叟纶父。',33,'元曲/yuanqu.json','["幺沙鸥滩鹭衤离依住，镇日坐钓叟纶父。", "趁斜阳晒网收竿，又是南风催雨。"]'),
('yuanqu-10968','幺・绿杨堤忘系孤桩，白浪打将船去。想明朝月落潮平，在掩映芦花浅处。市朝归兴','冯子振','元','元曲','yuanqu','','[]','山林朝市都曾住，忠孝两字报君父。',31,'元曲/yuanqu.json','["山林朝市都曾住，忠孝两字报君父。", "利名场反覆如云，又要商量阴雨。"]'),
('yuanqu-10969','・便天公有眼难开，袖手不如家去。更蛾眉强学时妆，是老子平生懒处。陆羽风流','冯子振','元','元曲','yuanqu','','[]','幺儿啼漂向波心住，舍得陆羽唤谁父？杜司空席上从容，点出茶瓯花雨。',32,'元曲/yuanqu.json','["幺儿啼漂向波心住，舍得陆羽唤谁父？杜司空席上从容，点出茶瓯花雨。"]'),
('yuanqu-10970','・散蓬莱两腋清风，未便玉川仙去。待中泠一滴分时，看满注黄金鼎处。顾渚紫笋','冯子振','元','元曲','yuanqu','','[]','幺春风阳羡微喧住，顾渚问苕叟吴父。',32,'元曲/yuanqu.json','["幺春风阳羡微喧住，顾渚问苕叟吴父。", "一枪旗紫笋灵芽，摘得和烟和雨。"]'),
('yuanqu-10971','・焙香时碾落云飞，纸上凤鸾衔去。玉皇前宝鼎亲尝，味恰到才情写处。园父','冯子振','元','元曲','yuanqu','','[]','幺柴门鸡犬山前住，笑语听伛背园父。',32,'元曲/yuanqu.json','["幺柴门鸡犬山前住，笑语听伛背园父。", "辘轳边抱瓮浇畦，点点阳春膏雨。"]'),
('yuanqu-10972','・菜花间蝶也飞来，又趁暖风双去。杏梢红韭嫩泉香，是老瓦盆边饮处。野客','冯子振','元','元曲','yuanqu','','[]','幺春归不恋风光住，向老拙问讯槎父。',32,'元曲/yuanqu.json','["幺春归不恋风光住，向老拙问讯槎父。", "叹匡山李白漂零，寂寞长安花雨。"]'),
('yuanqu-10973','・指沧溟铁网珊瑚，袖卷钓竿西去。锦袍空醉墨淋漓，是万古声名响处。城南秋思','冯子振','元','元曲','yuanqu','','[]','幺新凉时节城南住，灯火诵鲁国尼父。',32,'元曲/yuanqu.json','["幺新凉时节城南住，灯火诵鲁国尼父。", "到秋来宋玉生悲，不赋高唐云雨。"]'),
('yuanqu-10974','・一声声只在芭蕉，断送别离人去。甚河桥柳树全疏，恨正在长亭短处。赤壁怀古','冯子振','元','元曲','yuanqu','','[]','幺茅庐诸葛亲曾住，早赚出抱膝梁父。',33,'元曲/yuanqu.json','["幺茅庐诸葛亲曾住，早赚出抱膝梁父。", "笑谈间汉鼎三分，不记得南阳耕雨。"]'),
('yuanqu-10975','幺・叹西风卷尽豪华，往事大江东去。彻如今话说渔樵，算也是英雄了处。处士虚名','冯子振','元','元曲','yuanqu','','[]','高人谁恋朝中住，自古便有个巢父。',31,'元曲/yuanqu.json','["高人谁恋朝中住，自古便有个巢父。", "子陵滩钓得虚名，几度桐江春雨。"]'),
('yuanqu-10976','・睡神仙别有陈抟，拂袖华山归去。漫纷纷少室终南，怎不是神仙隐处？洞庭钓客','冯子振','元','元曲','yuanqu','','[]','幺年光流水何曾住，早忘却姓吕岩父。',32,'元曲/yuanqu.json','["幺年光流水何曾住，早忘却姓吕岩父。", "记蓬莱阆苑相逢，一别风流如雨。"]'),
('yuanqu-10977','・算人间碧海桑田，只似燕鸿来去。岳阳楼剑气凌云，度老树神仙此处。黄阁清风','冯子振','元','元曲','yuanqu','','[]','幺箕尾傅说商岩住，空桑子伊尹无父。',32,'元曲/yuanqu.json','["幺箕尾傅说商岩住，空桑子伊尹无父。", "汉萧何昴宿分英，李靖唐时行雨。"]'),
('yuanqu-10978','・出山来济了苍生，却卷白云闲去。一千年黄阁清风，是万古声名响处。夷门怀古','冯子振','元','元曲','yuanqu','','[]','幺人生只合梁园住，快活煞几个白头父。',33,'元曲/yuanqu.json','["幺人生只合梁园住，快活煞几个白头父。", "指他家五辈风流，睡足胭脂坡雨。"]'),
('yuanqu-10979','幺・说宣和锦片繁华，辇路看元宵去。马行街直转州桥，相国寺灯楼几处。都门感旧','冯子振','元','元曲','yuanqu','','[]','都门花月蹉跎住，恰做了白发伧父。',31,'元曲/yuanqu.json','["都门花月蹉跎住，恰做了白发伧父。", "酒微醒曲榭回廊，忘却天街酥雨。"]'),
('yuanqu-10980','・夏侯瞒智肖杨修，强说不多来去。怕文章泄漏风光，谜语到难开口处。兰亭手卷','冯子振','元','元曲','yuanqu','','[]','幺兰亭不肯昭陵住，老逸少是献之父。',33,'元曲/yuanqu.json','["幺兰亭不肯昭陵住，老逸少是献之父。", "过江来定武残碑，剥落元刂烟剜雨。"]'),
('yuanqu-10981','幺・纵新新茧纸临摹，乐事赏心俱去。永和年小草斜行，到野鹜家鸡窘处。庞隐图','冯子振','元','元曲','yuanqu','','[]','团栾话里禅龛住，灵昭女对老庞父。',32,'元曲/yuanqu.json','["团栾话里禅龛住，灵昭女对老庞父。", "利名心不挂丝毫，更肯沾风粘雨？。"]'),
('yuanqu-10982','・叹黄金散尽还家，逝水看流年去。只寻常卖簟篱休，这眷属今无讨处。拔宅冲升图','冯子振','元','元曲','yuanqu','','[]','幺淮南仙客蓬莱住，发漆黑变寻髯父。',32,'元曲/yuanqu.json','["幺淮南仙客蓬莱住，发漆黑变寻髯父。", "八公山九转丹成，洗尽腥风咸雨。"]'),
('yuanqu-10983','・想云霄犬吠鸡鸣，拔宅向青霄去。劝长安热客回头，镜影到流年老处。忆西湖','冯子振','元','元曲','yuanqu','','[]','幺吴侬生长西湖住，舣画舫听棹歌父。',31,'元曲/yuanqu.json','["幺吴侬生长西湖住，舣画舫听棹歌父。", "苏堤万柳春残，曲院风荷番雨。"]'),
('yuanqu-10984','幺・','冯子振','元','元曲','yuanqu','','[]','草萋萋一道腰裙，软绿断桥斜去。',64,'元曲/yuanqu.json','["草萋萋一道腰裙，软绿断桥斜去。", "判兴亡说向林逋，醉梅屋梅梢偃处。", "感事黄金难买朱颜住，驷马客羡跨牛父。", "石将军百斛明珠，几日欢云娱雨。"]'),
('yuanqu-10985','・趁春归一瞬流莺，万事夕阳西去。旧婵娟落在谁家？个里是高人省处。赠园父','冯子振','元','元曲','yuanqu','','[]','幺春光浓艳城南住，一叶价百倍园父。',32,'元曲/yuanqu.json','["幺春光浓艳城南住，一叶价百倍园父。", "牡丹台国色天香，锦幄无风无雨。"]'),
('yuanqu-10986','・惜花人不惜千金，一任蝶来蜂去。酒醒时月上三竿，是不是鸡声管处。感事','冯子振','元','元曲','yuanqu','','[]','幺江湖难比山林住，种果父胜刺船父。',32,'元曲/yuanqu.json','["幺江湖难比山林住，种果父胜刺船父。", "看春花又看秋花，不管颠风狂雨。"]'),
('yuanqu-10987','・尽人间白浪滔天，我自醉歌眠去。到中流手脚忙时，则靠着柴扉深处。买臣负薪手卷','冯子振','元','元曲','yuanqu','','[]','幺赭肩腰斧登山住，耐得苦是采薪父。',32,'元曲/yuanqu.json','["幺赭肩腰斧登山住，耐得苦是采薪父。", "乱云升急澍飞来，拗青松遮风雨。"]'),
('yuanqu-10988','・记年时雪断溪桥，脱度前湾归去。买臣妻富贵休休，气焰到寒灰舞处。燕南八景','冯子振','元','元曲','yuanqu','','[]','幺芦沟清绝霜晨住，步落月问倚阑父。',32,'元曲/yuanqu.json','["幺芦沟清绝霜晨住，步落月问倚阑父。", "蓟门东直下金台，仰看楼台飞雨。"]'),
('yuanqu-10989','・道陵前夕照苍茫，叠翠望居庸去。玉泉边一派西山，太液畔秋风紧处。松林','冯子振','元','元曲','yuanqu','','[]','幺山围行殿周遭住，万里客看牧羊父。',32,'元曲/yuanqu.json','["幺山围行殿周遭住，万里客看牧羊父。", "听神榆树北车声，满载松林寒雨。"]'),
('yuanqu-10990','・应昌南旧日长城，带取上京愁去。又秋风落雁归鸿，怎说到无言语处。至上京','冯子振','元','元曲','yuanqu','','[]','幺澶河西北征鞍住，古道上不见耕父。',32,'元曲/yuanqu.json','["幺澶河西北征鞍住，古道上不见耕父。", "白茫茫细草平沙，日日金莲川雨。"]'),
('yuanqu-10991','・李陵台往事休休，万里汉长城去。趁燕南落叶归来，怕迤<辶里>飞狐冷处。忆鸡鸣山旧游','冯子振','元','元曲','yuanqu','','[]','幺鸡鸣山下荒丘住，客吊古问驿亭父。',32,'元曲/yuanqu.json','["幺鸡鸣山下荒丘住，客吊古问驿亭父。", "几何年野屋丛祠，灭没犁烟锄雨。"]'),
('yuanqu-10992','・默寻思半晌无言，逆旅又催人去。指峰前代妤磨笄，是血泪当时洒处。南城赠丹砂道伴','冯子振','元','元曲','yuanqu','','[]','幺长松苍鹤相依住，骨老健称褐衣父。',32,'元曲/yuanqu.json','["幺长松苍鹤相依住，骨老健称褐衣父。", "坐烧丹忘记春秋，自在溪风山雨。"]'),
('yuanqu-10993','・有人来不问亲疏，淡饭一杯茶去。要茅檐卧看闲云，梅影转幽窗雅处。别意','冯子振','元','元曲','yuanqu','','[]','幺花骢嘶断留侬住，满酌酒劝据鞍父。',32,'元曲/yuanqu.json','["幺花骢嘶断留侬住，满酌酒劝据鞍父。", "柳青青万里初程，点染阳关朝雨。"]'),
('yuanqu-10994','幺・梦回时不见犀梳，燕子又衔春去。便人间月缺花残，是小小香魂断处。','冯子振','元','元曲','yuanqu','','[]','溪山小景长绳短系虚名住，倾浊酒劝邻父。',34,'元曲/yuanqu.json','["溪山小景长绳短系虚名住，倾浊酒劝邻父。", "草亭前矮树当门，画出轻烟疏雨。"]'),
('yuanqu-10995','幺・','冯子振','元','元曲','yuanqu','','[]','看燕南陌上红尘，马耳北风吹去。',65,'元曲/yuanqu.json','["看燕南陌上红尘，马耳北风吹去。", "一年年月夜花朝，自占取溪山好处。", "四皓屏张良更姓圯桥住，夜待旦遇个师父。", "一编书不为封留，字字咸阳膏雨。"]'),
('yuanqu-10996','・借箸筹灭项兴刘，到底学神仙去。待商山四皓还山，再不恋人间险处。','冯子振','元','元曲','yuanqu','','[]','幺逃吴辞楚无家住，解宝剑赠津父。',31,'元曲/yuanqu.json','["幺逃吴辞楚无家住，解宝剑赠津父。", "十年间隶越鞭荆，怒卷秋江潮雨。"]'),
('yuanqu-10997','幺・','冯子振','元','元曲','yuanqu','','[]','想空城组练三千，白马素车回去。',62,'元曲/yuanqu.json','["想空城组练三千，白马素车回去。", "又逡巡月上波平，暮色在烟光紫处。", "青衫司马江州住，月夜笛厌听村父。", "甚有传旧谱琵琶，切切嘈嘈檐雨。"]'),
('yuanqu-10999','中吕・红绣鞋题小山苏堤渔唱','冯子振','元','元曲','yuanqu','','[]','东里先生酒兴，南州高士文声，玉龙嘶断彩鸾鸣。',40,'元曲/yuanqu.json','["东里先生酒兴，南州高士文声，玉龙嘶断彩鸾鸣。", "水空秋月冷，山小暮天青，苏公堤上景。"]'),
('yuanqu-11000','尾・意无聊，愁无限，花落也莺慵燕懒。两地相思会面难，上危楼凭暖雕','高安道','元','元曲','yuanqu','','[]','畅心烦，盼杀人也秋水春山！几时看宝髻蓬松云乱绾？怕的是樽空酒阑，月斜人散，背银灯偷把泪珠弹。',46,'元曲/yuanqu.json','["畅心烦，盼杀人也秋水春山！几时看宝髻蓬松云乱绾？怕的是樽空酒阑，月斜人散，背银灯偷把泪珠弹。"]'),
('yuanqu-11001','般涉调・哨遍嗓淡行院','高安道','元','元曲','yuanqu','','[]','暖日和风清昼，茶馀饭饱斋时候。',112,'元曲/yuanqu.json','["暖日和风清昼，茶馀饭饱斋时候。", "自汉抱官囚，被名缰牵挽无休。", "寻故友，出来的衣冠济楚，像儿端严，一个个特清秀，都向门前等候。", "待去歌楼作乐，散闷消愁。", "倦游柳陌恋烟花，且向棚阑玩俳优。", "赏一会妙舞清歌，瞅一会皓齿明眸，躲一会闲茶浪酒。"]'),
('yuanqu-11002','耍孩儿・诧跋的单脚实村纣，呼喝的扌且扌来每叫吼。瞅粘的绿老更昏花，','高安道','元','元曲','yuanqu','','[]','把棚的莽壮真牛。',55,'元曲/yuanqu.json','["把棚的莽壮真牛。", "吹笛的把瑟歪着尖嘴，擂鼓的撅丁瘤着左手，撩打的腔腔嗽。", "靠棚头的先虾着脊背，卖薄荷的自肿了咽喉。"]'),
('yuanqu-11003','七煞・坐排场众女流，乐床上似兽头，栾睃来报是些十分丑。一个个青布','高安道','元','元曲','yuanqu','','[]','裙紧紧的兜着奄老，皂纱片深深的裹着额楼。',47,'元曲/yuanqu.json','["裙紧紧的兜着奄老，皂纱片深深的裹着额楼。", "棚上下把郎君溜，喝破子把腔儿莽诞，打讹的将纳老胡风彡。"]'),
('yuanqu-11004','六・撺断的昏撒多，主张的自吸溜，几曾见双撮泥金袖。可怜虱虮沿肩甲，','高安道','元','元曲','yuanqu','','[]','犹道珍珠络臂耩。',31,'元曲/yuanqu.json','["犹道珍珠络臂耩。", "四翩儿乔弯纽，甚实曾官梅点额，谁肯将蜀锦缠头。"]'),
('yuanqu-11005','三・妆旦不抹风彡，蠢身躯似水牛，嗓暴如恰哑了孤桩狗。带冠梳硬挺着','高安道','元','元曲','yuanqu','','[]','粗脖项，恰掌记光舒着黑指头。',34,'元曲/yuanqu.json','["粗脖项，恰掌记光舒着黑指头。", "肋额的相迤逗，写着道翩跹舞态，宛转歌喉。"]'),
('yuanqu-11006','一・打散的队子排，待将回数收，搽灰抹土胡亻孱亻愁。淡翻东瓦来西瓦，','高安道','元','元曲','yuanqu','','[]','却甚放走南州共北州。',30,'元曲/yuanqu.json','["却甚放走南州共北州。", "凹了也难收救，四边厢土糁，八下里砖风彡。"]'),
('yuanqu-11007','尾・梁园中可惯经，桑园里串的熟。似兀的武光头、刘色长、曹娥秀，则','高安道','元','元曲','yuanqu','','[]','索赶科地沿村转疃走。',113,'元曲/yuanqu.json','["索赶科地沿村转疃走。", "皮匠说谎十载寒窗诚意，书生皆想登科记。", "奈时运未亨通，混尘嚣日日衔杯，厮伴着青云益友。", "谈笔忘机，出语无俗气。", "偶题起老成靴脚，人人道好，个个称奇。", "若要做四缝磕瓜头，除是南街小王皮。", "快做能裁，着脚中穿，在城第一。"]'),
('yuanqu-11008','七煞・探头休蹴尖，衬薄怕汗湿。减刮的休显刀痕迹，剜裁的脸戏儿微分','高安道','元','元曲','yuanqu','','[]','间短，拢揎得腮帮儿省可里肥。',31,'元曲/yuanqu.json','["间短，拢揎得腮帮儿省可里肥。", "要着脚随人意，休教脑窄，莫得趺低。"]'),
('yuanqu-11009','六・丁宁说了一回，分明听了半日，交付与价钞先伶俐。从前名誉休多说，','高安道','元','元曲','yuanqu','','[]','今后生活便得知。',25,'元曲/yuanqu.json','["今后生活便得知。", "限三日穿新的，您休说谎，俺不催逼。"]'),
('yuanqu-11010','四・几番煨胶锅借揎头，数遍粘主根买桦皮，喷了水埋在糠糟内。今朝取','高安道','元','元曲','yuanqu','','[]','了明朝取，早又催来晚又催。',38,'元曲/yuanqu.json','["了明朝取，早又催来晚又催。", "怕越了靴行例，见天阴道胶水解散，恰天晴说皮糙ㄡ黧。"]'),
('yuanqu-11011','三・走的来不发心，ㄡ的方见次第，计数儿算有三千个誓。迷奚着谎眼先','高安道','元','元曲','yuanqu','','[]','陪笑，执闭着顽心更道易。',27,'元曲/yuanqu.json','["陪笑，执闭着顽心更道易。", "巴的今日，罗街拽巷，唱叫扬疾。"]'),
('yuanqu-11012','二・好一场恶一场，哭不得笑不得，软厮禁硬厮拼却不济。调脱空对众攀','高安道','元','元曲','yuanqu','','[]','今古，念条款依然说是非。',32,'元曲/yuanqu.json','["今古，念条款依然说是非。", "难回避，骷髅卦几番自说，猫狗砌数遍亲题。"]'),
('yuanqu-11013','一・又不是凤麒麟钩绊着缝，又不是鹿衔花窟嵌着刺，又不是倒钩针背衬','高安道','元','元曲','yuanqu','','[]','上加些功绩，又不是三垂云银线分花样，又不是一抹圈金沿宝里。',49,'元曲/yuanqu.json','["上加些功绩，又不是三垂云银线分花样，又不是一抹圈金沿宝里。", "每日闲淘气，子索行监坐守，谁敢东走西移。"]'),
('yuanqu-11014','尾・初言定正月终，调发到十月一。新靴子投至能够完备，旧兀刺先磨了','高安道','元','元曲','yuanqu','','[]','半截底。',4,'元曲/yuanqu.json','["半截底。"]'),
('yuanqu-11015','邯郸道省悟黄粱梦・混江龙','马致远','元','元曲','yuanqu','','[]','当日个曾逢关尹，至今遗下五千文。',101,'元曲/yuanqu.json','["当日个曾逢关尹，至今遗下五千文。", "大刚来玄虚为本，清净为门。", "虽然是草舍茅庵一道士，伴着这清风明月两闲人。", "也不知甚的秋，甚的春，甚的汉，甚的秦，长则是习疏狂、躯懒散、佯妆钝，把些个人间富贵，都做了眼底浮云。"]'),
('yuanqu-11016','邯郸道省悟黄粱梦・油葫芦','马致远','元','元曲','yuanqu','','[]','莫厌追欢笑语频，但开怀好会宾，寻思离乱可伤神。',71,'元曲/yuanqu.json','["莫厌追欢笑语频，但开怀好会宾，寻思离乱可伤神。", "俺闲遥遥独自林泉隐，你虚飘飘半纸功名进。", "你看这紫塞军、黄阁臣，几时得个安闲分，怎如我物外自由身。"]'),
('yuanqu-11017','邯郸道省悟黄粱梦・天下乐','马致远','元','元曲','yuanqu','','[]','他每得到清平有几人，何不早抽身，出世尘，尽白云满溪锁洞门，将一函经手自翻，一垆香手自焚。',53,'元曲/yuanqu.json','["他每得到清平有几人，何不早抽身，出世尘，尽白云满溪锁洞门，将一函经手自翻，一垆香手自焚。", "这的是清闲真道本。"]'),
('yuanqu-11018','邯郸道省悟黄粱梦・金盏儿','马致远','元','元曲','yuanqu','','[]','上昆仑，摘星辰，觑东洋海则是一掬寒泉滚，泰山一捻细微尘。',52,'元曲/yuanqu.json','["上昆仑，摘星辰，觑东洋海则是一掬寒泉滚，泰山一捻细微尘。", "天高三二寸，地厚一鱼鳞，抬头天外觑，无我一般人。"]'),
('yuanqu-11019','邯郸道省悟黄粱梦・后庭花','马致远','元','元曲','yuanqu','','[]','我驱的是六丁六甲神，七星七曜君。',53,'元曲/yuanqu.json','["我驱的是六丁六甲神，七星七曜君。", "食紫芝草千年寿，看碧桃花几度春。", "常则是醉醺醺、高谈阔论，来往的尽是天上人。"]'),
('yuanqu-11020','邯郸道省悟黄粱梦・醉中天','马致远','元','元曲','yuanqu','','[]','俺那里自泼村醪嫩，自折野花新。',53,'元曲/yuanqu.json','["俺那里自泼村醪嫩，自折野花新。", "独对青山酒一尊，闲将那朱顶仙鹤引。", "醉归去松阴满身，冷然风韵，铁笛声吹断云根。"]'),
('yuanqu-11021','邯郸道省悟黄粱梦・金盏儿','马致远','元','元曲','yuanqu','','[]','俺那里地无尘，草长春，四时花发常娇嫩。',56,'元曲/yuanqu.json','["俺那里地无尘，草长春，四时花发常娇嫩。", "更那翠屏般山色对柴门，雨滋棕叶润，露养药苗新。", "听野猿啼古树，看流水绕孤村。"]'),
('yuanqu-11022','邯郸道省悟黄粱梦・醉雁儿','马致远','元','元曲','yuanqu','','[]','你有那出世超凡神仙分，击一条一抹绦，带一顶九阳巾。',164,'元曲/yuanqu.json','["你有那出世超凡神仙分，击一条一抹绦，带一顶九阳巾。", "君，敢着你做真人。", "(洞宾云)俺为官的，身穿锦缎轻纱，口食香甜美味。", "你出家人草履麻绦，餐松啖柏，有甚么好处？(正末云)功名二字，如同那百尺高竿上调把戏一般，性命不保，脱不得酒色财气这四般儿。", "笛悠悠，鼓冬冬，人闹吵，在虚空。", "怎如的平地上来，平地上去，无灾无祸，可不自在多哩。", "(唱)。"]'),
('yuanqu-11023','邯郸道省悟黄粱梦・后庭花','马致远','元','元曲','yuanqu','','[]','酒恋清香疾病因，色爱荒淫患难根；财贪富贵伤残命，气竞刚强损隐身。',55,'元曲/yuanqu.json','["酒恋清香疾病因，色爱荒淫患难根；财贪富贵伤残命，气竞刚强损隐身。", "这四件儿不饶人。", "你若是将他断尽，便神仙有几分。"]'),
('yuanqu-11024','邯郸道省悟黄粱梦・醉中天','马致远','元','元曲','yuanqu','','[]','假饶你手段欺韩信，舌辩赛苏秦，到底个功名由命不由人，也未必能拿准。',63,'元曲/yuanqu.json','["假饶你手段欺韩信，舌辩赛苏秦，到底个功名由命不由人，也未必能拿准。", "只不如苦志修行谨慎，早图个灵丹腹孕，索强似你跨青驴踯躅风尘。"]'),
('yuanqu-11025','邯郸道省悟黄粱梦・一半儿','马致远','元','元曲','yuanqu','','[]','如今人宜假不宜真，则敬衣衫不敬人。',42,'元曲/yuanqu.json','["如今人宜假不宜真，则敬衣衫不敬人。", "题起修行耳怕闻，直恁的没精神，一半儿应承一半儿盹。"]'),
('yuanqu-11026','邯郸道省悟黄粱梦・金盏儿','马致远','元','元曲','yuanqu','','[]','比及你米淘了尘，水烧的滚，我教这一颗米内藏时运，半升铛里煮乾坤。',63,'元曲/yuanqu.json','["比及你米淘了尘，水烧的滚，我教这一颗米内藏时运，半升铛里煮乾坤。", "投至得黄粱炊未熟，他清梦思犹昏，我教他江山重改换，日月一番新。"]'),
('yuanqu-11027','邯郸道省悟黄粱梦・赚煞','马致远','元','元曲','yuanqu','','[]','羽衣轻，霓旌迅，有十二金童接引。',280,'元曲/yuanqu.json','["羽衣轻，霓旌迅，有十二金童接引。", "万里天风归路稳，向蓬莱顶上朝真。", "笑欣欣。", "袖拂白云，宴罢瑶池酒半醺。", "争奈你个唐吕岩性蠢，偏不肯受汉钟离教训，又则索跨苍鸾飞上九天门。", "(下)(洞宾梦上，云)兀那王婆，那先生去了也。", "(王婆云)去久了。", "(洞宾云)饭熟也未？(王婆云)还饶一把火儿。", "(洞宾云)王婆，我也等不的你那饭了，误了我程途。", "我上的蹇驴，便索长行去也。", "(下)(王婆云)吕岩去了也。", "他那里知道我非凡人，乃骊山老母一化。", "上仙法旨，着吕岩看破了酒色财气，人我是非，那其间才得返本朝元，重回正道。", "(诗云)汉钟离点化玄机，度吕岩省悟心回。", "待此人功成行满，同共赴阆苑瑶池。", "(下)。"]'),
('yuanqu-11028','邯郸道省悟黄粱梦・仙吕/赏花时','马致远','元','元曲','yuanqu','','[]','则我是皓首苍颜高太尉，别无甚亲人则觑着你。',40,'元曲/yuanqu.json','["则我是皓首苍颜高太尉，别无甚亲人则觑着你。", "儿幼小女娇痴，想为人在世，最苦是生离。"]'),
('yuanqu-11029','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','满饮阳关酒一杯。',163,'元曲/yuanqu.json','["满饮阳关酒一杯。", "(洞宾做吐科，云)您孩儿吃不得了，心中有些不好，吐了两口血。", "这酒元来伤人。", "您孩儿再也不吃这酒了。", "(高太尉云)既是伤着你心，再也休吃这酒罢。", "(洞宾云)父亲放心，您孩儿不吃了，辞别父亲，便索长行。", "(高太尉云)你休忘了我的言语，着心记者。", "(唱)则要你在意扶持唐社稷，嘱付了又重题。", "但愿的功成破敌，早唱凯歌回。", "(下)。"]'),
('yuanqu-11030','邯郸道省悟黄粱梦・醋葫芦','马致远','元','元曲','yuanqu','','[]','又不是别人相唬吓、厮展赖，是你男儿亲自撞将来。',52,'元曲/yuanqu.json','["又不是别人相唬吓、厮展赖，是你男儿亲自撞将来。", "你浑身是口难分解，赤紧的并脏拿贼，你看他死临侵不敢把头抬。"]'),
('yuanqu-11031','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','你男儿有八面威，七步才，现带着征西金印虎头牌。',90,'元曲/yuanqu.json','["你男儿有八面威，七步才，现带着征西金印虎头牌。", "他在那长朝殿前班部里摆。", "你教他把屎盆儿顶戴，兀的不屈沉杀了拜将筑坛台。", "(云)老汉有甚么面皮？大人，可怜见一双儿女，饶过夫人者。", "(唱)。"]'),
('yuanqu-11032','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','大人见义为，夫人知过改。',48,'元曲/yuanqu.json','["大人见义为，夫人知过改。", "不是中间老汉厮支划，若是外人知道来，休恁的大惊小怪。", "丑名儿出去怎生揩！。"]'),
('yuanqu-11033','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','问甚你夫妻好共歹，觑孩儿瘦更呆，便怎生教碜可可血泊里倘着尸骸？男子汉那一个不妒色。',76,'元曲/yuanqu.json','["问甚你夫妻好共歹，觑孩儿瘦更呆，便怎生教碜可可血泊里倘着尸骸？男子汉那一个不妒色。", "(带云)不争夫人死呵！(唱)枉乞两的两个小冤家不快，那凄凉日月索耽捱。"]'),
('yuanqu-11034','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','我见他掩了泪眼，改了面色，笑靥儿攒破旱莲腮，直从那针关儿透得命到来，恰便似九霄云外，滴溜溜飞下一纸赦书来。',53,'元曲/yuanqu.json','["我见他掩了泪眼，改了面色，笑靥儿攒破旱莲腮，直从那针关儿透得命到来，恰便似九霄云外，滴溜溜飞下一纸赦书来。"]'),
('yuanqu-11035','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','朝廷将使命差，前厅上把圣旨开。',55,'元曲/yuanqu.json','["朝廷将使命差，前厅上把圣旨开。", "道是西边上卖阵走回来。", "谁教你贪心爱他不义财。", "今日个脱空须败，恶支沙将这等罪名揣。"]'),
('yuanqu-11036','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','也是你慈悲生患害，俺哥哥除死无大灾。',136,'元曲/yuanqu.json','["也是你慈悲生患害，俺哥哥除死无大灾。", "何须你畅叫厮花白。", "(旦儿云)我是高太尉女儿，养汉来，养汉来。", "如今你休了我，谁管的我？(正末唱)闹垓垓幺喝十字街。", "(带云)他今日声声说是高太尉女儿养汉来。", "(唱)直恁的恶叉白赖，婆娘家情性恁般乖。", "(解子云)去罢，误了程限到几时。", "(正末唱)。"]'),
('yuanqu-11037','邯郸道省悟黄粱梦・后庭花','马致远','元','元曲','yuanqu','','[]','我则见飕飕的枷棒摔，打的他纷纷的皮肉开。',77,'元曲/yuanqu.json','["我则见飕飕的枷棒摔，打的他纷纷的皮肉开。", "见他可擦擦拖将去，我与你气丕丕赶上来。", "痛哀哉，身遭残害，他如何敢挣扎。", "我其实无百刂划，平白地招罪责，从今日离院宅。"]'),
('yuanqu-11038','邯郸道省悟黄粱梦・双雁儿','马致远','元','元曲','yuanqu','','[]','哥哥也恰如赵杲送灯台，便道不的。',47,'元曲/yuanqu.json','["哥哥也恰如赵杲送灯台，便道不的。", "山河易改。", "恁时节和尚在钵盂在，今日个、福气衰，看何时、冤业解。"]'),
('yuanqu-11039','邯郸道省悟黄粱梦・随调煞','马致远','元','元曲','yuanqu','','[]','好教我回去艰难，谁似你步行的快。',81,'元曲/yuanqu.json','["好教我回去艰难，谁似你步行的快。", "望不见。", "走上望高台，空目断一天残照霭。", "不知俺哥哥安在？(做叫科云)哥哥！(洞宾远应科)(正末唱)看时节隔疏林风送过哭声来。", "(下)。"]'),
('yuanqu-11040','邯郸道省悟黄粱梦・大石调/六国朝','马致远','元','元曲','yuanqu','','[]','风吹羊角，雪剪鹅毛，飞六出海山白，冻一壶天地老。',79,'元曲/yuanqu.json','["风吹羊角，雪剪鹅毛，飞六出海山白，冻一壶天地老。", "便有丹青巧，画笔难描。", "俺这里遥望千山表，是谁将粉黛扫？幽窗下寒敲竹叶，前村里冷压梅梢。", "撩乱野云低，微茫江树杳。"]'),
('yuanqu-11041','邯郸道省悟黄粱梦・归塞北','马致远','元','元曲','yuanqu','','[]','为甚春归早，既不沙可怎生蝶翅舞飘飘？梅蕊粉填合长安道。',42,'元曲/yuanqu.json','["为甚春归早，既不沙可怎生蝶翅舞飘飘？梅蕊粉填合长安道。", "柳花绵迷却灞陵桥。", "山馆酒旗遥。"]'),
('yuanqu-11042','邯郸道省悟黄粱梦・初问口','马致远','元','元曲','yuanqu','','[]','想那捕鱼叟蓑笠纶竿，他向那寒潭独钓，和俺这采樵人迷却归来道。',54,'元曲/yuanqu.json','["想那捕鱼叟蓑笠纶竿，他向那寒潭独钓，和俺这采樵人迷却归来道。", "则见冻雀又飞，寒鸦又噪，古木林中蓦听的山犭员叫。"]'),
('yuanqu-11043','邯郸道省悟黄粱梦・怨别离','马致远','元','元曲','yuanqu','','[]','园林无处不萧条，春归也犹未觉。',45,'元曲/yuanqu.json','["园林无处不萧条，春归也犹未觉。", "满地梨花无人扫。", "寒料峭，遥望见一点青山，兀良、却又早不见了。"]'),
('yuanqu-11044','邯郸道省悟黄粱梦・归塞北','马致远','元','元曲','yuanqu','','[]','白云岛，则听得孤鬼吼荒郊。',44,'元曲/yuanqu.json','["白云岛，则听得孤鬼吼荒郊。", "九天女鼓风驱造化，六丁神挥剑斩长蛟。", "既不沙，可怎生就地卷风涛。"]'),
('yuanqu-11045','邯郸道省悟黄粱梦・幺篇','马致远','元','元曲','yuanqu','','[]','孤村晓，稚子道犹自月明高。',118,'元曲/yuanqu.json','["孤村晓，稚子道犹自月明高。", "青女翦冰寒不散，黑云喷雨冻难消，无处觅渔樵。", "(洞宾云)孩儿行动些。", "如此大风大雪，又迷踪失路，眼见的是死人也。", "(做椎胸科，云)天口乐！这雪住一住可也好，越下的恶躁了。", "(正末云)这来的是吕岩，可也该省悟了。", "(唱)。"]'),
('yuanqu-11046','邯郸道省悟黄粱梦・擂鼓体','马致远','元','元曲','yuanqu','','[]','那先生浩歌拍手舞黄鹤，家住瑶池阆苑，十洲三岛。',68,'元曲/yuanqu.json','["那先生浩歌拍手舞黄鹤，家住瑶池阆苑，十洲三岛。", "一曲横笛秋气高，数着残棋江月晓。", "(洞宾云)哥哥，那先生是出家人，怎生有这本事？(正末唱)。"]'),
('yuanqu-11047','邯郸道省悟黄粱梦・归塞北','马致远','元','元曲','yuanqu','','[]','那先生服的是长生药，不许外人学。',70,'元曲/yuanqu.json','["那先生服的是长生药，不许外人学。", "三弄琴声弹落叶，九重春色醉仙桃，白日上青霄。", "(洞宾云)敢问哥哥，那先生是怎生模样，你再说一遍咱。", "(正末唱)。"]'),
('yuanqu-11048','邯郸道省悟黄粱梦・净瓶儿','马致远','元','元曲','yuanqu','','[]','那先生两手摇山岳，一对眼瞅邪妖。',94,'元曲/yuanqu.json','["那先生两手摇山岳，一对眼瞅邪妖。", "剑挥星斗，胸卷江涛。", "天教恶相貌，伏的虎，降的龙，德行高。", "他则是个活神道，也曾跨苍鸾亲把玉皇朝。", "(云)君子，你过的山崦儿，你望见团标，你问那先生路去。", "(唱)。"]'),
('yuanqu-11049','邯郸道省悟黄粱梦・玉翼蝉煞','马致远','元','元曲','yuanqu','','[]','那先生自舞自歌，吃的是仙酒仙桃，住的是草舍茅庵，强如龙楼凤阁。',241,'元曲/yuanqu.json','["那先生自舞自歌，吃的是仙酒仙桃，住的是草舍茅庵，强如龙楼凤阁。", "白云不扫，苍松自老；青山围绕，淡烟笼罩。", "黄精自饱，灵丹自烧。", "崎岖峪道，凹答岩壑；门无绰楔，洞无销钥；香焚石桌，笛吹古调；云黯黯，水迢迢，风凛凛，雪飘飘，柴门静，竹篱牢。", "过了那峻岭尖峰，曲涧寒泉，长林茂草，便望见那幽雅仙庄，这些是道。", "(带云)君子，你休迷了正道。", "你听者，(唱)你可也休错去了。", "(下)(洞宾云)孩儿也，你才听的那哥哥说来，兀那山崦里有一家人家，吃的也有，穿的也有，宿处也有。", "咱直到那里觅一宵宿去来。", "(同下)。"]'),
('yuanqu-11050','邯郸道省悟黄粱梦・滚绣球','马致远','元','元曲','yuanqu','','[]','寻思来，那快活，这半月多遇几个滥官员经过，打动下些金银段匹绫罗。',90,'元曲/yuanqu.json','["寻思来，那快活，这半月多遇几个滥官员经过，打动下些金银段匹绫罗。", "昨日共那几个，今日共这一火。", "从不曾离了侧坐，仰天的大笑呵呵。", "将那泼醅酒虢虢连糟咽，杀人剑蚩蚩带血磨。", "常则是烂醉无何。"]'),
('yuanqu-11051','邯郸道省悟黄粱梦・倘秀才','马致远','元','元曲','yuanqu','','[]','我为贼盗呵杀人放火，不似你贪财呵披枷带锁。',47,'元曲/yuanqu.json','["我为贼盗呵杀人放火，不似你贪财呵披枷带锁。", "你得了斗来大黄金印一颗，为元帅、佐山河，倒大来显豁。"]'),
('yuanqu-11052','邯郸道省悟黄粱梦・滚绣球','马致远','元','元曲','yuanqu','','[]','你那罪过，怎过活，做的来实难结末，自揽下千丈风波。',117,'元曲/yuanqu.json','["你那罪过，怎过活，做的来实难结末，自揽下千丈风波。", "谁教你向界河，受财货，将咱大军折挫？似这等不义财贪得如何，道不的\"殷勤过日灾须少，侥幸成家祸必多\"，枉了张罗。", "(洞宾云)不好了，我不问那里逃命去来。", "(正末仗剑赶洞宾。", "躲科)(正末唱)。"]'),
('yuanqu-11053','邯郸道省悟黄粱梦・倘秀才','马致远','元','元曲','yuanqu','','[]','你早则省得浮世风灯石火，再休恋儿女神珠玉颗。',51,'元曲/yuanqu.json','["你早则省得浮世风灯石火，再休恋儿女神珠玉颗。", "咱人百岁光阴有几何，端的日月去、似撺梭。", "想你那受过的坎坷。"]'),
('yuanqu-11054','邯郸道省悟黄粱梦・煞尾','马致远','元','元曲','yuanqu','','[]','你正果正是修行果，你灾咎皆因我度脱。',90,'元曲/yuanqu.json','["你正果正是修行果，你灾咎皆因我度脱。", "早则绝忧愁、没恼聒，行处行，坐处坐，闲处闲，陀处陀。", "屈着指，自数过，真神仙，是七座，添伊家，总八个。", "道与哥哥，非是风魔，这个爱吃酒的钟离便是我。"]'),
('yuanqu-11055','仙吕・后庭花拟古','邵亨贞','元','元曲','yuanqu','','[]','铜壶更漏残，红汝春梦阑。',79,'元曲/yuanqu.json','["铜壶更漏残，红汝春梦阑。", "江上花无语，天涯人未还。", "倚楼闲，月明千里，隔江何处山？刺船鹦鹉洲，题诗黄鹤楼。", "金谷铜驼梦，湘云楚水愁。", "少年游，好怀依旧，故人还在不？。"]'),
('yuanqu-11056','越调・凭阑人题曹云西翁赠妓小画','邵亨贞','元','元曲','yuanqu','','[]','谁写江南一段秋，妆点钱塘苏小楼？楼中多少愁！楚山无断头。',28,'元曲/yuanqu.json','["谁写江南一段秋，妆点钱塘苏小楼？楼中多少愁！楚山无断头。"]'),
('yuding-0','帝京篇十首','李世民','唐','御定全唐诗','yuding','','[]','秦川雄帝宅，函谷壯皇居。綺殿千尋起，離宮百雉餘。',528,'御定全唐詩/json/001.json','["秦川雄帝宅，函谷壯皇居。綺殿千尋起，離宮百雉餘。", "連薨遙接漢，飛觀迥淩虛。雲日隱層闕，風煙出綺疏。", "岩廊罷機務，崇文聊駐輦。玉匣啟龍圖，金繩披鳳篆。", "韋編斷仍續，縹帙舒還卷。對此乃淹留，欹案觀墳典。", "移步出詞林，停輿欣武宴。雕弓寫明月，駿馬疑流電。", "驚雁落虛弦，啼猿悲急箭。閱賞誠多美，於茲乃忘倦。", "鳴笳臨樂館，眺聽歡芳節。急管韻朱弦，清歌凝白雪。", "彩鳳肅來儀，玄鶴紛成列。去茲鄭衛聲，雅音方可悅。", "芳辰追逸趣，禁苑信多奇。橋形通漢上，峰勢接雲危。", "煙霞交隱映，花鳥自參差。何如肆轍跡，萬里賞瑤池。", "飛蓋去芳園，蘭橈遊翠渚。萍間日彩亂，荷處香風舉。", "桂楫滿中川，弦歌振長嶼。豈必汾河曲，方為歡宴所。", "落日雙闕昏，回輿九重暮。長煙散初碧，皎月澄輕素。", "搴幌玩琴書，開軒引雲霧。斜漢耿層閣，清風搖玉樹。", "歡樂難再逢，芳辰良可惜。玉酒泛雲罍，蘭殽陳綺席。", "千鐘合堯禹，百獸諧金石。得志重寸陰，忘懷輕尺璧。", "建章歡賞夕，二八盡妖妍。羅綺昭陽殿，芬芳玳瑁筵。", "佩移星正動，扇掩月初圓。無勞上懸圃，即此對神仙。", "以茲遊觀極，悠然獨長想。披卷覽前蹤，撫躬尋既往。", "望古茅茨約，瞻今蘭殿廣。人道惡高危，虛心戒盈蕩。", "奉天竭誠敬，臨民思惠養。納善察忠諫，明科慎刑賞。", "六五誠難繼，四三非易仰。廣待淳化敷，方嗣雲亭響。"]'),
('yuding-1','飲馬長城窟行','李世民','唐','御定全唐诗','yuding','','[]','塞外悲風切，交河冰已結。瀚海百重波，陰山千里雪。',120,'御定全唐詩/json/001.json','["塞外悲風切，交河冰已結。瀚海百重波，陰山千里雪。", "迥戍危烽火，層巒引高節。悠悠卷旆旌，飲馬出長城。", "寒沙連騎跡，朔吹斷邊聲。胡塵清玉塞，羌笛韻金鉦。", "絕漠干戈戢，車徒振原隰。都尉反龍堆，將軍旋馬邑。", "揚麾氛霧靜，紀石功名立。荒裔一戎衣，靈台凱歌入。"]'),
('yuding-2','執契靜三邊','李世民','唐','御定全唐诗','yuding','','[]','執契靜三邊，持衡臨萬姓。玉彩輝關燭，金華流日鏡。',240,'御定全唐詩/json/001.json','["執契靜三邊，持衡臨萬姓。玉彩輝關燭，金華流日鏡。", "無為宇宙清，有美璿璣正。皎佩星連景，飄衣雲結慶。", "戢武耀七德，升文輝九功。煙波澄舊碧，塵火息前紅。", "霜野韜蓮劍，關城罷月弓。錢綴榆天合，新城柳塞空。", "花銷蔥嶺雪，縠盡流沙霧。秋駕轉兢懷，春冰彌軫慮。", "書絕龍庭羽，烽休鳳穴戍。衣宵寢二難，食旰餐三懼。", "翦暴興先廢，除凶存昔亡。圓蓋歸天壤，方輿入地荒。", "孔海池京邑，雙河沼帝鄉。循躬思勵己，撫俗愧時康。", "元首佇鹽梅，股肱惟輔弼。羽賢崆嶺四，翼聖襄城七。", "澆俗庶反淳，替文聊就質。已知隆至道，共歡區宇一。"]'),
('yuding-3','正日臨朝','李世民','唐','御定全唐诗','yuding','','[]','條風開獻節，灰律動初陽。百蠻奉遐贐，萬國朝未央。',96,'御定全唐詩/json/001.json','["條風開獻節，灰律動初陽。百蠻奉遐贐，萬國朝未央。", "雖無舜禹跡，幸欣天地康。車軌同八表，書文混四方。", "赫奕儼冠蓋，紛綸盛服章。羽旄飛馳道，鐘鼓震岩廊。", "組練輝霞色，霜戟耀朝光。晨宵懷至理，終愧撫遐荒。"]'),
('yuding-4','幸武功慶善宮','李世民','唐','御定全唐诗','yuding','','[]','壽丘惟舊跡，酆邑乃前基。粵予承累聖，懸弧亦在茲。',120,'御定全唐詩/json/001.json','["壽丘惟舊跡，酆邑乃前基。粵予承累聖，懸弧亦在茲。", "弱齡逢運改，提劍郁匡時。指麾八荒定，懷柔萬國夷。", "梯山咸入款，駕海亦來思。單于陪武帳，日逐衛文䪥。", "端扆朝四岳，無為任百司。霜節明秋景，輕冰結水湄。", "芸黃遍原隰，禾穎積京畿。共樂還鄉宴，歡比大風詩。"]'),
('yuding-5','重幸武功','李世民','唐','御定全唐诗','yuding','','[]','代馬依朔吹，驚禽愁昔叢。況茲承眷德，懷舊感深衷。',120,'御定全唐詩/json/001.json','["代馬依朔吹，驚禽愁昔叢。況茲承眷德，懷舊感深衷。", "積善忻餘慶，暢武悅成功。垂衣天下治，端拱車書同。", "白水巡前跡，丹陵幸舊宮。列筵歡故老，高宴聚新豐。", "駐蹕撫田畯，回輿訪牧童。瑞氣縈丹闕，祥煙散碧空。", "孤嶼含霜白，遙山帶日紅。於焉歡擊築，聊以詠南風。"]'),
('yuding-6','經破薛舉戰地','李世民','唐','御定全唐诗','yuding','','[]','昔年懷壯氣，提戈初仗節。心隨朗日高，志與秋霜潔。',120,'御定全唐詩/json/001.json','["昔年懷壯氣，提戈初仗節。心隨朗日高，志與秋霜潔。", "移鋒驚電起，轉戰長河決。營碎落星沉，陣卷橫雲裂。", "一揮氛沴靜，再舉鯨鯢滅。于茲俯舊原，屬目駐華軒。", "沉沙無故跡，減灶有殘痕。浪霞穿水淨，峰霧抱蓮昏。", "世途亟流易，人事殊今昔。長想眺前蹤，撫躬聊自適。"]'),
('yuding-7','過舊宅二首','李世民','唐','御定全唐诗','yuding','','[]','新豐停翠輦，譙邑駐鳴笳。園荒一徑斷，苔古半階斜。',132,'御定全唐詩/json/001.json','["新豐停翠輦，譙邑駐鳴笳。園荒一徑斷，苔古半階斜。", "前池消舊水，昔樹發今花。一朝辭此地，四海遂為家。", "金輿巡白水，玉輦駐新豐。紐落藤披架，花殘菊破叢。", "葉鋪荒草蔓，流竭半池空。紉佩蘭凋徑，舒圭葉翦桐。", "昔地一蕃內，今宅九圍中。架海波澄鏡，韜戈器反農。", "八表文同軌，無勞歌大風。"]'),
('yuding-8','還陝述懷','李世民','唐','御定全唐诗','yuding','','[]','慨然撫長劍，濟世豈邀名。星旗紛電舉，日羽肅天行。',60,'御定全唐詩/json/001.json','["慨然撫長劍，濟世豈邀名。星旗紛電舉，日羽肅天行。", "遍野屯萬騎，臨原駐五營。登山麾武節，背水縱神兵。", "在昔戎戈動，今來宇宙平。"]'),
('yuding-9','入潼關','李世民','唐','御定全唐诗','yuding','','[]','崤函稱地險，襟帶壯兩京。霜峰直臨道，冰河曲繞城。',84,'御定全唐詩/json/001.json','["崤函稱地險，襟帶壯兩京。霜峰直臨道，冰河曲繞城。", "古木參差影，寒猿斷續聲。冠蓋往來合，風塵朝夕驚。", "高談先馬度，偽曉預雞鳴。棄繻懷遠志，封泥負壯情。", "別有真人氣，安知名不名。"]'),
('yuding-10','於北平作','李世民','唐','御定全唐诗','yuding','','[]','翠野駐戎軒，盧龍轉征旆。遙山麗如綺，長流縈似帶。',48,'御定全唐詩/json/001.json','["翠野駐戎軒，盧龍轉征旆。遙山麗如綺，長流縈似帶。", "海氣百重樓，岩松千丈蓋。茲焉可遊賞，何必襄城外。"]'),
('yuding-11','遼城望月','李世民','唐','御定全唐诗','yuding','','[]','玄兔月初明，澄輝照遼碣。映雲光暫隱，隔樹花如綴。',60,'御定全唐詩/json/001.json','["玄兔月初明，澄輝照遼碣。映雲光暫隱，隔樹花如綴。", "魄滿桂枝圓，輪虧鏡彩缺。臨城卻影散，帶暈重圍結。", "駐蹕俯九都，停觀妖氛滅。"]'),
('yuding-12','春日登陝州城樓俯眺原野廻丹碧綴煙霞密翠斑紅芳菲花柳即目川岫聊以命篇','李世民','唐','御定全唐诗','yuding','','[]','碧原開霧隰，綺嶺峻霞城。煙峰高下翠，日浪淺深明。',60,'御定全唐詩/json/001.json','["碧原開霧隰，綺嶺峻霞城。煙峰高下翠，日浪淺深明。", "斑紅妝蕊樹，圓青壓溜荊。跡岩勞傅想，窺野訪莘情。", "巨川何以濟，舟楫佇時英。"]'),
('yuding-13','春日玄武門宴群臣','李世民','唐','御定全唐诗','yuding','','[]','韶光開令序，淑氣動芳年。駐輦華林側，高宴柏梁前。',96,'御定全唐詩/json/001.json','["韶光開令序，淑氣動芳年。駐輦華林側，高宴柏梁前。", "紫庭文佩滿，丹墀袞紱連。九夷簉瑤席，五狄列瓊筵。", "娛賓歌湛露，廣樂奏鈞天。清尊浮綠醑，雅曲韻朱弦。", "粵余君萬國，還慚撫八埏。庶幾保貞固，虛己厲求賢。"]'),
('yuding-14','登三臺言志','李世民','唐','御定全唐诗','yuding','','[]','未央初壯漢，阿房昔侈秦。在危猶騁麗，居奢遂役人。',132,'御定全唐詩/json/001.json','["未央初壯漢，阿房昔侈秦。在危猶騁麗，居奢遂役人。", "豈如家四海，日宇罄朝倫。扇天裁戶舊，砌地翦基新。", "引月擎宵桂，飄雲逼曙鱗。露除光炫玉，霜闕映雕銀。", "舞接花梁燕，歌迎鳥路塵。鏡池波太液，莊苑麗宜春。", "作異甘泉日，停非路寢辰。念勞慚逸己，居曠返勞神。", "所欣成大廈，宏材佇渭濱。"]'),
('yuding-15','出獵','李世民','唐','御定全唐诗','yuding','','[]','楚王雲夢澤，漢帝長楊宮。豈若因農暇，閱武出轘嵩。',96,'御定全唐詩/json/001.json','["楚王雲夢澤，漢帝長楊宮。豈若因農暇，閱武出轘嵩。", "三驅陳銳卒，七萃列材雄。寒野霜氛白，平原燒火紅。", "雕戈夏服箭，羽騎綠沉弓。怖獸潛幽壑，驚禽散翠空。", "長煙晦落景，灌木振嚴風。所為除民瘼，非是悅林叢。"]'),
('yuding-16','冬狩','李世民','唐','御定全唐诗','yuding','','[]','烈烈寒風起，慘慘飛雲浮。霜濃凝廣隰，冰厚結清流。',108,'御定全唐詩/json/001.json','["烈烈寒風起，慘慘飛雲浮。霜濃凝廣隰，冰厚結清流。", "金鞍移上苑，玉勒騁平疇。旌旗四望合，罝羅一面求。", "楚踣爭兕殪，秦亡角鹿愁。獸忙投密樹，鴻驚起礫洲。", "騎斂原塵靜，戈回嶺日收。心非洛汭逸，意在渭濱遊。", "禽荒非所樂，撫轡更招憂。"]'),
('yuding-17','春日望海','李世民','唐','御定全唐诗','yuding','','[]','披襟眺滄海，憑軾玩春芳。積流橫地紀，疏派引天潢。',120,'御定全唐詩/json/001.json','["披襟眺滄海，憑軾玩春芳。積流橫地紀，疏派引天潢。", "仙氣凝三嶺，和風扇八荒。拂潮雲布色，穿浪日舒光。", "照岸花分彩，迷雲雁斷行。懷卑運深廣，持滿守靈長。", "有形非易測，無源詎可量。洪濤經變野，翠島屢成桑。", "之罘思漢帝，碣石想秦皇。霓裳非本意，端拱且圖王。"]'),
('yuding-18','臨洛水','李世民','唐','御定全唐诗','yuding','','[]','春搜馳駿骨，總轡俯長河。霞處流縈錦，風前漾卷羅。',48,'御定全唐詩/json/001.json','["春搜馳駿骨，總轡俯長河。霞處流縈錦，風前漾卷羅。", "水花翻照樹，堤蘭倒插波。豈必汾陰曲，秋雲發棹歌。"]'),
('yuding-19','望終南山','李世民','唐','御定全唐诗','yuding','','[]','重巒俯渭水，碧嶂插遙天。出紅扶嶺日，入翠貯岩煙。',48,'御定全唐詩/json/001.json','["重巒俯渭水，碧嶂插遙天。出紅扶嶺日，入翠貯岩煙。", "疊松朝若夜，複岫闕疑全。對此恬千慮，無勞訪九仙。"]'),
('yuding-20','元日','李世民','唐','御定全唐诗','yuding','','[]','高軒曖春色，邃閣媚朝光。彤庭飛彩旆，翠幌曜明璫。',96,'御定全唐詩/json/001.json','["高軒曖春色，邃閣媚朝光。彤庭飛彩旆，翠幌曜明璫。", "恭己臨四極，垂衣馭八荒。霜戟列丹陛，絲竹韻長廊。", "穆矣熏風茂，康哉帝道昌。繼文遵後軌，循古鑒前王。", "草秀故春色，梅豔昔年妝。巨川思欲濟，終以寄舟航。"]'),
('yuding-21','初春登樓即目觀作述懷','李世民','唐','御定全唐诗','yuding','','[]','憑軒俯蘭閣，眺矚散靈襟。綺峰含翠霧，照日蕊紅林。',96,'御定全唐詩/json/001.json','["憑軒俯蘭閣，眺矚散靈襟。綺峰含翠霧，照日蕊紅林。", "鏤丹霞錦岫，殘素雪斑岑。拂浪堤垂柳，嬌花鳥續吟。", "連甍豈一拱，眾幹如千尋。明非獨材力，終藉棟樑深。", "彌懷矜樂志，更懼戒盈心。愧制勞居逸，方規十產金。"]'),
('yuding-22','首春','李世民','唐','御定全唐诗','yuding','','[]','寒隨窮律變，春逐鳥聲開。初風飄帶柳，晚雪間花梅。',48,'御定全唐詩/json/001.json','["寒隨窮律變，春逐鳥聲開。初風飄帶柳，晚雪間花梅。", "碧林青舊竹，綠沼翠新苔。芝田初雁去，綺樹巧鶯來。"]'),
('yuding-23','初晴落景','李世民','唐','御定全唐诗','yuding','','[]','晚霞聊自怡，初晴彌可喜。日晃百花色，風動千林翠。',48,'御定全唐詩/json/001.json','["晚霞聊自怡，初晴彌可喜。日晃百花色，風動千林翠。", "池魚躍不同，園鳥聲還異。寄言博通者，知予物外志。"]'),
('yuding-24','初夏','李世民','唐','御定全唐诗','yuding','','[]','一朝春夏改，隔夜鳥花遷。陰陽深淺葉，曉夕重輕煙。',72,'御定全唐詩/json/001.json','["一朝春夏改，隔夜鳥花遷。陰陽深淺葉，曉夕重輕煙。", "哢鶯猶響殿，橫絲正網天。佩高蘭影接，綬細草紋連。", "碧鱗驚棹側，玄燕舞簷前。何必汾陽處，始複有山泉。"]'),
('yuding-25','度秋','李世民','唐','御定全唐诗','yuding','','[]','夏律昨留灰，秋箭今移晷。峨嵋岫初出，洞庭波漸起。',48,'御定全唐詩/json/001.json','["夏律昨留灰，秋箭今移晷。峨嵋岫初出，洞庭波漸起。", "桂白髮幽岩，菊黃開灞涘。運流方可歎，含毫屬微理。"]'),
('yuding-26','儀鸞殿早秋','李世民','唐','御定全唐诗','yuding','','[]','寒驚薊門葉，秋發小山枝。松陰背日轉，竹影避風移。',48,'御定全唐詩/json/001.json','["寒驚薊門葉，秋發小山枝。松陰背日轉，竹影避風移。", "提壺菊花岸，高興芙蓉池。欲知涼氣早，巢空燕不窺。"]'),
('yuding-27','秋日即目','李世民','唐','御定全唐诗','yuding','','[]','爽氣浮丹闕，秋光澹紫宮。衣碎荷疏影，花明菊點叢。',96,'御定全唐詩/json/001.json','["爽氣浮丹闕，秋光澹紫宮。衣碎荷疏影，花明菊點叢。", "袍輕低草露，蓋側舞松風。散岫飄雲葉，迷路飛煙鴻。", "砌冷蘭凋佩，閨寒樹隕桐。別鶴棲琴裏，離猿啼峽中。", "落野飛星箭，弦虛半月弓。芳菲夕霧起，暮色滿房櫳。"]'),
('yuding-28','山閣晚秋','李世民','唐','御定全唐诗','yuding','','[]','山亭秋色滿，岩牖涼風度。疏蘭尚染煙，殘菊猶承露。',48,'御定全唐詩/json/001.json','["山亭秋色滿，岩牖涼風度。疏蘭尚染煙，殘菊猶承露。", "古石衣新苔，新巢封古樹。曆覽情無極，咫尺輪光暮。"]'),
('yuding-29','秋暮言志','李世民','唐','御定全唐诗','yuding','','[]','朝光浮燒野，霜華淨碧空。結浪冰初鏡，在徑菊方叢。',60,'御定全唐詩/json/001.json','["朝光浮燒野，霜華淨碧空。結浪冰初鏡，在徑菊方叢。", "約嶺煙深翠，分旗霞散紅。抽思滋泉側，飛想傅岩中。", "已獲千箱慶，何以繼熏風。"]'),
('yuding-30','喜雪','李世民','唐','御定全唐诗','yuding','','[]','碧昏朝合霧，丹卷暝韜霞。結葉繁雲色，凝瓊遍雪華。',132,'御定全唐詩/json/001.json','["碧昏朝合霧，丹卷暝韜霞。結葉繁雲色，凝瓊遍雪華。", "光樓皎若粉，映幕集疑沙。泛柳飛飛絮，妝梅片片花。", "照璧台圓月，飄珠箔穿露。瑤潔短長階，玉叢高下樹。", "映桐珪累白，縈峰蓮抱素。斷續氣將沉，徘徊歲雲暮。", "懷珍愧隱德，表瑞佇豐年。蕊間飛禁苑，鶴處舞伊川。", "儻詠幽蘭曲，同歡黃竹篇。"]'),
('yuding-31','秋日斅庾信體','李世民','唐','御定全唐诗','yuding','','[]','嶺銜宵月桂，珠穿曉露叢。蟬啼覺樹冷，螢火不溫風。',60,'御定全唐詩/json/001.json','["嶺銜宵月桂，珠穿曉露叢。蟬啼覺樹冷，螢火不溫風。", "花生圓菊蕊，荷盡戲魚通。晨浦鳴飛雁，夕渚集棲鴻。", "颯颯高天吹，氛澄下熾空。"]'),
('yuding-32','賦尚書','李世民','唐','御定全唐诗','yuding','','[]','崇文時駐步，東觀還停輦。輟膳玩三墳，暉燈披五典。',72,'御定全唐詩/json/001.json','["崇文時駐步，東觀還停輦。輟膳玩三墳，暉燈披五典。", "寒心睹肉林，飛魄看沉湎。縱情昏主多，克己明君鮮。", "滅身資累惡，成名由積善。既承百王末，戰兢隨歲轉。"]'),
('yuding-33','詠司馬彪續漢志','李世民','唐','御定全唐诗','yuding','','[]','二儀初創象，三才乃分位。非惟樹司牧，固亦垂文字。',264,'御定全唐詩/json/001.json','["二儀初創象，三才乃分位。非惟樹司牧，固亦垂文字。", "綿代更膺期，芳圖無輟記。炎漢承君道，英謨纂神器。", "潛龍既可躍，逵兔奚難致。前史殫妙詞，後昆沉雅思。", "書言揚盛跡，補闕興洪志。川穀猶舊途，郡國開新意。", "梅山未覺朽，谷水誰雲異。車服隨名表，文物因時置。", "鳳戟翼康衢，鑾輿總柔轡。清濁必能澄，洪纖幸無棄。", "觀儀不失序，遵禮方由事。政宣竹律和，時平玉條備。", "文囿雕奇彩，藝門蘊深致。雲飛星共流，風揚月兼至。", "類禋遵令典，壇壝資良地。五勝竟無違，百司誠有庇。", "粵予承暇景，談叢引泉秘。討論窮義府，看核披經笥。", "大辨良難仰，小學終先匱。聞道諒知榮，含毫孰忘愧。"]'),
('yuding-34','詠風','李世民','唐','御定全唐诗','yuding','','[]','蕭條起關塞，搖颺下蓬瀛。拂林花亂彩，響穀鳥分聲。',48,'御定全唐詩/json/001.json','["蕭條起關塞，搖颺下蓬瀛。拂林花亂彩，響穀鳥分聲。", "披雲羅影散，泛水織文生。勞歌大風曲，威加四海清。"]'),
('yuding-35','詠雨','李世民','唐','御定全唐诗','yuding','','[]','罩雲飄遠岫，噴雨泛長河。低飛昏嶺腹，斜足灑岩阿。',48,'御定全唐詩/json/001.json','["罩雲飄遠岫，噴雨泛長河。低飛昏嶺腹，斜足灑岩阿。", "泫叢珠締葉，起溜鏡圖波。蒙柳添絲密，含吹織空羅。"]'),
('yuding-36','詠雪','李世民','唐','御定全唐诗','yuding','','[]','潔野凝晨曜，裝墀帶夕暉。集條分樹玉，拂浪影泉璣。',48,'御定全唐詩/json/001.json','["潔野凝晨曜，裝墀帶夕暉。集條分樹玉，拂浪影泉璣。", "色灑妝台粉，花飄綺席衣。入扇縈離匣，點素皎殘機。"]'),
('yuding-37','賦得夏首啟節','李世民','唐','御定全唐诗','yuding','','[]','北闕三春晚，南榮九夏初。黃鶯弄漸變，翠林花落餘。',60,'御定全唐詩/json/001.json','["北闕三春晚，南榮九夏初。黃鶯弄漸變，翠林花落餘。", "瀑流還響穀，猿啼自應虛。早荷向心卷，長楊就影舒。", "此時歡不極，調軫坐相於。"]'),
('yuding-38','賦得白日半西山','李世民','唐','御定全唐诗','yuding','','[]','紅輪不暫駐，烏飛豈複停。岑霞漸漸落，溪陰寸寸生。',48,'御定全唐詩/json/001.json','["紅輪不暫駐，烏飛豈複停。岑霞漸漸落，溪陰寸寸生。", "藿葉隨光轉，葵心逐照傾。晚煙含樹色，棲鳥雜流聲。"]'),
('yuding-39','置酒坐飛閣','李世民','唐','御定全唐诗','yuding','','[]','高軒臨碧渚，飛簷迥架空。餘花攢鏤檻，殘柳散雕櫳。',48,'御定全唐詩/json/001.json','["高軒臨碧渚，飛簷迥架空。餘花攢鏤檻，殘柳散雕櫳。", "岸菊初含蕊，園梨始帶紅。莫慮昆山暗，還共盡杯中。"]'),
('yuding-40','采芙蓉','李世民','唐','御定全唐诗','yuding','','[]','結伴戲方塘，攜手上雕航。船移分細浪，風散動浮香。',60,'御定全唐詩/json/001.json','["結伴戲方塘，攜手上雕航。船移分細浪，風散動浮香。", "游鶯無定曲，驚鳧有亂行。蓮稀釧聲斷，水廣棹歌長。", "棲烏還密樹，泛流歸建章。"]'),
('yuding-41','賦得櫻桃','李世民','唐','御定全唐诗','yuding','','[]','華林滿芳景，洛陽遍陽春。朱顏含遠日，翠色影長津。',48,'御定全唐詩/json/001.json','["華林滿芳景，洛陽遍陽春。朱顏含遠日，翠色影長津。", "喬柯囀嬌鳥，低枝映美人。昔作園中實，今來席上珍。"]'),
('yuding-42','賦得李','李世民','唐','御定全唐诗','yuding','','[]','玉衡流桂圃，成蹊正可尋。鶯啼密葉外，蝶戲脆花心。',48,'御定全唐詩/json/001.json','["玉衡流桂圃，成蹊正可尋。鶯啼密葉外，蝶戲脆花心。", "麗景光朝彩，輕霞散夕陰。暫顧暉章側，還眺靈山林。"]'),
('yuding-43','賦得浮橋','李世民','唐','御定全唐诗','yuding','','[]','岸曲非千里，橋斜異七星。暫低逢輦度，還高值浪驚。',48,'御定全唐詩/json/001.json','["岸曲非千里，橋斜異七星。暫低逢輦度，還高值浪驚。", "水搖文鷁動，纜轉錦花縈。遠近隨輪影，輕重應人行。"]'),
('yuding-44','謁並州大興國寺詩','李世民','唐','御定全唐诗','yuding','','[]','回鑾遊福地，極目玩芳晨。梵鐘交二響，法日轉雙輪。',72,'御定全唐詩/json/001.json','["回鑾遊福地，極目玩芳晨。梵鐘交二響，法日轉雙輪。", "寶刹遙承露，天花近足春。未佩蘭猶小，無絲柳尚新。", "圓光低月殿，碎影亂風筠。對此留餘想，超然離俗塵。"]'),
('yuding-45','詠興國寺佛殿前幡','李世民','唐','御定全唐诗','yuding','','[]','拂霞疑電落，騰虛狀寫虹。屈伸煙霧裏，低舉白雲中。',48,'御定全唐詩/json/001.json','["拂霞疑電落，騰虛狀寫虹。屈伸煙霧裏，低舉白雲中。", "紛披乍依迥，掣曳或隨風。念茲輕薄質，無翅強搖空。"]'),
('yuding-46','望送魏徵葬','李世民','唐','御定全唐诗','yuding','','[]','閶闔總金鞍，上林移玉輦。野郊愴新別，河橋非舊餞。',72,'御定全唐詩/json/001.json','["閶闔總金鞍，上林移玉輦。野郊愴新別，河橋非舊餞。", "慘日映峰沉，愁雲隨蓋轉。哀笳時斷續，悲旌乍舒卷。", "望望情何極，浪浪淚空泫。無複昔時人，芳春共誰遣。"]'),
('yuding-47','傷遼東戰亡','李世民','唐','御定全唐诗','yuding','','[]','鑿門初奉律，仗戰始臨戎。振鱗方躍浪，騁翼正淩風。',48,'御定全唐詩/json/001.json','["鑿門初奉律，仗戰始臨戎。振鱗方躍浪，騁翼正淩風。", "未展六奇術，先虧一簣功。防身豈乏智，殉命有餘忠。"]'),
('yuding-48','月晦','李世民','唐','御定全唐诗','yuding','','[]','晦魄移中律，凝暄起麗城。罩雲朝蓋上，穿露曉珠呈。',48,'御定全唐詩/json/001.json','["晦魄移中律，凝暄起麗城。罩雲朝蓋上，穿露曉珠呈。", "笑樹花分色，啼枝鳥合聲。披襟歡眺望，極目暢春情。"]'),
('yuding-49','秋日翠微宮','李世民','唐','御定全唐诗','yuding','','[]','秋日凝翠嶺，涼吹肅離宮。荷疏一蓋缺，樹冷半帷空。',48,'御定全唐詩/json/001.json','["秋日凝翠嶺，涼吹肅離宮。荷疏一蓋缺，樹冷半帷空。", "側陣移鴻影，圓花釘菊叢。攄懷俗塵外，高眺白雲中。"]'),
('yuding-50','初秋夜坐','李世民','唐','御定全唐诗','yuding','','[]','斜廊連綺閣，初月照宵幃。塞冷鴻飛疾，園秋蟬噪遲。',48,'御定全唐詩/json/001.json','["斜廊連綺閣，初月照宵幃。塞冷鴻飛疾，園秋蟬噪遲。", "露結林疏葉，寒輕菊吐滋。愁心逢此節，長歎獨含悲。"]'),
('yuding-51','秋日二首','李世民','唐','御定全唐诗','yuding','','[]','菊散金風起，荷疏玉露圓。將秋數行雁，離夏幾林蟬。',96,'御定全唐詩/json/001.json','["菊散金風起，荷疏玉露圓。將秋數行雁，離夏幾林蟬。", "雲凝愁半嶺，霞碎纈高天。還似成都望，直見峨眉前。", "爽氣澄蘭沼，秋風動桂林。露凝千片玉，菊散一叢金。", "日岫高低影，雲空點綴陰。蓬瀛不可望，泉石且娛心。"]'),
('yuding-52','冬宵各為四韻','李世民','唐','御定全唐诗','yuding','','[]','雕宮靜龍漏，綺閣宴公侯。珠簾燭焰動，繡柱月光浮。',48,'御定全唐詩/json/001.json','["雕宮靜龍漏，綺閣宴公侯。珠簾燭焰動，繡柱月光浮。", "雲起將歌發，風停與管遒。瑣除任多士，端扆竟何憂。"]'),
('yuding-53','冬日臨昆明池','李世民','唐','御定全唐诗','yuding','','[]','石鯨分玉溜，劫燼隱平沙。柳影冰無葉，梅心凍有花。',48,'御定全唐詩/json/001.json','["石鯨分玉溜，劫燼隱平沙。柳影冰無葉，梅心凍有花。", "寒野凝朝霧，霜天散夕霞。歡情猶未極，落景遽西斜。"]'),
('yuding-54','望雪','李世民','唐','御定全唐诗','yuding','','[]','凍雲宵遍嶺，素雪曉凝華。入牖千重碎，迎風一半斜。',48,'御定全唐詩/json/001.json','["凍雲宵遍嶺，素雪曉凝華。入牖千重碎，迎風一半斜。", "不妝空散粉，無樹獨飄花。縈空慚夕照，破彩謝晨霞。"]'),
('yuding-55','守歲','李世民','唐','御定全唐诗','yuding','','[]','暮景斜芳殿，年華麗綺宮。寒辭去冬雪，暖帶入春風。',48,'御定全唐詩/json/001.json','["暮景斜芳殿，年華麗綺宮。寒辭去冬雪，暖帶入春風。", "階馥舒梅素，盤花卷燭紅。共歡新故歲，迎送一宵中。"]'),
('yuding-56','除夜','李世民','唐','御定全唐诗','yuding','','[]','歲陰窮暮紀，獻節啟新芳。冬盡今宵促，年開明日長。',48,'御定全唐詩/json/001.json','["歲陰窮暮紀，獻節啟新芳。冬盡今宵促，年開明日長。", "冰消出鏡水，梅散入風香。對此歡終宴，傾壺待曙光。"]'),
('yuding-57','詠雨','李世民','唐','御定全唐诗','yuding','','[]','和氣吹綠野，梅雨灑芳田。新流添舊澗，宿霧足朝煙。',48,'御定全唐詩/json/001.json','["和氣吹綠野，梅雨灑芳田。新流添舊澗，宿霧足朝煙。", "雁濕行無次，花沾色更鮮。對此欣登歲，披襟弄五弦。"]'),
('yuding-58','賦得含峰雲','李世民','唐','御定全唐诗','yuding','','[]','翠樓含曉霧，蓮峰帶晚雲。玉葉依岩聚，金枝觸石分。',48,'御定全唐詩/json/001.json','["翠樓含曉霧，蓮峰帶晚雲。玉葉依岩聚，金枝觸石分。", "橫天結陣影，逐吹起羅文。非複陽臺下，空將惑楚君。"]'),
('yuding-59','三層閣上置音聲','李世民','唐','御定全唐诗','yuding','','[]','綺筵移暮景，紫閣引宵煙。隔棟歌塵合，分階舞影連。',48,'御定全唐詩/json/001.json','["綺筵移暮景，紫閣引宵煙。隔棟歌塵合，分階舞影連。", "聲流三處管，響亂一重弦。不似秦樓上，吹簫空學仙。"]'),
('yuding-60','遠山澄碧霧','李世民','唐','御定全唐诗','yuding','','[]','殘雲收翠嶺，夕霧結長空。帶岫凝全碧，障霞隱半紅。',48,'御定全唐詩/json/001.json','["殘雲收翠嶺，夕霧結長空。帶岫凝全碧，障霞隱半紅。", "仿佛分初月，飄颻度曉風。還因三裏處，冠蓋遠相通。"]'),
('yuding-61','賦得花庭霧','李世民','唐','御定全唐诗','yuding','','[]','蘭氣已熏宮，新蕊半妝叢。色含輕重霧，香引去來風。',48,'御定全唐詩/json/001.json','["蘭氣已熏宮，新蕊半妝叢。色含輕重霧，香引去來風。", "拂樹濃舒碧，縈花薄蔽紅。還當雜行雨，仿佛隱遙空。"]'),
('yuding-62','春池柳','李世民','唐','御定全唐诗','yuding','','[]','年柳變池台，隋堤曲直回。逐浪絲陰去，迎風帶影來。',48,'御定全唐詩/json/001.json','["年柳變池台，隋堤曲直回。逐浪絲陰去，迎風帶影來。", "疏黃一鳥弄，半翠幾眉開。縈雪臨春岸，參差間早梅。"]'),
('yuding-63','芳蘭','李世民','唐','御定全唐诗','yuding','','[]','春暉開紫苑，淑景媚蘭場。映庭含淺色，凝露泫浮光。',48,'御定全唐詩/json/001.json','["春暉開紫苑，淑景媚蘭場。映庭含淺色，凝露泫浮光。", "日麗參差影，風傳輕重香。會須君子折，佩里作芬芳。"]'),
('yuding-64','詠桃','李世民','唐','御定全唐诗','yuding','','[]','禁苑春暉麗，花蹊綺樹妝。綴條深淺色，點露參差光。',48,'御定全唐詩/json/001.json','["禁苑春暉麗，花蹊綺樹妝。綴條深淺色，點露參差光。", "向日分千笑，迎風共一香。如何仙嶺側，獨秀隱遙芳。"]'),
('yuding-65','賦簾','李世民','唐','御定全唐诗','yuding','','[]','參差垂玉闕，舒卷映蘭宮。珠光搖素月，竹影亂清風。',48,'御定全唐詩/json/001.json','["參差垂玉闕，舒卷映蘭宮。珠光搖素月，竹影亂清風。", "彩散銀鉤上，文斜桂戶中。惟當雜羅綺，相與媚房櫳。"]'),
('yuding-66','詠烏代陳師道','李世民','唐','御定全唐诗','yuding','','[]','淩晨麗城去，薄暮上林棲。辭枝枝暫起，停樹樹還低。',48,'御定全唐詩/json/001.json','["淩晨麗城去，薄暮上林棲。辭枝枝暫起，停樹樹還低。", "向日終難托，迎風詎肯迷。只待纖纖手，曲裏作宵啼。"]'),
('yuding-67','詠飲馬','李世民','唐','御定全唐诗','yuding','','[]','駿骨飲長涇，奔流灑絡纓。細紋連噴聚，亂荇繞蹄縈。',48,'御定全唐詩/json/001.json','["駿骨飲長涇，奔流灑絡纓。細紋連噴聚，亂荇繞蹄縈。", "水光鞍上側，馬影溜中橫。翻似天池裏，騰波龍種生。"]'),
('yuding-68','賦得殘菊','李世民','唐','御定全唐诗','yuding','','[]','階蘭凝曙霜，岸菊照晨光。露濃晞晚笑，風勁淺殘香。',48,'御定全唐詩/json/001.json','["階蘭凝曙霜，岸菊照晨光。露濃晞晚笑，風勁淺殘香。", "細葉凋輕翠，圓花飛碎黃。還持今歲色，複結後年芳。"]'),
('yuding-69','賦秋日懸清光賜房玄齡','李世民','唐','御定全唐诗','yuding','','[]','秋露凝高掌，朝光上翠微。參差麗雙闕，照耀滿重闈。',60,'御定全唐詩/json/001.json','["秋露凝高掌，朝光上翠微。參差麗雙闕，照耀滿重闈。", "仙馭隨輪轉，靈烏帶影飛。臨波無定彩，入隙有圓暉。", "還當葵藿志，傾葉自相依。"]'),
('yuding-70','琵琶','李世民','唐','御定全唐诗','yuding','','[]','半月無雙影，全花有四時。摧藏千里態，掩抑幾重悲。',60,'御定全唐詩/json/001.json','["半月無雙影，全花有四時。摧藏千里態，掩抑幾重悲。", "促節縈紅袖，清音滿翠帷。駛彈風響急，緩曲釧聲遲。", "空餘關隴恨，因此代相思。"]'),
('yuding-71','宴中山','李世民','唐','御定全唐诗','yuding','','[]','驅馬出遼陽，萬里轉旗常。對敵六奇舉，臨戎八陣張。',72,'御定全唐詩/json/001.json','["驅馬出遼陽，萬里轉旗常。對敵六奇舉，臨戎八陣張。", "斬鯨澄碧海，卷霧掃扶桑。昔去蘭縈翠，今來桂染芳。", "雲芝浮碎葉，冰鏡上朝光。回首長安道，方歡宴柏梁。"]'),
('yuding-72','餞中書侍郎來濟','李世民','唐','御定全唐诗','yuding','','[]','曖曖去塵昏灞岸，飛飛輕蓋指河梁。雲峰衣結千重葉，',64,'御定全唐詩/json/001.json','["曖曖去塵昏灞岸，飛飛輕蓋指河梁。雲峰衣結千重葉，", "雪岫花開幾樹妝。深悲黃鶴孤舟遠，獨歎青山別路長。", "聊將分袂沾巾淚，還用持添離席觴。"]'),
('yuding-73','於太原召侍臣賜宴守歲','李世民','唐','御定全唐诗','yuding','','[]','四時運灰管，一夕變冬春。送寒餘雪盡，迎歲早梅新。',24,'御定全唐詩/json/001.json','["四時運灰管，一夕變冬春。送寒餘雪盡，迎歲早梅新。"]'),
('yuding-74','詠燭二首','李世民','唐','御定全唐诗','yuding','','[]','焰聽風來動，花開不待春。鎮下千行淚，非是為思人。',48,'御定全唐詩/json/001.json','["焰聽風來動，花開不待春。鎮下千行淚，非是為思人。", "九龍蟠焰動，四照逐花生。即此流高殿，堪持待月明。"]'),
('yuding-75','詠弓','李世民','唐','御定全唐诗','yuding','','[]','上弦明月半，激箭流星遠。落雁帶書驚，啼猿映枝轉。',24,'御定全唐詩/json/001.json','["上弦明月半，激箭流星遠。落雁帶書驚，啼猿映枝轉。"]'),
('yuding-76','賦得早雁出雲鳴','李世民','唐','御定全唐诗','yuding','','[]','初秋玉露清，早雁出空鳴。隔雲時亂影，因風乍含聲。',24,'御定全唐詩/json/001.json','["初秋玉露清，早雁出空鳴。隔雲時亂影，因風乍含聲。"]'),
('yuding-77','賦得臨池柳','李世民','唐','御定全唐诗','yuding','','[]','岸曲絲陰聚，波移帶影疏。還將眉裏翠，來就鏡中舒。',24,'御定全唐詩/json/001.json','["岸曲絲陰聚，波移帶影疏。還將眉裏翠，來就鏡中舒。"]'),
('yuding-78','賦得臨池竹','李世民','唐','御定全唐诗','yuding','','[]','貞條障曲砌，翠葉貫寒霜。拂牖分龍影，臨池待鳳翔。',24,'御定全唐詩/json/001.json','["貞條障曲砌，翠葉貫寒霜。拂牖分龍影，臨池待鳳翔。"]'),
('yuding-79','賦得弱柳鳴秋蟬','李世民','唐','御定全唐诗','yuding','','[]','散影玉階柳，含翠隱鳴蟬。微形藏葉裏，亂響出風前。',24,'御定全唐詩/json/001.json','["散影玉階柳，含翠隱鳴蟬。微形藏葉裏，亂響出風前。"]'),
('yuding-80','探得李','李世民','唐','御定全唐诗','yuding','','[]','盤根直盈渚，交幹橫倚天。舒華光四海，卷葉蔭三川。',24,'御定全唐詩/json/001.json','["盤根直盈渚，交幹橫倚天。舒華光四海，卷葉蔭三川。"]'),
('yuding-81','詠小山','李世民','唐','御定全唐诗','yuding','','[]','近穀交縈蕊，遙峰對出蓮。徑細無全磴，松小未含煙。',24,'御定全唐詩/json/001.json','["近穀交縈蕊，遙峰對出蓮。徑細無全磴，松小未含煙。"]'),
('yuding-82','賜蕭瑀','李世民','唐','御定全唐诗','yuding','','[]','疾風知勁草，板蕩識誠臣。勇夫安識義，智者必懷仁。',24,'御定全唐詩/json/001.json','["疾風知勁草，板蕩識誠臣。勇夫安識義，智者必懷仁。"]'),
('yuding-83','賜房玄齡','李世民','唐','御定全唐诗','yuding','','[]','太液仙舟迥，西園隱上才。未曉征車度，雞鳴關早開。',24,'御定全唐詩/json/001.json','["太液仙舟迥，西園隱上才。未曉征車度，雞鳴關早開。"]'),
('yuding-84','遼東山夜臨秋','李世民','唐','御定全唐诗','yuding','','[]','煙生遙岸隱，月落半崖陰。連山驚鳥亂，隔岫斷猿吟。',24,'御定全唐詩/json/001.json','["煙生遙岸隱，月落半崖陰。連山驚鳥亂，隔岫斷猿吟。"]'),
('yuding-85','賜魏徵詩','李世民','唐','御定全唐诗','yuding','','[]','醽醁勝蘭生，翠濤過玉z1。千日醉不醒，十年味不敗。',25,'御定全唐詩/json/001.json','["醽醁勝蘭生，翠濤過玉z1。千日醉不醒，十年味不敗。"]'),
('yuding-86','兩儀殿賦柏梁體','李世民','唐','御定全唐诗','yuding','','[]','絕域降附天下平，——李世民',65,'御定全唐詩/json/001.json','["絕域降附天下平，——李世民", "八表無事悅聖情。——淮安王", "雲披霧斂天地明，——長孫無忌", "登封日觀禪雲亭，——房玄齡", "太常具禮方告成。——蕭瑀"]'),
('yuding-87','句','李世民','唐','御定全唐诗','yuding','','[]','雪恥酬百王，除凶報千古。',36,'御定全唐詩/json/001.json','["雪恥酬百王，除凶報千古。", "昔乘匹馬去，今驅萬乘來。", "近日毛雖暖，聞弦心已驚。"]'),
('yuding-0','太子納妃太平公主出降','李治','唐','御定全唐诗','yuding','','[]','龍樓光曙景，魯館啟朝扉。豔日濃妝影，低星降婺輝。',144,'御定全唐詩/json/002.json','["龍樓光曙景，魯館啟朝扉。豔日濃妝影，低星降婺輝。", "玉庭浮瑞色，銀榜藻祥徽。雲轉花縈蓋，霞飄葉綴旗。", "雕軒回翠陌，寶駕歸丹殿。鳴珠佩曉衣，鏤璧輪開扇。", "華冠列綺筵，蘭醑申芳宴。環階鳳樂陳，玳席珍羞薦。", "蝶舞袖香新，歌分落素塵。歡凝歡懿戚，慶葉慶初姻。", "暑闌炎氣息，涼早吹疏頻。方期六合泰，共賞萬年春。"]'),
('yuding-1','七夕宴懸圃二首','李治','唐','御定全唐诗','yuding','','[]','羽蓋飛天漢，鳳駕越層巒。俱歎三秋阻，共敘一宵歡。',96,'御定全唐詩/json/002.json','["羽蓋飛天漢，鳳駕越層巒。俱歎三秋阻，共敘一宵歡。", "璜虧夜月落，靨碎曉星殘。誰能重操杼，纖手濯清瀾。", "霓裳轉雲路，鳳駕儼天潢。虧星凋夜靨，殘月落朝璜。", "促歡今夕促，長離別後長。輕梭聊駐織，掩淚獨悲傷。"]'),
('yuding-2','過溫湯','李治','唐','御定全唐诗','yuding','','[]','溫渚停仙蹕，豐郊駐曉旌。路曲回輪影，岩虛傳漏聲。',60,'御定全唐詩/json/002.json','["溫渚停仙蹕，豐郊駐曉旌。路曲回輪影，岩虛傳漏聲。", "暖溜驚湍駛，寒空碧霧輕。林黃疏葉下，野白曙霜明。", "眺聽良無已，煙霞斷續生。"]'),
('yuding-3','九月九日','李治','唐','御定全唐诗','yuding','','[]','端居臨玉扆，初律啟金商。鳳闕澄秋色，龍闈引夕涼。',108,'御定全唐詩/json/002.json','["端居臨玉扆，初律啟金商。鳳闕澄秋色，龍闈引夕涼。", "野淨山氣斂，林疏風露長。砌蘭虧半影，岩桂發全香。", "滿蓋荷凋翠，圓花菊散黃。揮鞭爭電烈，飛羽亂星光。", "柳空穿石碎，弦虛側月張。怯猿啼落岫，驚雁斷分行。", "斜輪低夕景，歸旆擁通莊。"]'),
('yuding-4','謁慈恩寺題奘法師房','李治','唐','御定全唐诗','yuding','','[]','停軒觀福殿，遊目眺皇畿。法輪含日轉，花蓋接雲飛。',60,'御定全唐詩/json/002.json','["停軒觀福殿，遊目眺皇畿。法輪含日轉，花蓋接雲飛。", "翠煙香綺閣，丹霞光寶衣。幡虹遙合彩，定水迥分暉。", "蕭然登十地，自得會三歸。"]'),
('yuding-5','謁大慈恩寺','李治','唐','御定全唐诗','yuding','','[]','日宮開萬仞，月殿聳千尋。花蓋飛團影，幡虹曳曲陰。',48,'御定全唐詩/json/002.json','["日宮開萬仞，月殿聳千尋。花蓋飛團影，幡虹曳曲陰。", "綺霞遙籠帳，叢珠細網林。寥廓煙雲表，超然物外心。"]'),
('yuding-6','守歲','李治','唐','御定全唐诗','yuding','','[]','今宵冬律盡，來朝麗景新。花餘凝地雪，條含暖吹分。',60,'御定全唐詩/json/002.json','["今宵冬律盡，來朝麗景新。花餘凝地雪，條含暖吹分。", "綬吐芽猶嫩，冰□已鏤津。薄紅梅色冷，淺綠柳輕春。", "送迎交兩節，暄寒變一辰。"]'),
('yuding-7','咸亨殿宴近臣諸親柏梁體','李治','唐','御定全唐诗','yuding','','[]','屏欲除奢政返淳。',8,'御定全唐詩/json/002.json','["屏欲除奢政返淳。"]'),
('yuding-8','九月九日幸臨渭亭登高得秋字','李顯','唐','御定全唐诗','yuding','','[]','九日正乘秋，三杯興已周。泛桂迎尊滿，吹花向酒浮。',48,'御定全唐詩/json/002.json','["九日正乘秋，三杯興已周。泛桂迎尊滿，吹花向酒浮。", "長房萸早熟，彭澤菊初收。何藉龍沙上，方得恣淹留。"]'),
('yuding-9','登驪山高頂寓目','李顯','唐','御定全唐诗','yuding','','[]','四郊秦漢國，八水帝王都。閶闔雄裏閈，城闕壯規模。',48,'御定全唐詩/json/002.json','["四郊秦漢國，八水帝王都。閶闔雄裏閈，城闕壯規模。", "貫渭稱天邑，含岐實奧區。金門披玉館，因此識皇圖。"]'),
('yuding-10','幸秦始皇陵','李顯','唐','御定全唐诗','yuding','','[]','眷言君失德，驪邑想秦餘。政煩方改篆，愚俗乃焚書。',48,'御定全唐詩/json/002.json','["眷言君失德，驪邑想秦餘。政煩方改篆，愚俗乃焚書。", "阿房久已滅，閣道遂成墟。欲厭東南氣，翻傷掩鮑車。"]'),
('yuding-11','立春日遊苑迎春','李顯','唐','御定全唐诗','yuding','','[]','神皋福地三秦邑，玉台金闕九仙家。寒光猶戀甘泉樹，',64,'御定全唐詩/json/002.json','["神皋福地三秦邑，玉台金闕九仙家。寒光猶戀甘泉樹，", "淑景偏臨建始花。彩蝶黃鶯未歌舞，梅香柳色已矜誇。", "迎春正啟流霞席，暫囑曦輪勿遽斜。"]'),
('yuding-12','十月誕辰內殿宴群臣效柏梁體聯句','李顯','唐','御定全唐诗','yuding','','[]','潤色鴻業寄賢才，——李顯',200,'御定全唐詩/json/002.json','["潤色鴻業寄賢才，——李顯", "叨居右弼愧鹽梅。——李嶠", "運籌帷幄荷時來，——宗楚客", "職掌圖籍濫蓬萊。——劉憲", "兩司謬忝謝鐘裴，——崔湜", "禮樂銓管效涓埃。——鄭愔", "陳師振旅清九垓，——趙彥昭", "欣承顧問侍天杯。——李適", "銜恩獻壽柏梁台，——蘇頲", "黃縑青簡奉康哉。——盧藏用", "鯫生侍從忝王枚，——李乂", "右掖司言實不才。——馬懷素", "宗伯秩禮天地開，——薛稷", "帝歌難續仰昭回。——宋之問", "微臣捧日變寒灰，——陸景初", "遠慚班左愧遊陪。——上官婕妤"]'),
('yuding-13','景龍四年正月五日移仗蓬萊宮御大明殿會吐蕃騎馬之戲因重爲柏梁體聯句','李顯','唐','御定全唐诗','yuding','','[]','大明禦宇臨萬方，——李顯',183,'御定全唐詩/json/002.json','["大明禦宇臨萬方，——李顯", "顧慚內政翊陶唐。——皇后", "鸞鳴鳳舞向平陽，——長寧公主", "秦樓魯館沐恩光。——安樂公主", "無心為子輒求郎，——太平公主", "雄才七步謝陳王。——溫王重茂", "當熊讓輦愧前芳，——上官昭容", "再司銓筦恩可忘。——崔湜", "文江學海思濟航，——鄭愔", "萬邦考績臣所詳。——武平一", "著作不休出中腸，——閻朝隱", "權豪屏跡肅嚴霜。——竇從一", "鑄鼎開嶽造明堂，——宗晉卿", "玉醴由來獻壽觴。——明悉獵"]'),
('yuding-14','石淙','李顯','唐','御定全唐诗','yuding','','[]','三陽本是標靈紀，二室由來獨擅名。霞衣霞錦千般狀，',64,'御定全唐詩/json/002.json','["三陽本是標靈紀，二室由來獨擅名。霞衣霞錦千般狀，", "雲峰雲岫百重生。水炫珠光遇泉客，岩懸石鏡厭山精。", "永願乾坤符睿算，長居膝下屬歡情。"]'),
('yuding-15','石淙','李旦','唐','御定全唐诗','yuding','','[]','奇峰嶾嶙箕山北，秀崿岧嶢嵩鎮南。地首地肺何曾擬，',64,'御定全唐詩/json/002.json','["奇峰嶾嶙箕山北，秀崿岧嶢嵩鎮南。地首地肺何曾擬，", "天目天臺倍覺慚。樹影蒙蘢鄣疊岫，波深洶湧落懸潭。", "□願紫宸居得一，永欣丹扆禦通三。"]'),
('yuding-0','過晉陽宮','李隆基','唐','御定全唐诗','yuding','','[]','緬想封唐處，實惟建國初。俯察伊晉野，仰觀乃參虛。',144,'御定全唐詩/json/003.json','["緬想封唐處，實惟建國初。俯察伊晉野，仰觀乃參虛。", "井邑龍斯躍，城池鳳翔餘。林塘猶沛澤，台榭宛舊居。", "運革祚中否，時遷命茲符。顧循承丕構，怵惕多憂虞。", "尚恐威不逮，複慮化未孚。豈徒勞轍跡，所期訓戎車。", "習俗問黎人，親巡慰裏閭。永言念成功，頌德臨康衢。", "長懷經綸日，歎息履庭隅。艱難安可忘，欲去良踟躕。"]'),
('yuding-1','行次成皋途經先聖擒建德之所緬思功業感而賦詩','李隆基','唐','御定全唐诗','yuding','','[]','有隋政昏虐，群雄已交爭。先聖按劍起，叱吒風雲生。',72,'御定全唐詩/json/003.json','["有隋政昏虐，群雄已交爭。先聖按劍起，叱吒風雲生。", "飲馬河洛竭，作氣嵩華驚。克敵睿圖就，擒俘帝道亨。", "顧慚嗣寶曆，恭承天下平。幸過翦鯨地，感慕神且英。"]'),
('yuding-2','校獵義成喜逢大雪率題九韻以示群官','李隆基','唐','御定全唐诗','yuding','','[]','弧矢威天下，旌旗遊近縣。一面施鳥羅，三驅教人戰。',108,'御定全唐詩/json/003.json','["弧矢威天下，旌旗遊近縣。一面施鳥羅，三驅教人戰。", "暮雲成積雪，曉色開行殿。皓然原隰同，不覺林野變。", "北風勇士馬，東日華組練。觸地銀獐出，連山縞鹿見。", "月兔落高矰，星狼下急箭。既欣盈尺兆，複憶磻溪便。", "歲豐將遇賢，俱荷皇天眷。"]'),
('yuding-3','賜諸州刺史以題座右','李隆基','唐','御定全唐诗','yuding','','[]','眷言思共理，鑒夢想維良。猗歟此推擇，聲績著周行。',120,'御定全唐詩/json/003.json','["眷言思共理，鑒夢想維良。猗歟此推擇，聲績著周行。", "賢能既俟進，黎獻實佇康。視人當如子，愛人亦如傷。", "講學試誦論，阡陌勸耕桑。虛譽不可飾，清知不可忘。", "求名跡易見，安貞德自彰。訟獄必以情，教民貴有常。", "恤惸且存老，撫弱複綏強。勉哉各祗命，知予眷萬方。"]'),
('yuding-4','送忠州太守康昭遠等','李隆基','唐','御定全唐诗','yuding','','[]','端拱臨中樞，緬懷共予理。不有台閣英，孰振循良美。',84,'御定全唐詩/json/003.json','["端拱臨中樞，緬懷共予理。不有台閣英，孰振循良美。", "分符侯甸內，拜手明庭裏。誓節期飲冰，調人方導水。", "嘉聲馳九牧，惠化光千祀。時雨侔昔賢，芳猷貫前史。", "佇爾頌中和，吾將令卿士。"]'),
('yuding-5','送李邕之任滑臺','李隆基','唐','御定全唐诗','yuding','','[]','漢家重東郡，宛彼白馬津。黎庶既蕃殖，臨之勞近臣。',48,'御定全唐詩/json/003.json','["漢家重東郡，宛彼白馬津。黎庶既蕃殖，臨之勞近臣。", "遠別初首路，今行方及春。課成應第一，良牧爾當仁。"]'),
('yuding-6','端午三殿宴群臣探得神字','李隆基','唐','御定全唐诗','yuding','','[]','五月符天數，五音調夏鈞。舊來傳五日，無事不稱神。',84,'御定全唐詩/json/003.json','["五月符天數，五音調夏鈞。舊來傳五日，無事不稱神。", "穴枕通靈氣，長絲續命人。四時花競巧，九子粽爭新。", "方殿臨華節，圓宮宴雅臣。進對一言重，遒文六義陳。", "股肱良足詠，風化可還淳。"]'),
('yuding-7','溫湯對雪','李隆基','唐','御定全唐诗','yuding','','[]','北風吹同雲，同雲飛白雪。白雪乍回散，同雲何慘烈。',48,'御定全唐詩/json/003.json','["北風吹同雲，同雲飛白雪。白雪乍回散，同雲何慘烈。", "未見溫泉冰，寧知火井滅。表瑞良在茲，庶幾可怡悅。"]'),
('yuding-8','登蒲州逍遙樓','李隆基','唐','御定全唐诗','yuding','','[]','長榆息烽火，高柳靜風塵。卜征巡九洛，展豫出三秦。',72,'御定全唐詩/json/003.json','["長榆息烽火，高柳靜風塵。卜征巡九洛，展豫出三秦。", "昔是潛龍地，今為上理辰。時平乘道泰，聊賞遇年春。", "黃河分地絡，飛觀接天津。一覽遺芳翰，千載肅如神。"]'),
('yuding-9','經河上公廟','李隆基','唐','御定全唐诗','yuding','','[]','昔聞有耆叟，河上獨遺榮。跡與塵囂隔，心將道德並。',72,'御定全唐詩/json/003.json','["昔聞有耆叟，河上獨遺榮。跡與塵囂隔，心將道德並。", "詎以天地累，寧為寵辱驚。矯然翔寥廓，如何屈堅貞。", "玄玄妙門啟，肅肅祠宇清。冥漠無先後，那能紀姓名。"]'),
('yuding-10','過王濬墓','李隆基','唐','御定全唐诗','yuding','','[]','吳國分牛鬥，晉室命龍驤。受任敵已滅，策勳名不彰。',72,'御定全唐詩/json/003.json','["吳國分牛鬥，晉室命龍驤。受任敵已滅，策勳名不彰。", "居美未盡善，矜功徒自傷。長戟今何在，孤墳此路傍。", "不觀松柏茂，空餘荊棘場。歎嗟懸劍隴，誰識夢刀祥。"]'),
('yuding-11','初入秦川路逢寒食','李隆基','唐','御定全唐诗','yuding','','[]','洛陽芳樹映天津，灞岸垂楊窣地新。直為經過行處樂，',160,'御定全唐詩/json/003.json','["洛陽芳樹映天津，灞岸垂楊窣地新。直為經過行處樂，", "不知虛度兩京春。去年餘閏今春早，曙色和風著花草。", "可憐寒食與清明，光輝並在長安道。自從關路入秦川，", "爭道何人不戲鞭。公子途中妨蹴鞠，佳人馬上廢秋千。", "渭水長橋今欲渡，蔥蔥漸見新豐樹。遠看驪岫入雲霄，", "預想湯池起煙霧。煙霧氛氳水殿開，暫拂香輪歸去來。", "今歲清明行已晚，明年寒食更相陪。"]'),
('yuding-12','春臺望','李隆基','唐','御定全唐诗','yuding','','[]','暇景屬三春，高臺聊四望。目極千里際，山川一何壯。',204,'御定全唐詩/json/003.json','["暇景屬三春，高臺聊四望。目極千里際，山川一何壯。", "太華見重岩，終南分疊嶂。郊原紛綺錯，參差多異狀。", "佳氣滿通溝，遲步入綺樓。初鶯一一鳴紅樹，", "歸雁雙雙去綠洲。太液池中下黃鶴，昆明水上映牽牛。", "聞道漢家全盛日，別館離宮趣非一。甘泉逶迤亙明光，", "五柞連延接未央。周廬徼道縱橫轉，飛閣回軒左右長。", "須念作勞居者逸，勿言我後焉能恤。為想雄豪壯柏梁，", "何如儉陋卑茅室。陽烏黯黯向山沉，夕鳥喧喧入上林。", "薄暮賞餘回步輦，還念中人罷百金。"]'),
('yuding-13','過大哥宅探得歌字韻','李隆基','唐','御定全唐诗','yuding','','[]','魯衛情先重，親賢愛轉多。冕旒豐暇日，乘景暫經過。',48,'御定全唐詩/json/003.json','["魯衛情先重，親賢愛轉多。冕旒豐暇日，乘景暫經過。", "戚裏申高宴，平臺奏雅歌。複尋為善樂，方驗保山河。"]'),
('yuding-14','同玉真公主過大哥山池','李隆基','唐','御定全唐诗','yuding','','[]','地有招賢處，人傳樂善名。鶩池臨九達，龍岫對層城。',48,'御定全唐詩/json/003.json','["地有招賢處，人傳樂善名。鶩池臨九達，龍岫對層城。", "桂月先秋冷，蘋風向晚清。鳳樓遙可見，仿佛玉簫聲。"]'),
('yuding-15','經鄒魯祭孔子而歎之','李隆基','唐','御定全唐诗','yuding','','[]','夫子何為者，棲棲一代中。地猶鄹氏邑，宅即魯王宮。',48,'御定全唐詩/json/003.json','["夫子何為者，棲棲一代中。地猶鄹氏邑，宅即魯王宮。", "歎鳳嗟身否，傷麟怨道窮。今看兩楹奠，當與夢時同。"]'),
('yuding-16','惟此溫泉是稱愈疾豈予獨受其福思與兆人共之乗暇巡遊乃言其志','李隆基','唐','御定全唐诗','yuding','','[]','桂殿與山連，蘭湯湧自然。陰崖含秀色，溫穀吐潺湲。',48,'御定全唐詩/json/003.json','["桂殿與山連，蘭湯湧自然。陰崖含秀色，溫穀吐潺湲。", "績為蠲邪著，功因養正宣。願言將億兆，同此共昌延。"]'),
('yuding-17','旋師喜捷','李隆基','唐','御定全唐诗','yuding','','[]','邊服胡塵起，長安漢將飛。龍蛇開陣法，貔虎振軍威。',48,'御定全唐詩/json/003.json','["邊服胡塵起，長安漢將飛。龍蛇開陣法，貔虎振軍威。", "詐虜腦塗地，征夫血染衣。今朝書奏入，明日凱歌歸。"]'),
('yuding-18','過老子廟','李隆基','唐','御定全唐诗','yuding','','[]','仙居懷聖德，靈廟肅神心。草合人蹤斷，塵濃鳥跡深。',48,'御定全唐詩/json/003.json','["仙居懷聖德，靈廟肅神心。草合人蹤斷，塵濃鳥跡深。", "流沙丹灶沒，關路紫煙沉。獨傷千載後，空餘松柏林。"]'),
('yuding-19','途次陝州','李隆基','唐','御定全唐诗','yuding','','[]','境出三秦外，途分二陝中。山川入虞虢，風俗限西東。',48,'御定全唐詩/json/003.json','["境出三秦外，途分二陝中。山川入虞虢，風俗限西東。", "樹古棠陰在，耕餘讓畔空。鳴笳從此去，行見洛陽宮。"]'),
('yuding-20','野次喜雪','李隆基','唐','御定全唐诗','yuding','','[]','拂曙辟行宮，寒皋野望通。繁雲低遠岫，飛雪舞長空。',48,'御定全唐詩/json/003.json','["拂曙辟行宮，寒皋野望通。繁雲低遠岫，飛雪舞長空。", "賦象恒依物，縈回屢逐風。為知勤恤意，先此示年豐。"]'),
('yuding-21','送賀知章歸四明','李隆基','唐','御定全唐诗','yuding','','[]','遺榮期入道，辭老竟抽簪。豈不惜賢達，其如高尚心。',48,'御定全唐詩/json/003.json','["遺榮期入道，辭老竟抽簪。豈不惜賢達，其如高尚心。", "寰中得秘要，方外散幽襟。獨有青門餞，群僚悵別深。"]'),
('yuding-22','軒遊宮十五夜','李隆基','唐','御定全唐诗','yuding','','[]','行邁離秦國，巡方赴洛師。路逢三五夜，春色暗中期。',48,'御定全唐詩/json/003.json','["行邁離秦國，巡方赴洛師。路逢三五夜，春色暗中期。", "關外長河轉，宮中淑氣遲。歌鐘對明月，不減舊游時。"]'),
('yuding-23','觀拔河俗戲','李隆基','唐','御定全唐诗','yuding','','[]','壯徒恒賈勇，拔拒抵長河。欲練英雄志，須明勝負多。',48,'御定全唐詩/json/003.json','["壯徒恒賈勇，拔拒抵長河。欲練英雄志，須明勝負多。", "噪齊山岌嶪，氣作水騰波。預期年歲稔，先此樂時和。"]'),
('yuding-24','同劉晃喜雨','李隆基','唐','御定全唐诗','yuding','','[]','節變寒初盡，時和氣已春。繁雲先合寸，膏雨自依旬。',48,'御定全唐詩/json/003.json','["節變寒初盡，時和氣已春。繁雲先合寸，膏雨自依旬。", "颯颯飛平野，霏霏靜暗塵。懸知花葉意，朝夕望中新。"]'),
('yuding-25','千秋節賜群臣鏡','李隆基','唐','御定全唐诗','yuding','','[]','鑄得千秋鏡，光生百煉金。分將賜群後，遇象見清心。',48,'御定全唐詩/json/003.json','["鑄得千秋鏡，光生百煉金。分將賜群後，遇象見清心。", "臺上冰華澈，窗中月影臨。更銜長綬帶，留意感人深。"]'),
('yuding-26','賜道士鄧紫陽','李隆基','唐','御定全唐诗','yuding','','[]','太乙三門訣，元君六甲符。下傳金版術，上刻玉清書。',48,'御定全唐詩/json/003.json','["太乙三門訣，元君六甲符。下傳金版術，上刻玉清書。", "有美探真士，囊中得秘書。自知三醮後，翊我滅殘胡。"]'),
('yuding-27','幸蜀西至劍門','李隆基','唐','御定全唐诗','yuding','','[]','劍閣橫雲峻，鑾輿出狩回。翠屏千仞合，丹嶂五丁開。',48,'御定全唐詩/json/003.json','["劍閣橫雲峻，鑾輿出狩回。翠屏千仞合，丹嶂五丁開。", "灌木縈旗轉，仙雲拂馬來。乘時方在德，嗟爾勒銘才。"]'),
('yuding-28','答司馬承禎上劍鏡','李隆基','唐','御定全唐诗','yuding','','[]','寶照含天地，神劍合陰陽。日月麗光景，星斗裁文章。',48,'御定全唐詩/json/003.json','["寶照含天地，神劍合陰陽。日月麗光景，星斗裁文章。", "寫鑒表容質，佩服為身防。從茲一賞玩，永德保齡長。"]'),
('yuding-29','送趙法師還蜀因名山奠簡','李隆基','唐','御定全唐诗','yuding','','[]','道家奠靈簡，自昔仰神仙。真子今將命，蒼生福可傳。',48,'御定全唐詩/json/003.json','["道家奠靈簡，自昔仰神仙。真子今將命，蒼生福可傳。", "江山尋故國，城郭信依然。二室遙相望，雲回洞裏天。"]'),
('yuding-30','送道士薛季昌還山','李隆基','唐','御定全唐诗','yuding','','[]','洞府修真客，衡陽念舊居。將成金闕要，願奉玉清書。',48,'御定全唐詩/json/003.json','["洞府修真客，衡陽念舊居。將成金闕要，願奉玉清書。", "雲路三天近，松溪萬籟虛。猶期傳秘訣，來往候仙輿。"]'),
('yuding-31','送玄同真人李抱朴謁灊山仙祠','李隆基','唐','御定全唐诗','yuding','','[]','城闕天中近，蓬瀛海上遙。歸期千載鶴，春至一來朝。',48,'御定全唐詩/json/003.json','["城闕天中近，蓬瀛海上遙。歸期千載鶴，春至一來朝。", "采藥逢三秀，餐霞臥九霄。參同如有旨，金鼎待君燒。"]'),
('yuding-32','春日出苑遊矚','李隆基','唐','御定全唐诗','yuding','','[]','三陽麗景早芳辰，四序佳園物候新。梅花百樹障去路，',64,'御定全唐詩/json/003.json','["三陽麗景早芳辰，四序佳園物候新。梅花百樹障去路，", "垂柳千條暗回津。鳥飛直為驚風葉，魚沒都由怯岸人。", "惟願聖主南山壽，何愁不賞萬年春。"]'),
('yuding-33','春晚宴兩相及禮官麗正殿學士探得風字','李隆基','唐','御定全唐诗','yuding','','[]','幹道運無窮，恒將人代工。陰陽調曆象，禮樂報玄穹。',72,'御定全唐詩/json/003.json','["幹道運無窮，恒將人代工。陰陽調曆象，禮樂報玄穹。", "介胄清荒外，衣冠佐域中。言談延國輔，詞賦引文雄。", "野霽伊川綠，郊明鞏樹紅。冕旒多暇景，詩酒會春風。"]'),
('yuding-34','首夏花萼樓觀群臣宴寧王山亭回樓下又申之以賞樂賦詩','李隆基','唐','御定全唐诗','yuding','','[]','今年通閏月，入夏展春輝。樓下風光晚，城隅宴賞歸。',72,'御定全唐詩/json/003.json','["今年通閏月，入夏展春輝。樓下風光晚，城隅宴賞歸。", "九歌揚政要，六舞散朝衣。天喜時相合，人和事不違。", "禮中推意厚，樂處感心微。別賞陽臺樂，前旬暮雨飛。"]'),
('yuding-35','同二相已下群官樂遊園宴','李隆基','唐','御定全唐诗','yuding','','[]','撰日岩廊暇，需雲宴樂初。萬方朝玉帛，千品會簪裾。',72,'御定全唐詩/json/003.json','["撰日岩廊暇，需雲宴樂初。萬方朝玉帛，千品會簪裾。", "地入南山近，城分北斗餘。池塘垂柳密，原隰野花疏。", "帟幕看逾暗，歌鐘聽自虛。興闌歸騎轉，還奏弼違書。"]'),
('yuding-36','集賢書院成送張說上集賢學士賜宴得珍字','李隆基','唐','御定全唐诗','yuding','','[]','廣學開書院，崇儒引席珍。集賢招袞職，論道命台臣。',72,'御定全唐詩/json/003.json','["廣學開書院，崇儒引席珍。集賢招袞職，論道命台臣。", "禮樂沿今古，文章革舊新。獻酬尊俎列，賓主位班陳。", "節變雲初夏，時移氣尚春。所希光史冊，千載仰茲晨。"]'),
('yuding-37','王屋山送道士司馬承禎還天台','李隆基','唐','御定全唐诗','yuding','','[]','紫府求賢士，清溪祖逸人。江湖與城闕，異跡且殊倫。',72,'御定全唐詩/json/003.json','["紫府求賢士，清溪祖逸人。江湖與城闕，異跡且殊倫。", "間有幽棲者，居然厭俗塵。林泉先得性，芝桂欲調神。", "地道逾稽嶺，天台接海濱。音徽從此間，萬古一芳春。"]'),
('yuding-38','早度蒲津關','李隆基','唐','御定全唐诗','yuding','','[]','鐘鼓嚴更曙，山河野望通。鳴鑾下蒲阪，飛旆入秦中。',72,'御定全唐詩/json/003.json','["鐘鼓嚴更曙，山河野望通。鳴鑾下蒲阪，飛旆入秦中。", "地險關逾壯，天平鎮尚雄。春來津樹合，月落戍樓空。", "馬色分朝景，雞聲逐曉風。所希常道泰，非複候繻同。"]'),
('yuding-39','途經華嶽','李隆基','唐','御定全唐诗','yuding','','[]','飭駕去京邑，鳴鸞指洛川。循途經太華，回蹕暫周旋。',72,'御定全唐詩/json/003.json','["飭駕去京邑，鳴鸞指洛川。循途經太華，回蹕暫周旋。", "翠崿留斜影，懸岩冒夕煙。四方皆石壁，五位配金天。", "仿佛看高掌，依稀聽子先。終當銘歲月，從此記靈仙。"]'),
('yuding-40','喜雪','李隆基','唐','御定全唐诗','yuding','','[]','日觀蔔先征，時巡順物情。風行未備禮，雲密遽飄霙。',72,'御定全唐詩/json/003.json','["日觀蔔先征，時巡順物情。風行未備禮，雲密遽飄霙。", "委樹寒花發，縈空落絮輕。朝如玉已會，庭似月猶明。", "既睹膚先合，還欣尺有盈。登封何以報，因此謝功成。"]'),
('yuding-41','幸鳳泉湯','李隆基','唐','御定全唐诗','yuding','','[]','西狩觀周俗，南山曆漢宮。薦鮮知路近，省斂覺年豐。',72,'御定全唐詩/json/003.json','["西狩觀周俗，南山曆漢宮。薦鮮知路近，省斂覺年豐。", "陰穀含神爨，湯泉養聖功。益齡仙井合，愈疾醴源通。", "不重鳴岐鳳，誰矜陳寶雄。願將無限澤，沾沐眾心同。"]'),
('yuding-42','南出雀鼠谷答張說','李隆基','唐','御定全唐诗','yuding','','[]','雷出應幹象，風行順國人。川途猶在晉，車馬漸歸秦。',72,'御定全唐詩/json/003.json','["雷出應幹象，風行順國人。川途猶在晉，車馬漸歸秦。", "背陝關山險，橫汾鼓吹頻。草依陽穀變，花待北岩春。", "聞有鵷鸞客，清詞雅調新。求音思欲報，心跡竟難陳。"]'),
('yuding-43','賜崔日知往潞州','李隆基','唐','御定全唐诗','yuding','','[]','潞國開新府，壺關寵舊林。妙旌循吏德，持悅庶氓心。',72,'御定全唐詩/json/003.json','["潞國開新府，壺關寵舊林。妙旌循吏德，持悅庶氓心。", "禮樂中朝貴，神明列郡欽。揚風非贈扇，易俗是張琴。", "藩鎮謳謠滿，行宮雨露深。會書丞相策，先賜潁川金。"]'),
('yuding-44','為趙法師別造精院過院賦詩','李隆基','唐','御定全唐诗','yuding','','[]','宗師心物外，為道運虛舟。不戀岩泉賞，來從宮禁遊。',72,'御定全唐詩/json/003.json','["宗師心物外，為道運虛舟。不戀岩泉賞，來從宮禁遊。", "探玄知幾歲，習靜更宜秋。煙樹辨朝色，風湍聞夜流。", "坐朝繁聽覽，尋勝在清幽。欲廣無為化，因茲庶可求。"]'),
('yuding-45','端午','李隆基','唐','御定全唐诗','yuding','','[]','端午臨中夏，時清日複長。鹽梅已佐鼎，曲糵且傳觴。',72,'御定全唐詩/json/003.json','["端午臨中夏，時清日複長。鹽梅已佐鼎，曲糵且傳觴。", "事古人留跡，年深縷積長。當軒知槿茂，向水覺蘆香。", "億兆同歸壽，群公共保昌。忠貞如不替，貽厥後昆芳。"]'),
('yuding-46','春中興慶宮酺宴','李隆基','唐','御定全唐诗','yuding','','[]','九達長安道，三陽別館春。還將聽朝暇，回作豫遊晨。',96,'御定全唐詩/json/003.json','["九達長安道，三陽別館春。還將聽朝暇，回作豫遊晨。", "不戰要荒服，無刑禮樂新。合酺覃土宇，歡宴接群臣。", "玉斝飛千日，瓊筵薦八珍。舞衣雲曳影，歌扇月開輪。", "伐鼓魚龍雜，撞鐘角抵陳。曲終酣興晚，須有醉歸人。"]'),
('yuding-47','千秋節宴','李隆基','唐','御定全唐诗','yuding','','[]','蘭殿千秋節，稱名萬壽觴。風傳率土慶，日表繼天祥。',96,'御定全唐詩/json/003.json','["蘭殿千秋節，稱名萬壽觴。風傳率土慶，日表繼天祥。", "玉宇開花萼，宮縣動會昌。衣冠白鷺下，帟幕翠雲長。", "獻遺成新俗，朝儀入舊章。月銜花綬鏡，露綴彩絲囊。", "處處祠田祖，年年宴杖鄉。深思一德事，小獲萬人康。"]'),
('yuding-48','左丞相說右丞相璟太子少傅乾曜同日上官命宴東堂賜詩','李隆基','唐','御定全唐诗','yuding','','[]','赤帝收三傑，黃軒舉二臣。由來丞相重，分掌國之鈞。',96,'御定全唐詩/json/003.json','["赤帝收三傑，黃軒舉二臣。由來丞相重，分掌國之鈞。", "我有握中璧，雙飛席上珍。子房推道要，仲子訝風神。", "複輟台衡老，將為調護人。鵷鸞同拜日，車騎擁行塵。", "樂聚南宮宴，觴連北斗醇。俾予成百揆，垂拱問彝倫。"]'),
('yuding-49','早登太行山中言志','李隆基','唐','御定全唐诗','yuding','','[]','清蹕度河陽，凝笳上太行。火龍明鳥道，鐵騎繞羊腸。',96,'御定全唐詩/json/003.json','["清蹕度河陽，凝笳上太行。火龍明鳥道，鐵騎繞羊腸。", "白霧埋陰壑，丹霞助曉光。澗泉含宿凍，山木帶餘霜。", "野老茅為屋，樵人薜作裳。宣風問耆艾，敦俗勸耕桑。", "涼德慚先哲，徽猷慕昔皇。不因今展義，何以冒垂堂。"]'),
('yuding-50','平胡','李隆基','唐','御定全唐诗','yuding','','[]','雜虜忽倡狂，無何敢亂常。羽書朝繼入，烽火夜相望。',96,'御定全唐詩/json/003.json','["雜虜忽倡狂，無何敢亂常。羽書朝繼入，烽火夜相望。", "將出凶門勇，兵因死地強。蒙輪皆突騎，按劍盡鷹揚。", "鼓角雄山野，龍蛇入戰場。流膏潤沙漠，濺血染鋒鋩。", "霧掃清玄塞，雲開靜朔方。武功今已立，文德愧前王。"]'),
('yuding-51','遊興慶宮作','李隆基','唐','御定全唐诗','yuding','','[]','代邸青門右，離宮紫陌陲。庭如過沛日，水若渡江時。',120,'御定全唐詩/json/003.json','["代邸青門右，離宮紫陌陲。庭如過沛日，水若渡江時。", "綺觀連雞岫，朱樓接雁池。從來敦棣萼，今此茂荊枝。", "萬葉傳餘慶，千年志不移。憑軒聊屬目，輕輦共追隨。", "務本方崇訓，相輝保羽儀。時康俗易漸，德薄政難施。", "鼓吹迎飛蓋，弦歌送羽卮。所希覃率土，孝弟一同規。"]'),
('yuding-52','送張說巡邊','李隆基','唐','御定全唐诗','yuding','','[]','端拱複垂裳，長懷禦遠方。股肱申教義，戈劍靖要荒。',120,'御定全唐詩/json/003.json','["端拱複垂裳，長懷禦遠方。股肱申教義，戈劍靖要荒。", "命將綏邊服，雄圖出廟堂。三台入武帳，八座起文昌。", "寶胄匡韓主，華宗輔漢王。茂先慚博物，平子謝文章。", "盡節恢時佐，輸誠禦寇場。三軍臨朔野，駟馬即戎行。", "鼓吹威夷狄，旌軒溢洛陽。雲台先著美，今日更貽芳。"]'),
('yuding-53','餞王晙巡邊','李隆基','唐','御定全唐诗','yuding','','[]','振武威荒服，揚文肅遠墟。金壇申將禮，玉節授軍符。',120,'御定全唐詩/json/003.json','["振武威荒服，揚文肅遠墟。金壇申將禮，玉節授軍符。", "免胄三方外，銜刀萬里餘。昔時吳會靜，今日虜庭虛。", "分閫仍推轂，援桴且訓車。風揚旌旆遠，雨洗甲兵初。", "坐見臺階謐，行聞襖祲除。檄來雖插羽，箭去亦飛書。", "舟楫功須著，鹽梅望匪疏。不應陳七德，欲使化先敷。"]'),
('yuding-54','巡省途次上黨舊宮賦','李隆基','唐','御定全唐诗','yuding','','[]','三千初擊浪，九萬欲摶空。天地猶驚否，陰陽始遇蒙。',144,'御定全唐詩/json/003.json','["三千初擊浪，九萬欲摶空。天地猶驚否，陰陽始遇蒙。", "存貞期曆試，佐貳佇昭融。多謝時康理，良慚實賴功。", "長懷問鼎氣，夙負拔山雄。不學劉琨舞，先歌漢祖風。", "英髦既包括，豪傑自牢籠。人事一朝異，謳歌四海同。", "如何昔朱邸，今此作離宮。雁沼澄瀾翠，猿岩落照紅。", "小山秋桂馥，長阪舊蘭叢。即是淹留處，乘歡樂未窮。"]'),
('yuding-55','潼關口號','李隆基','唐','御定全唐诗','yuding','','[]','河曲回千里，關門限二京。所嗟非恃德，設險到天平。',24,'御定全唐詩/json/003.json','["河曲回千里，關門限二京。所嗟非恃德，設險到天平。"]'),
('yuding-56','千秋節賜群臣鏡','李隆基','唐','御定全唐诗','yuding','','[]','瑞露垂花綬，寒冰澈寶輪。對茲臺上月，聊以慶佳辰。',24,'御定全唐詩/json/003.json','["瑞露垂花綬，寒冰澈寶輪。對茲臺上月，聊以慶佳辰。"]'),
('yuding-57','續薛令之題壁','李隆基','唐','御定全唐诗','yuding','','[]','啄木觜距長，鳳凰羽毛短。苦嫌松桂寒，任逐桑榆暖。',24,'御定全唐詩/json/003.json','["啄木觜距長，鳳凰羽毛短。苦嫌松桂寒，任逐桑榆暖。"]'),
('yuding-58','送胡真師還西山','李隆基','唐','御定全唐诗','yuding','','[]','仙客厭人間，孤雲比性閑。話離情未已，煙水萬重山。',24,'御定全唐詩/json/003.json','["仙客厭人間，孤雲比性閑。話離情未已，煙水萬重山。"]'),
('yuding-59','過大哥山池題石壁','李隆基','唐','御定全唐诗','yuding','','[]','澄潭皎鏡石崔巍，萬壑千岩暗綠苔。',32,'御定全唐詩/json/003.json','["澄潭皎鏡石崔巍，萬壑千岩暗綠苔。", "林亭自有幽貞趣，況複秋深爽氣來。"]'),
('yuding-60','題梅妃畫真','李隆基','唐','御定全唐诗','yuding','','[]','憶昔嬌妃在紫宸，鉛華不禦得天真。',32,'御定全唐詩/json/003.json','["憶昔嬌妃在紫宸，鉛華不禦得天真。", "霜綃雖似當時態，爭奈嬌波不顧人。"]'),
('yuding-61','鶺鴒頌','李隆基','唐','御定全唐诗','yuding','','[]','伊我軒宮，奇樹青蔥，藹周廬兮。冒霜停雪，以茂以悅，',165,'御定全唐詩/json/003.json','["伊我軒宮，奇樹青蔥，藹周廬兮。冒霜停雪，以茂以悅，", "恣卷舒兮。連枝同榮，吐綠含英，曜春初兮。", "蓐收禦節，寒露微結，氣清虛兮。桂宮蘭殿，唯所息宴，", "棲雍渠兮。行搖飛鳴，急難有情，情有餘兮。", "顧惟德涼，夙夜兢惶，慚化疏兮。上之所教，下之所效，", "實在予兮。天倫之性，魯衛分政，親賢居兮。", "爰遊爰處，爰笑爰語，巡庭除兮。觀此翔禽，以悅我心，", "良史書兮。"]'),
('yuding-62','傀儡吟','李隆基','唐','御定全唐诗','yuding','','[]','刻木牽絲作老翁，雞皮鶴發與真同。',32,'御定全唐詩/json/003.json','["刻木牽絲作老翁，雞皮鶴發與真同。", "須臾弄罷寂無事，還似人生一夢中。"]'),
('yuding-63','句','李隆基','唐','御定全唐诗','yuding','','[]','昔見漳濱臥，言將人事違。今逢慶誕日，猶謂學仙歸。',48,'御定全唐詩/json/003.json','["昔見漳濱臥，言將人事違。今逢慶誕日，猶謂學仙歸。", "棠棣花重發，鴒原鳥再飛。", "德比代雲布，心如晉水清。"]'),
('yuding-0','延英殿玉靈芝詩三章，章八句','李亨','唐','御定全唐诗','yuding','','[]','玉殿肅肅，靈芝煌煌。重英發秀，連葉分房。',110,'御定全唐詩/json/004.json','["玉殿肅肅，靈芝煌煌。重英發秀，連葉分房。", "宗廟之福，垂其耿光。", "元氣產芝，明神合德。紫微間采，白蕣呈色。", "載啟瑞圖，庶符皇極。天心有眷，王道惟直。", "幸生芳本，當我扆旒。效此靈質，賁其王猷。", "神惟不愛，道亦無求。端拱思惟，永荷天休。"]'),
('yuding-1','賜梨李泌與諸王聯句','李亨','唐','御定全唐诗','yuding','','[]','先生年幾許，顏色似童兒。——潁王',64,'御定全唐詩/json/004.json','["先生年幾許，顏色似童兒。——潁王", "夜抱九仙骨，朝披一品衣。——信王", "不食千鐘粟，唯餐兩顆梨。——益王", "天生此間氣，助我化無為。——李亨"]'),
('yuding-2','中和節日宴百僚賜詩','李適','唐','御定全唐诗','yuding','','[]','韶年啟仲序，初吉諧良辰。肇茲中和節，式慶天地春。',72,'御定全唐詩/json/004.json','["韶年啟仲序，初吉諧良辰。肇茲中和節，式慶天地春。", "歡酣朝野同，生德區宇均。雲開灑膏露，草疏芳河津。", "歲華今載陽，東作方肆勤。慚非熏風唱，曷用慰吾人。"]'),
('yuding-3','中和節賜百官燕集因示所懷','李適','唐','御定全唐诗','yuding','','[]','至化恒在宥，保和茲息人。推誠撫諸夏，與物長為春。',72,'御定全唐詩/json/004.json','["至化恒在宥，保和茲息人。推誠撫諸夏，與物長為春。", "仲月風景暖，禁城花柳新。芳時協金奏，賜宴同群臣。", "絲竹豈雲樂，忠賢惟所親。庶洽朝野意，曠然天地均。"]'),
('yuding-4','重陽日賜宴曲江亭，賦六韻詩用清字','李適','唐','御定全唐诗','yuding','','[]','早衣對庭燎，躬化勤意誠。時此萬機暇，適與佳節並。',72,'御定全唐詩/json/004.json','["早衣對庭燎，躬化勤意誠。時此萬機暇，適與佳節並。", "曲池潔寒流，芳菊舒金英。乾坤爽氣滿，台殿秋光清。", "朝野慶年豐，高會多歡聲。永懷無荒戒，良士同斯情。"]'),
('yuding-5','九月十八賜百僚追賞因書所懷','李適','唐','御定全唐诗','yuding','','[]','雨霽霜氣肅，天高雲日明。繁林已墜葉，寒菊仍舒榮。',72,'御定全唐詩/json/004.json','["雨霽霜氣肅，天高雲日明。繁林已墜葉，寒菊仍舒榮。", "懿此秋節時，更延追賞情。池台列廣宴，絲竹傳新聲。", "至樂非外獎，浹歡同中誠。庶敦朝野意，永使風化清。"]'),
('yuding-6','送徐州張建封還鎮','李適','唐','御定全唐诗','yuding','','[]','牧守寄所重，才賢生為時。宣風自淮甸，授鉞膺藩維。',96,'御定全唐詩/json/004.json','["牧守寄所重，才賢生為時。宣風自淮甸，授鉞膺藩維。", "入覲展遐戀，臨軒慰來思。忠誠在方寸，感激陳情詞。", "報國爾所向，恤人予是資。歡宴不盡懷，車馬當還期。", "穀雨將應候，行春猶未遲。勿以千里遙，而雲無己知。"]'),
('yuding-7','麟德殿宴百僚','李適','唐','御定全唐诗','yuding','','[]','憂勤承聖緒，開泰喜時康。恭己臨群後，垂衣禦八荒。',72,'御定全唐詩/json/004.json','["憂勤承聖緒，開泰喜時康。恭己臨群後，垂衣禦八荒。", "務閑春向暮，朝罷日猶長。紫殿初筵列，彤庭廣樂張。", "成功歸輔弼，致理賴忠良。共此歡娛事，千秋樂未央。"]'),
('yuding-8','元日退朝觀軍仗歸營','李適','唐','御定全唐诗','yuding','','[]','獻歲視元朔，萬方咸在庭。端旒揖群後，回輦閱師貞。',96,'御定全唐詩/json/004.json','["獻歲視元朔，萬方咸在庭。端旒揖群後，回輦閱師貞。", "彩仗宿華殿，退朝歸禁營。分行左右出，轉旆風雲生。", "歷歷趨複道，容容映層城。勇餘矜捷技，令肅無喧聲。", "眷此戎旅節，載嘉良士誠。順時傾宴賞，亦以助文經。"]'),
('yuding-9','中和節賜群臣宴賦七韻','李適','唐','御定全唐诗','yuding','','[]','東風變梅柳，萬匯生春光。中和紀月令，方與天地長。',84,'御定全唐詩/json/004.json','["東風變梅柳，萬匯生春光。中和紀月令，方與天地長。", "耽樂豈予尚，懿茲時景良。庶遂亭育恩，同致寰海康。", "君臣永終始，交泰符陰陽。曲沼水新碧，華林桃稍芳。", "勝賞信多歡，戒之在無荒。"]'),
('yuding-10','三日書懷因示百僚','李適','唐','御定全唐诗','yuding','','[]','佳節上元巳，芳時屬暮春。流觴想蘭亭，捧劍得金人。',72,'御定全唐詩/json/004.json','["佳節上元巳，芳時屬暮春。流觴想蘭亭，捧劍得金人。", "風輕水初綠，日晴花更新。天文信昭回，皇道頗敷陳。", "恭己每從儉，清心常保真。戒茲游衍樂，書以示群臣。"]'),
('yuding-11','重陽日中外同歡，以詩言志，因示群官','李適','唐','御定全唐诗','yuding','','[]','爽節在重九，物華新雨餘。清秋黃葉下，菊散金潭初。',84,'御定全唐詩/json/004.json','["爽節在重九，物華新雨餘。清秋黃葉下，菊散金潭初。", "萬實行就稔，百工欣所如。歡心暢遐邇，殊俗同車書。", "至化自敦睦，佳辰宜宴胥。鏘鏘間絲竹，濟濟羅簪裾。", "此樂匪足耽，此誠期永孚。"]'),
('yuding-12','重陽日即事','李適','唐','御定全唐诗','yuding','','[]','令節曉澄霽，四郊煙靄空。天清白露潔，菊散黃金叢。',72,'御定全唐詩/json/004.json','["令節曉澄霽，四郊煙靄空。天清白露潔，菊散黃金叢。", "寡德荷天貺，順時休百工。豈懷歌鐘樂，思為君臣同。", "至化在亭育，相成資始終。未知康衢詠，所仰惟年豐。"]'),
('yuding-13','豐年多慶，九日示懷','李適','唐','御定全唐诗','yuding','','[]','爽氣肅時令，早衣聞朔鴻。重陽有佳節，具物欣年豐。',72,'御定全唐詩/json/004.json','["爽氣肅時令，早衣聞朔鴻。重陽有佳節，具物欣年豐。", "皎潔暮潭色，芬敷新菊叢。芳尊滿衢室，繁吹凝煙空。", "惠合信吾道，保和惟爾同。推誠至玄化，天下期為公。"]'),
('yuding-14','七月十五日題章敬寺','李適','唐','御定全唐诗','yuding','','[]','招提邇皇邑，複道連重城。法筵會早秋，駕言訪禪扃。',108,'御定全唐詩/json/004.json','["招提邇皇邑，複道連重城。法筵會早秋，駕言訪禪扃。", "嘗聞大仙教，清淨宗無生。七物匪吾寶，萬行先求成。", "名相既雙寂，繁華奚所榮。金風扇微涼，遠煙凝翠晶。", "松院靜苔色，竹房深磬聲。境幽真慮恬，道勝外物輕。", "意適本非說，含毫空複情。"]'),
('yuding-15','中春麟德殿會百僚觀新樂詩一章，章十六句','李適','唐','御定全唐诗','yuding','','[]','芳歲肇佳節，物華當仲春。乾坤既昭泰，煙景含氤氳。',96,'御定全唐詩/json/004.json','["芳歲肇佳節，物華當仲春。乾坤既昭泰，煙景含氤氳。", "德淺荷玄貺，樂成思治人。前庭列鐘鼓，廣殿延群臣。", "八卦隨舞意，五音轉曲新。顧非咸池奏，庶協南風熏。", "式宴禮所重，浹歡情必均。同和諒在茲，萬國希可親。"]'),
('yuding-16','九日絕句','李適','唐','御定全唐诗','yuding','','[]','禁苑秋來爽氣多，昆明風動起滄波。',32,'御定全唐詩/json/004.json','["禁苑秋來爽氣多，昆明風動起滄波。", "中流簫鼓誠堪賞，詎假橫汾發棹歌。"]'),
('yuding-17','暮春喜雨詩','李昂1','唐','御定全唐诗','yuding','','[]','風雲喜際會，雷雨遂流滋。薦幣虛陳禮，動天實精思。',72,'御定全唐詩/json/004.json','["風雲喜際會，雷雨遂流滋。薦幣虛陳禮，動天實精思。", "漸侵九夏節，複在三春時。霢霂垂朱闕，飄颻入綠墀。", "郊坰既沾足，黍稷有豐期。百辟同康樂，萬方佇雍熙。"]'),
('yuding-18','題程修己竹障','李昂1','唐','御定全唐诗','yuding','','[]','良工運精思，巧極似有神。',28,'御定全唐詩/json/004.json','["良工運精思，巧極似有神。", "臨窗忽睹繁陰合，再盼真假殊未分。"]'),
('yuding-19','宮中題','李昂1','唐','御定全唐诗','yuding','','[]','輦路生春草，上林花發時。憑高何限意，無複侍臣知。',24,'御定全唐詩/json/004.json','["輦路生春草，上林花發時。憑高何限意，無複侍臣知。"]'),
('yuding-20','上巳日賜裴度','李昂1','唐','御定全唐诗','yuding','','[]','注想待元老，識君恨不早。我家柱石衰，憂來學丘禱。',24,'御定全唐詩/json/004.json','["注想待元老，識君恨不早。我家柱石衰，憂來學丘禱。"]'),
('yuding-21','上元日二首','李昂1','唐','御定全唐诗','yuding','','[]','上元高會集群仙，心齋何事欲祈年。',64,'御定全唐詩/json/004.json','["上元高會集群仙，心齋何事欲祈年。", "丹誠儻徹玉帝座，且共吾人慶大田。", "蓂生三五葉初齊，上元羽客出桃蹊。", "不愛仙家登真訣，願蒙四海福黔黎。"]'),
('yuding-22','夏日聯句','李昂1','唐','御定全唐诗','yuding','','[]','人皆苦炎熱，我愛夏日長。——李昂1',34,'御定全唐詩/json/004.json','["人皆苦炎熱，我愛夏日長。——李昂1", "熏風自南來，殿閣生微涼。——柳公權"]'),
('yuding-23','百丈山','李忱','唐','御定全唐诗','yuding','','[]','大雄真跡枕危巒，梵宇層樓聳萬般。日月每從肩上過，',40,'御定全唐詩/json/004.json','["大雄真跡枕危巒，梵宇層樓聳萬般。日月每從肩上過，", "更有上方人罕到，暮鐘朝磬碧雲端。"]'),
('yuding-24','吊白居易','李忱','唐','御定全唐诗','yuding','','[]','綴玉聯珠六十年，誰教冥路作詩仙。浮雲不系名居易，',40,'御定全唐詩/json/004.json','["綴玉聯珠六十年，誰教冥路作詩仙。浮雲不系名居易，", "文章已滿行人耳，一度思卿一愴然。"]'),
('yuding-25','幸華嚴寺','李忱','唐','御定全唐诗','yuding','','[]','雲散晴山幾萬重，煙收春色更沖融。帳殿出空登碧漢，',40,'御定全唐詩/json/004.json','["雲散晴山幾萬重，煙收春色更沖融。帳殿出空登碧漢，", "今日追游何所似，莫慚漢武賞汾中。"]'),
('yuding-26','重陽錫宴群臣','李忱','唐','御定全唐诗','yuding','','[]','款塞旋征騎，和戎委廟賢。傾心方倚注，葉力共安邊。',24,'御定全唐詩/json/004.json','["款塞旋征騎，和戎委廟賢。傾心方倚注，葉力共安邊。"]'),
('yuding-27','題涇縣水西寺','李忱','唐','御定全唐诗','yuding','','[]','大殿連雲接爽溪，鐘聲還與鼓聲齊。',32,'御定全唐詩/json/004.json','["大殿連雲接爽溪，鐘聲還與鼓聲齊。", "長安若問江南事，說道風光在水西。"]'),
('yuding-28','瀑布聯句','李忱','唐','御定全唐诗','yuding','','[]','千岩萬壑不辭勞，遠看方知出處高。——黃檗',40,'御定全唐詩/json/004.json','["千岩萬壑不辭勞，遠看方知出處高。——黃檗", "溪澗豈能留得住，終歸大海作波濤。——李忱"]'),
('yuding-29','句','李忱','唐','御定全唐诗','yuding','','[]','海嶽宴咸通。',22,'御定全唐詩/json/004.json','["海嶽宴咸通。", "七載秉鈞調四序，一方獄市獲來蘇。"]'),
('yuding-30','句','李曄1','唐','御定全唐诗','yuding','','[]','只解劈牛兼劈樹，不能誅惡與誅凶。',16,'御定全唐詩/json/004.json','["只解劈牛兼劈樹，不能誅惡與誅凶。"]'),
('yuding-0','春遊曲','長孫氏','唐','御定全唐诗','yuding','','[]','上苑桃花朝日明，蘭閨豔妾動春情。井上新桃偷面色，',40,'御定全唐詩/json/005.json','["上苑桃花朝日明，蘭閨豔妾動春情。井上新桃偷面色，", "林下何須遠借問，出眾風流舊有名。"]'),
('yuding-1','曳鼎歌','武則天','唐','御定全唐诗','yuding','','[]','羲農首出，軒昊膺期。唐虞繼踵，湯禹乘時。',40,'御定全唐詩/json/005.json','["羲農首出，軒昊膺期。唐虞繼踵，湯禹乘時。", "天下光宅，海內雍熙。上玄降鑒，方建隆基。"]'),
('yuding-2','唐享昊天樂：第一','武則天','唐','御定全唐诗','yuding','','[]','太陰凝至化，真耀蘊軒儀。德邁娥台敞，仁高姒幄披。',36,'御定全唐詩/json/005.json','["太陰凝至化，真耀蘊軒儀。德邁娥台敞，仁高姒幄披。", "捫天遂啟極，夢日乃升曦。"]'),
('yuding-3','唐享昊天樂：第二','武則天','唐','御定全唐诗','yuding','','[]','瞻紫極，望玄穹。翹至懇，罄深衷。',32,'御定全唐詩/json/005.json','["瞻紫極，望玄穹。翹至懇，罄深衷。", "聽雖遠，誠必通。垂厚澤，降雲宮。"]'),
('yuding-4','唐享昊天樂：第三','武則天','唐','御定全唐诗','yuding','','[]','幹儀混成沖邃，天道下濟高明，闓陽晨披紫闕，',35,'御定全唐詩/json/005.json','["幹儀混成沖邃，天道下濟高明，闓陽晨披紫闕，", "丹襟式敷衷懇，玄鑒庶察微誠。"]'),
('yuding-5','唐享昊天樂：第四','武則天','唐','御定全唐诗','yuding','','[]','巍巍睿業廣，赫赫聖基隆。菲德承先顧，禎符萃眇躬。',60,'御定全唐詩/json/005.json','["巍巍睿業廣，赫赫聖基隆。菲德承先顧，禎符萃眇躬。", "銘開武岩側，圖薦洛川中。微誠詎幽感，景命忽昭融。", "有懷慚紫極，無以謝玄穹。"]'),
('yuding-6','唐享昊天樂：第五','武則天','唐','御定全唐诗','yuding','','[]','朝壇霧卷，曙嶺煙沉。爰設筐幣，式表誠心。',40,'御定全唐詩/json/005.json','["朝壇霧卷，曙嶺煙沉。爰設筐幣，式表誠心。", "筵輝麗璧，樂暢和音。仰惟靈鑒，俯察翹襟。"]'),
('yuding-7','唐享昊天樂：第六','武則天','唐','御定全唐诗','yuding','','[]','昭昭上帝，穆穆下臨。禮崇備物，樂奏鏘金。',40,'御定全唐詩/json/005.json','["昭昭上帝，穆穆下臨。禮崇備物，樂奏鏘金。", "蘭羞委薦，桂醑盈斟。敢希明德，幸罄莊心。"]'),
('yuding-8','唐享昊天樂：第七','武則天','唐','御定全唐诗','yuding','','[]','尊浮九醞，禮備三周。陳誠菲奠，契福神猷。',20,'御定全唐詩/json/005.json','["尊浮九醞，禮備三周。陳誠菲奠，契福神猷。"]');
